fn main() -> Result<()> {
    let mut rl = DefaultEditor::new()?;

    // Bind Ctrl+J to insert a newline while keeping the cursor editable.
    // rustyline does not support a "read-only" visual continuation prompt 
    // natively in the way some shells do (where the previous lines become immutable).
    // However, binding Cmd::Newline (or Insert('\n')) allows multiline input.
    // The prompt (">> ") is only shown for the first line. Subsequent lines 
    // are visually continued automatically by rustyline when a newline is inserted.
    rl.bind_sequence(
        KeyEvent(KeyCode::Char('j'), Modifiers::CTRL),
        EventHandler::Simple(Cmd::Newline),
    );

    println!("REPL started. Type your code. Use Ctrl+J to add a new line. Ctrl+D to exit.");

    loop {
        // The prompt ">> " is displayed only for the initial line.
        // When you press Ctrl+J, rustyline handles the visual continuation internally.
        let readline = rl.readline(">> ");

        match readline {
            Ok(line) => {
                if line.trim().is_empty() {
                    continue;
                }
                println!("Received: {}", line);
                // In a real REPL, you would check if the input is complete.
