// The Python script content is embedded at compile time.
// This solves the packaging requirement without needing external files.
const PYTHON_SCRIPT: &str = include_str!("../src/python/script.py");

fn main() {
    // 1. Determine the filesystem path for the script.
    // Since we embedded the content, we need to write it to a temporary location
    // or run it via stdin. Running via stdin is cleaner and doesn't leave temp files.
    // However, if the script relies on __file__, a temp file is better.
    // Here we use a temp file approach to ensure maximum compatibility with scripts
    // that might expect a file path.

    let temp_dir = env::temp_dir();
    let script_path = temp_dir.join("rust_program_embedded_script.py");

    // Write the embedded script to the temp location
    if let Err(e) = fs::write(&script_path, PYTHON_SCRIPT) {
        eprintln!("Failed to write temporary script: {}", e);
        std::process::exit(1);
    }

    // Ensure the file is cleaned up after execution (though OS usually cleans /tmp)
    let _guard = scopeguard::guard(script_path.clone(), |path| {
        let _ = fs::remove_file(path);
    });

    // 2. Execute the Python interpreter with the path
    // We assume 'python3' is available. Fallback to 'python' if needed.
    let python_cmd = which_python();

    let mut cmd = Command::new(python_cmd);
    cmd.arg(&script_path);

    // Pass through any arguments received by the Rust CLI to the Python script
    let args: Vec<String> = env::args().skip(1).collect();
    if !args.is_empty() {
        cmd.args(&args);
    }

    let status = cmd.status().expect("Failed to start Python interpreter");

    if !status.success() {
        std::process::exit(status.code().unwrap_or(1));
    }
}

fn which_python() -> String {
    // Check for python3 first (common on Linux/Mac)
    if Command::new("python3").arg("--version").output().is_ok() {
        return "python3".to_string();
    }
    // Fallback to python (common on Windows)
    if Command::new("python").arg("--version").output().is_ok() {
        return "python".to_string();
    }
    eprintln!("Error: Neither 'python3' nor 'python' found in PATH.");
    std::process::exit(1);
}

// Minimal implementation of scopeguard to avoid adding external dependencies 
// for such a small utility, keeping the crate self-contained as requested.
mod scopeguard {
    use std::ops::Deref;

    pub struct ScopeGuard<T, F> 
    where
        F: FnMut(T),
    {
        value: Option<T>,
        drop_fn: Option<F>,
    }

    impl<T, F> ScopeGuard<T, F>
    where
        F: FnMut(T),
    {
        pub fn new(value: T, drop_fn: F) -> Self {
            ScopeGuard {
                value: Some(value),
                drop_fn: Some(drop_fn),
            }
        }
    }

    impl<T, F> Drop for ScopeGuard<T, F>
    where
        F: FnMut(T),
    {
        fn drop(&mut self) {
            if let Some(value) = self.value.take() {
                if let Some(mut drop_fn) = self.drop_fn.take() {
                    drop_fn(value);
                }
            }
        }
    }

    pub fn guard<T, F>(value: T, drop_fn: F) -> ScopeGuard<T, F>
    where
        F: FnMut(T),
    {
        ScopeGuard::new(value, drop_fn)
    }
}
"
