#[component]
fn DragProvider(children: Element) -> Element {
    // Provide the context to all children
    let mut drag_state = use_context_provider(|| DragState::new());

    rsx! {
        div {
            id: "drag_provider",
            style: "width: 100%; height: 100%;",
            // Global listeners update the shared state
            onmousemove: move |me| {
                let coords = me.element_coordinates();
                drag_state.mouse_position.set(ElementPoint::new(coords.x as f64, coords.y as f64));
            },
            onmousedown: move |_| {
                drag_state.is_dragged.set(true);
            },
            onmouseup: move |_| {
                drag_state.is_dragged.set(false);
            },
