fn Point(props: PointProps) -> Element {
    // Local state for the specific point's position and drag status
    let mut coords = use_signal(|| ElementPoint::new(props.x, props.y));
    let mut is_dragged = use_signal(|| false);

    // Subscribe to the global drag context
    let global_state = use_context::<DragState>();
    let global_mouse = global_state.mouse_position;
    let global_is_dragged = global_state.is_dragged;

