    // This effect runs whenever the signals accessed inside change.
    // We check if the global "is_dragged" is true AND if this specific point "is_dragged" is true.
    use_effect(move || {
        let g_dragged = *global_is_dragged.read();
        let local_dragged = *is_dragged.read();

        if g_dragged && local_dragged {
            let mouse_pos = *global_mouse.read();
            let current_pos = *coords.read();

            // Only update if position actually changed to prevent unnecessary cycles
            if mouse_pos != current_pos {
                coords.set(mouse_pos);
            }
        } else if !g_dragged && local_dragged {
            // If global drag stopped but local thinks it's still dragging, reset local
            is_dragged.set(false);
        }
    });

