        circle {
            cx: coords.read().x,
            cy: coords.read().y,
            r: props.r,
            fill: if *is_dragged.read() { "orange" } else { "red" },
            stroke: "black",
            stroke_width: "2",
            style: "cursor: grab;",
            onmousedown: move |_| {
                if props.draggable {
                    is_dragged.set(true);
                }
            },
            // We don't need onmousemove here because the provider handles it globally
        }
    }
}
