/// A simple struct holding an atomic counter.
struct ChannelManager {
    channel_index: AtomicUsize,
}

impl ChannelManager {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Allocates a new channel index atomically.
    ///
    /// On thumbv6m (Cortex-M0+), native atomic RMW (Read-Modify-Write) instructions
    /// like `LL/SC` or `LDREX/STREX` do not exist. Therefore, `fetch_add` on
    /// `core::sync::atomic::AtomicUsize` will panic at runtime if no critical-section
    /// implementation is active, or requires emulation via disabling interrupts.
    ///
    /// We use `critical_section::with` to emulate the RMW operation safely.
    fn get_next_index(&self) -> usize {
        critical_section::with(|_cs| {
            // Inside a critical section, interrupts are disabled (on embedded) 
            // or a global lock is held (on std). 
            // 
            // Regarding Memory Orderings:
            // Since the entire block is atomic with respect to other threads/cores
            // due to the critical section, the specific ordering flags on the 
            // individual load/store operations primarily serve as compiler fences.
            //
            // 1. Ordering::Relaxed is technically sufficient here for correctness 
            //    regarding data races because the critical section itself provides 
            //    the necessary synchronization boundaries (it acts as a full fence).
            //    The hardware cannot reorder instructions across the interrupt 
            //    disable/enable boundaries implicitly created by the critical section.
            //
            // 2. However, using Ordering::SeqCst (Sequentially Consistent) is often
            //    preferred in emulation layers to match the semantics of the native
            //    `fetch_add` which defaults to SeqCst if not specified, or to ensure
            //    strict visibility across cores immediately upon exit. 
            //
            // 3. If the original code used `Relaxed`, keeping `Relaxed` inside the 
            //    CS is the most faithful translation performance-wise, as the CS 
            //    already guarantees atomicity and isolation.

            let old_val = self.channel_index.load(Ordering::Relaxed);

            // We perform the addition manually
            let new_val = old_val.wrapping_add(1);

            self.channel_index.store(new_val, Ordering::Relaxed);

            old_val
        })
    }
}

