    // Initialize the manager
    let manager = ChannelManager::new();

    println!("Starting atomic replacement demo...");
    println!("Simulating thumbv6m-none-eabi behavior using critical-section.");

    // Simulate concurrent access by calling it multiple times
    // In a real embedded scenario, this would be accessed from different 
    // interrupt contexts or the second core.
