// --- The Solution: Recursive Filtering via Value Tree ---

/// Converts a struct into a generic JSON Value tree.
/// This allows us to treat the struct as a navigable map without knowing its fields at compile time.
fn to_value_tree<T: Serialize>(obj: &T) -> Result<serde_json::Value, serde_json::Error> {
    serde_json::to_value(obj)
}

/// Recursively checks if the `target` matches the `filter`.
/// 
/// Logic:
/// 1. If filter is Null/Missing: Match (no constraint).
/// 2. If filter is an Object: Recurse into fields. All present filter fields must match.
/// 3. If filter is a Primitive: Direct equality check.
/// 4. If target is missing but filter exists: No match.
fn matches_filter(target: &serde_json::Value, filter: &serde_json::Value) -> bool {
    match filter {
        serde_json::Value::Null => true, // No filter specified for this branch

        serde_json::Value::Object(filter_map) => {
            // If target isn't an object, it can't match an object filter
            let target_map = match target {
                serde_json::Value::Object(m) => m,
                _ => return false,
            };

            // Iterate over every field specified in the filter
            for (key, filter_val) in filter_map {
                // If the key doesn't exist in target, or recursive check fails
                if !target_map.contains_key(key) {
                    return false;
                }

                let target_val = &target_map[key];
                if !matches_filter(target_val, filter_val) {
                    return false;
                }
            }
            true
        }

        // For primitives (String, Number, Bool, Array), do direct equality
        _ => target == filter,
    }
}

