  "main.rs": "use std::fmt;
use chumsky::prelude::*;
use chumsky::input::Input;
use chumsky::error::Rich;

// Simplified token for demonstration
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct Token(char);

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", self.0)
    }
}

/// The core issue in the original code was binding the lifetime `'src` to the trait itself.
/// When a trait is defined as `trait BaseSliceParser<'src>`, any method inside it (like `parse_this_owned`)
/// is forced to use that specific `'src` lifetime for all arguments and return values.
///
/// In `parse_this_owned`, you create a local `Vec` named `input`. This `input` only lives
/// for the duration of the function call. However, because the trait is bound to `'src`,
/// the compiler expects the slice borrowed from `input` to live for `'src` (which could be
/// longer than the function call).
///
/// THE FIX:
/// 1. Remove the lifetime parameter from the trait definition (`trait BaseSliceParser`).
/// 2. Add the lifetime parameter to the specific methods that need it (`fn parse_this<'src>(...)`).
/// This allows the compiler to infer a fresh, short lifetime for `input` that matches
/// the scope of the function call, rather than being constrained by a trait-level lifetime.

pub trait BaseParser {
    // We keep the associated types generic over 'src, but the trait itself is not bounded.
    type InputToken<'src>: PartialEq + fmt::Display + Clone + 'src;
    type Input<'src>: Input<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;
    type Output;

    fn parser<'src>() -> impl Parser<'src, Self::Input<'src>, Self::Output, extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>>;

    /// Perform the parsing within this layer
    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>> {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

/// FIXED: No lifetime parameter on the trait itself.
pub trait BaseSliceParser: BaseParser {
    /// FIXED: The lifetime `'src` is now local to this method.
    /// This tells the compiler: "For this specific call, choose a lifetime `'src`
    /// that matches the `input` vector provided right now."
    fn parse_this_owned<'src>(input: Vec<Self::InputToken<'src>>) -> Result<Self::Output, Vec<String>> {
        // `input.as_slice()` creates a reference that lives as long as `input`.
        // Since `'src` is inferred from this call, it matches perfectly.
        Self::parse_this(input.as_slice())
        // `input` is dropped here, but the borrow ended when `parse_this` returned.
        // No conflict!
    }
}

// --- Implementation Example ---

struct CharParser;

impl BaseParser for CharParser {
    type InputToken<'src> = Token;
    type Input<'src> = &'src [Token];
    type Output = String;

    fn parser<'src>() -> impl Parser<'src, Self::Input<'src>, Self::Output, extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>> {
