/// 1. Remove the lifetime parameter `'a` from the struct entirely.
/// 2. Use `Cow<'static, str>` instead of `Cow<'a, str>`.
///
/// WHY THIS WORKS:
/// The methods `R::group` and `R::kind` in your real crate likely return string slices
/// that are either hardcoded constants or derived from type information that lives for
/// the entire duration of the program ('static). They do not actually borrow data from
/// the specific instance of `DynamicType` passed to them (even though they take a reference).
///
/// By changing the lifetime to 'static, we tell the compiler: "These strings live forever,
/// so they don't depend on the lifetime of the `dynamic_type` field instance."
///
/// If your real `R::group` actually returns data borrowed from the argument (e.g. a field inside DynamicType),
/// then you MUST allocate (to_string()) or restructure the logic, because you cannot store
/// a reference to a field that is owned by the same struct (self-referential structs are hard/impossible in safe Rust).
/// But 99% of metadata systems return static strings.

#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<Cow<'static, str>>,
    kind: Cow<'static, str>,
    name: String,
