        // Handle the suffix (glob or specific item) and children
        let is_glob = tree.star_token().is_some();
        let children = tree.use_tree_list();

        let final_path_str = if let Some(list) = children {
            // Case: use vexide::devices::{smart, adi};
            // Becomes: use vexide::{smart, adi};
            // We need to reconstruct the inner list content manually or reuse syntax if possible.
            // Since we are doing text replacement, we extract the inner content.

            let inner_trees: Vec<String> = list
                .use_trees()
                .filter_map(|t| {
                    // Recursively resolve children too, just in case of nested depth
                    // But for this specific rule, children of devices are usually leaves or simple groups
                    // We will assume direct children for simplicity, but strictly we should recurse.
                    // However, since we are replacing the WHOLE node, we must generate the full correct string.

                    // Simple approach for this demo: Just grab the text of children and hope they don't need deep recursion
                    // A robust solution requires building the string recursively.
                    let mut child_prefix = new_path_parts.clone();
                    // If child has a path, add it? No, the child path is relative.
                    // Actually, the easiest way is to generate the NEW use tree using `make` helpers if possible,
                    // but `make` doesn't support complex lists easily from scratch without a parser.

                    // Fallback: Construct string manually.
                    Some(t.syntax().text().to_string()) 
                })
                .collect();

            format!("{}::{{{}}}", new_path_parts.join("::"), inner_trees.join(", "))
        } else if is_glob {
            // Case: use vexide::devices::*;
            // Becomes: use vexide::*;
            format!("{}::*", new_path_parts.join("::"))
        } else {
            // Case: use vexide::devices::smart::Motor;
            // Becomes: use vexide::smart::Motor;
            // The path() we grabbed earlier included the specific item (Motor) if it was part of the path segment chain.
            // Wait, `tree.path()` usually stops before the final identifier if it's a rename? 
            // In `vexide::devices::smart::Motor`, the path is `vexide::devices::smart::Motor`.
            // Our `current_prefix` logic above captured all segments.
            // So `new_path_parts` already contains `vexide`, `smart`, `Motor`.
            new_path_parts.join("::")
        };

        // Build the replacement string. 
        // We must preserve aliases (e.g. `use old as new`).
        let alias = tree.rename().map(|r| r.syntax().text().to_string()).unwrap_or_default();
        let replacement = if alias.is_empty() {
            final_path_str
        } else {
            format!("{} {}", final_path_str, alias)
        };

        builder.replace(tree.syntax().text_range(), replacement);

        // Since we replaced the whole node, we do NOT recurse into children.
        return;
    }

    // 3. If no rewrite needed at this level, recurse into children
    if let Some(list) = tree.use_tree_list() {
        for child_tree in list.use_trees() {
            rewrite_use_tree(builder, &child_tree, &current_prefix);
        }
    }
}
