  "main.rs": "use radiate::{Op, Node, Tree, TreeLanguage, mutate, crossover, evaluate};
use std::sync::Arc;
use rnd::Rng;

// Define custom operation types
#[derive(Debug, Clone, Copy)]
enum CustomOp {
    Add,
    Sub,
    Mul,
    SqrtPlusOne, // Our custom operator: sqrt(x) + 1
}

impl CustomOp {
    fn arity(&self) -> usize {
        match self {
            CustomOp::Add | CustomOp::Sub | CustomOp::Mul => 2,
            CustomOp::SqrtPlusOne => 1,
        }
    }

    fn apply(&self, args: &[f64]) -> f64 {
        match self {
            CustomOp::Add => args[0] + args[1],
            CustomOp::Sub => args[0] - args[1],
            CustomOp::Mul => args[0] * args[1],
            CustomOp::SqrtPlusOne => (args[0].abs().sqrt()) + 1.0, // abs() to avoid NaN for negatives
        }
    }

    fn to_op(&self) -> Op<f64> {
        // We'll use Op::custom with a unique identifier
        match self {
            CustomOp::Add => Op::add(),
            CustomOp::Sub => Op::sub(),
            CustomOp::Mul => Op::mul(),
            CustomOp::SqrtPlusOne => Op::custom("sqrt_plus_one", self.arity(), move |args| {
                if args.len() != 1 {
                    return f64::NAN;
                }
                (args[0].abs().sqrt()) + 1.0
            }),
        }
    }
}

// Define our language
type Expr = Tree<CustomOp, f64>;

impl TreeLanguage<CustomOp, f64> for Expr {
    fn node_count(&self) -> usize {
        self.size()
    }

    fn depth(&self) -> usize {
        self.depth()
    }

    fn evaluate(&self, inputs: &[f64]) -> f64 {
        match self {
            Tree::Leaf(value) => *value,
            Tree::Node(op, children) => {
                let mut args = Vec::new();
                for child in children {
                    args.push(child.evaluate(inputs));
                }
                op.apply(&args)
            }
        }
    }

    fn mutate(&mut self, rng: &mut Rng, config: &radiate::Config) {
        mutate(self, rng, config);
    }

    fn crossover(&mut self, other: &mut Self, rng: &mut Rng, config: &radiate::Config) {
        crossover(self, other, rng, config);
    }
}

fn main() {
    // Create a simple dataset: y = sqrt(x) + 1 + noise
    let mut rng = Rng::new();
    let data: Vec<(Vec<f64>, f64)> = (0..20)
        .map(|i| {
            let x = i as f64 * 0.5;
            let y = (x.abs().sqrt()) + 1.0 + (rng.gen_range(-0.1..0.1));
            (vec![x], y)
        })
        .collect();

    // Define available operations
    let operations = vec![
        Op::add(),
        Op::sub(),
        Op::mul(),
        Op::custom("sqrt_plus_one", 1, |args| {
            if args.is_empty() {
                return f64::NAN;
            }
            (args[0].abs().sqrt()) + 1.0
        }),
    ];

    // Create initial population
    let mut population: Vec<Expr> = (0..50)
        .map(|_| {
            Tree::random(
                &mut rng,
                3, // max depth
                &operations,
                &vec![Op::constant(rng.gen_range(-5.0..5.0))],
            )
        })
        .collect();

    // Simple evolutionary loop
    for generation in 0..100 {
        // Evaluate fitness
        let mut fitnesses: Vec<f64> = population
            .iter()
            .map(|ind| {
                let mut error = 0.0;
                for (input, target) in &data {
                    let pred = ind.evaluate(input);
                    error += (pred - target).powi(2);
                }
                error / data.len() as f64 // MSE
            })
            .collect();

        // Find best individual
        let best_idx = fitnesses
            .iter()
            .enumerate()
            .min_by(|a, b| a.1.partial_cmp(b.1).unwrap())
            .unwrap()
            .0;

        if generation % 10 == 0 {
            println!(
                "Generation {}: Best MSE = {:.4}",
                generation, fitnesses[best_idx]
            );
        }

        // Selection and reproduction (simplified tournament selection)
        let mut new_population = Vec::new();
        while new_population.len() < population.len() {
            // Tournament selection
            let idx1 = rng.gen_range(0..population.len());
            let idx2 = rng.gen_range(0..population.len());
            let parent1 = if fitnesses[idx1] < fitnesses[idx2] {
                idx1
            } else {
                idx2
            };

            let idx1 = rng.gen_range(0..population.len());
            let idx2 = rng.gen_range(0..population.len());
            let parent2 = if fitnesses[idx1] < fitnesses[idx2] {
                idx1
            } else {
                idx2
            };

            let mut child = population[parent1].clone();
            let mut partner = population[parent2].clone();

            // Crossover
            child.crossover(&mut partner, &mut rng, &radiate::Config::default());

            // Mutation
            child.mutate(&mut rng, &radiate::Config::default());

            new_population.push(child);
        }

        population = new_population;
    }

    // Show best solution
    let final_fitnesses: Vec<f64> = population
        .iter()
        .map(|ind| {
            let mut error = 0.0;
            for (input, target) in &data {
                let pred = ind.evaluate(input);
                error += (pred - target).powi(2);
            }
            error / data.len() as f64
        })
        .collect();

    let best_idx = final_fitnesses
        .iter()
        .enumerate()
        .min_by(|a, b| a.1.partial_cmp(b.1).unwrap())
        .unwrap()
        .0;

    println!("\nBest solution found:");
    println!("{:?}", population[best_idx]);
    println!("Final MSE: {:.4}", final_fitnesses[best_idx]);

    // Test the best solution on some samples
    println!("\nTesting best solution:");
    for i in [0.0, 1.0, 4.0, 9.0, 16.0] {
        let input = vec![i];
        let pred = population[best_idx].evaluate(&input);
        let actual = (i.abs().sqrt()) + 1.0;
        println!("x={}: predicted={:.4}, actual={:.4}", i, pred, actual);
    }
}"
}

