  "main.rs": "use serde::de::{self, Deserialize, Deserializer, MapAccess, SeqAccess, Visitor};
use serde::ser::{Serialize, Serializer, SerializeStruct};
use std::fmt;

// Define the nested structures
#[derive(Debug, Clone)]
enum B {
    TypeOne { value: String },
    TypeTwo { count: u32 },
}

#[derive(Debug, Clone, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

// --- Serialization Implementations ---

impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::TypeOne { value } => {
                let mut state = serializer.serialize_struct("TypeOne", 2)?;
                state.serialize_field("type", "one")?;
                state.serialize_field("value", value)?;
                state.end()
            }
            B::TypeTwo { count } => {
                let mut state = serializer.serialize_struct("TypeTwo", 2)?;
                state.serialize_field("type", "two")?;
                state.serialize_field("count", count)?;
                state.end()
            }
        }
    }
}

impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?;
        state.end()
    }
}

// --- Deserialization Implementations ---

// Visitor for Enum B
struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a map representing enum B")
    }

    fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut type_field: Option<String> = None;
        let mut value_field: Option<String> = None;
        let mut count_field: Option<u32> = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "type" => {
                    let t: String = map.next_value()?;
                    type_field = Some(t);
                }
                "value" => {
                    let v: String = map.next_value()?;
                    value_field = Some(v);
                }
                "count" => {
                    let c: u32 = map.next_value()?;
                    count_field = Some(c);
                }
                // Ignore unknown fields if necessary, or error out
                _ => {
                    let _: de::IgnoredAny = map.next_value()?;
                }
            }
        }

        match type_field.as_deref() {
            Some("one") => {
                let value = value_field.ok_or_else(|| de::Error::missing_field("value"))?;
                Ok(B::TypeOne { value })
            }
            Some("two") => {
                let count = count_field.ok_or_else(|| de::Error::missing_field("count"))?;
                Ok(B::TypeTwo { count })
            }
            Some(other) => Err(de::Error::unknown_variant(other, &["one", "two"])),
            None => Err(de::Error::missing_field("type")),
        }
    }
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(BVisitor)
    }
}

// Visitor for Struct A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a map representing struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut val = A::default();
        let mut x_found = false;
        let mut b_found = false;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => {
                    val.x = map.next_value()?;
                    x_found = true;
                }
                "b" => {
                    // This is where we connect the levels.
                    // We ask the map for the next value, specifying the type Vec<B>.
                    // Serde will automatically use the custom Deserialize impl for B 
                    // for each element in the sequence.
                    val.b = map.next_value()?;
                    b_found = true;
                }
                _ => {
                    // Skip unknown fields
                    let _: de::IgnoredAny = map.next_value()?;
                }
            }
        }

        if !x_found {
            return Err(de::Error::missing_field("x"));
        }
        if !b_found {
            return Err(de::Error::missing_field("b"));
        }

        Ok(val)
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    // Example JSON input that matches our custom logic
    let json_data = r#"
    {
        "x": 42,
        "b": [
            { "type": "one", "value": "hello" },
            { "type": "two", "count": 100 }
        ]
    }
    "#;

    println!("Input JSON:\n{}\n", json_data);

    // Deserialize
    let parsed_a: A = match serde_json::from_str(json_data) {
        Ok(a) => a,
        Err(e) => {
            eprintln!("Deserialization error: {}", e);
            return;
        }
    };

    println!("Deserialized Struct A: {:?}", parsed_a);
    println!("First B item: {:?}", parsed_a.b.get(0));
    println!("Second B item: {:?}", parsed_a.b.get(1));

    // Serialize back to JSON to verify round-trip
    let output_json = match serde_json::to_string_pretty(&parsed_a) {
