  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(pub i32);

// The enum that holds the type-erased async workload.
// It stores a function that takes a mutable reference to Context and returns a pinned, boxed Future.
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context,
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
        >,
    },
}

/// Helper function to wrap an `AsyncFnOnce` closure and send it over a channel.
///
/// This handles the boxing and pinning required to store the closure in `InnerAsyncEvent`.
pub fn with_context_async<F>(work_sender: &mpsc::Sender<InnerAsyncEvent>, block: F)
where
    F: for<'a> FnOnce(&'a mut Context) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
        + Send
        + 'static,
{
    // We box the closure immediately. Since the closure implements FnOnce, 
    // we can only call it once, which matches the semantics of moving it into the channel.
    let boxed_block: Box<
        dyn for<'a> Fn(&'a mut Context)
                -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
            + Send,
    > = Box::new(block);

    let event = InnerAsyncEvent::DoWithContext {
        block: boxed_block,
    };

    // Ignore send errors for this example (channel closed)
    let _ = work_sender.try_send(event);
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<InnerAsyncEvent>(10);

    // Spawn a worker thread (task) that processes events
    let worker = tokio::spawn(async move {
        while let Some(event) = rx.recv().await {
            let mut ctx = Context(0);
            println!("Worker: Initial context value: {}", ctx.0);

            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // Call the closure to get the future, then await it
                    let fut = block(&mut ctx);
                    fut.await;
                }
            }

            println!("Worker: Final context value: {}", ctx.0);
        }
        println!("Worker: Channel closed, exiting.");
    });

    // --- Usage Example 1: Directly passing a boxed future returning closure ---
    with_context_async(&tx, |ctx: &mut Context| {
        Box::pin(async move {
            println!("Task 1: Running async work...");
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            ctx.0 += 10;
        })
    });

    // --- Usage Example 2: A slightly more complex closure ---
    with_context_async(&tx, |ctx: &mut Context| {
        Box::pin(async move {
            println!("Task 2: Doing more work...");
            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
            ctx.0 *= 2;
        })
    });

    // Drop sender to signal completion
    drop(tx);

    // Wait for worker to finish
    worker.await.unwrap();

    println!("Main: All tasks completed.");
}
"
}

