    // Rust SDK requires explicit streaming.
    let mut stream = container_client
        .list_blobs()
        .prefix(&prefix)
        .into_stream();

    let mut blob_names = Vec::new();

    while let Some(result) = stream.next().await {
        match result {
            Ok(response) => {
                for blob in response.blobs.blobs() {
                    if blob.name.ends_with(".json") {
                        blob_names.push(blob.name.clone());
                    }
                }
            }
            Err(e) => {
                eprintln!("Error listing blobs: {:?}", e);
                break;
            }
        }
    }

    println!("[LOG] Found {} JSON blobs for prefix '{}'", blob_names.len(), prefix);

    // Download and Deserialize concurrently
    // C# uses Parallel.ForEachAsync with MaxDegreeOfParallelism = ProcessorCount
    // We replicate this with a bounded stream or JoinSet
    let mut download_set = JoinSet::new();
    let max_concurrency = num_cpus::get(); // Similar to Environment.ProcessorCount

    for name in blob_names {
        let container = container_client.clone();

        // If we hit concurrency limit, wait for one to finish before spawning more
        // This mimics the throttling behavior of ParallelOptions
        if download_set.len() >= max_concurrency {
            if let Some(res) = download_set.join_next().await {
                if let Ok(Some(trade)) = res {
                    trades.push(trade);
                }
            }
        }

        download_set.spawn(async move {
            let blob_client = container.blob_client(&name);

            match blob_client.get_content().await {
                Ok(data) => {
                    // C# uses Newtonsoft.Json, we use serde_json
                    // serde is generally faster, but network is usually the bottleneck
                    match serde_json::from_slice::<TradeData>(&data) {
                        Ok(trade) => Some(trade),
                        Err(e) => {
                            eprintln!("Failed to parse JSON {}: {}", name, e);
                            None
                        }
                    }
                }
                Err(e) => {
                    eprintln!("Failed to download {}: {}", name, e);
                    None
                }
            }
        });
    }

    // Drain remaining tasks
    while let Some(res) = download_set.join_next().await {
        if let Ok(Some(trade)) = res {
            trades.push(trade);
        }
    }

    println!("[LOG] Prefix '{}' completed in {:.2}s ({} trades)", 
             prefix, start_prefix.elapsed().as_secs_f64(), trades.len());

    trades
}

