  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll, RawWaker, RawWakerVTable, Waker};
use tokio::runtime::Handle;

/// Result of a non-blocking poll attempt
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// A no-op waker that does nothing when woken.
/// This is safe to use for "try polling" because if the future returns Pending,
/// we explicitly handle it by spawning a task, so we don't rely on the waker
/// to resume execution.
fn create_noop_waker() -> Waker {
    fn noop_clone(_: *const ()) -> RawWaker {
        noop_raw_waker()
    }
    fn noop_wake(_: *const ()) {}
    fn noop_wake_by_ref(_: *const ()) {}
    fn noop_drop(_: *const ()) {}

    fn noop_raw_waker() -> RawWaker {
        RawWaker::new(
            std::ptr::null(),
            &RawWakerVTable::new(noop_clone, noop_wake, noop_wake_by_ref, noop_drop),
        )
    }

    unsafe { Waker::from_raw(noop_raw_waker()) }
}

/// Attempts to poll a future once without awaiting.
/// Returns Ready(value) if completed, or Pending if it needs to wait.
fn try_poll<X>(future: &mut Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = create_noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Helper to simulate a future that might be ready immediately or pending
async fn maybe_immediate(id: u32) -> String {
    if id % 2 == 0 {
        // Even IDs complete immediately (no await points effectively)
        format!("Result-{}-Immediate", id)
    } else {
        // Odd IDs yield once, forcing Pending on first poll
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
        format!("Result-{}-Deferred", id)
    }
}

#[tokio::main]
async fn main() {
    println!("Starting manual poll demonstration...");

    // We need a vector to hold the futures so they don't move in memory
    // while we hold mutable references to them for polling.
    let mut futures: Vec<Pin<Box<dyn Future<Output = String>>>> = Vec::new();

    // Create 5 test futures
    for i in 0..5 {
        futures.push(Box::pin(maybe_immediate(i)));
    }

    // Iterate and try to poll manually
    for (i, fut) in futures.iter_mut().enumerate() {
        match try_poll(fut) {
            TryPollResult::Ready(val) => {
                println!("[Sync Path] Future {} completed immediately: {}", i, val);
            }
            TryPollResult::Pending => {
                println!("[Async Path] Future {} is pending. Spawning task...", i);

                // We need to move the future into the spawned task.
                // Since we have a Pin<&mut dyn Future>, we can't easily move it out 
                // without some unsafe trickery or restructuring. 
                // In a real scenario, you likely own the future or use an Option.
                // Here, we will demonstrate the pattern by re-creating the logic 
                // or assuming we can extract it. 
                //
                // To make this code compile and work safely with the vector approach,
                // we'll replace the pending future with a dummy and take ownership.

                // Swap with a dummy future so we can take ownership of the original
                let dummy = Box::pin(async { String::from("dummy") }) as Pin<Box<dyn Future<Output = String>>>;
                let mut taken_future = std::mem::replace(fut, dummy);

                tokio::spawn(async move {
                    // Now we can await normally
                    let result = taken_future.await;
                    println!("  -> [Task] Future completed in background: {}", result);
                });
            }
        }
    }

    // Give spawned tasks time to complete before exiting
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    println!("Done.");
}
"
