// A wrapper struct to hold the logger and provide templated logging methods.
// We use a Mutex to allow interior mutability since the syslog logger requires &mut self.
struct AppLogger {
    inner: Mutex<BasicLogger>,
}

impl AppLogger {
    fn new(logger: BasicLogger) -> Self {
        AppLogger {
            inner: Mutex::new(logger),
        }
    }

    // A generic private helper to handle the repeated .expect() and formatting logic
    fn log<F>(&self, level: Level, message_fn: F)
    where
        F: FnOnce() -> String,
    {
        let mut logger = self.inner.lock().expect("Logger mutex poisoned");
        let msg = message_fn();

        let result = match level {
            Level::Error => logger.err(&msg),
            Level::Warn => logger.warning(&msg),
            Level::Info => logger.info(&msg),
            Level::Debug => logger.debug(&msg),
            Level::Trace => logger.trace(&msg),
        };

        result.expect("Failed to log message");
    }

    // Public templated methods for specific levels
    pub fn info<F>(&self, message_fn: F)
    where
        F: FnOnce() -> String,
