{
  "Cargo.toml": "[package]
name = "rustyline-cursor-fix"
version = "0.1.0"
edition = "2021"

[dependencies]
rustyline = "14.0"
",
  "main.rs": "use rustyline::conditional::{ConditionalEventHandler, EventContext};
use rustyline::config::Configurer;
use rustyline::error::ReadlineError;
use rustyline::highlight::Highlighter;
use rustyline::hint::Hinter;
use rustyline::validate::Validator;
use rustyline::{Cmd, Editor, Event, EventHandler, KeyEvent, Movement, RepeatCount};
use std::borrow::Cow;

/// Custom event handler that replaces preceding whitespace with a specific character
/// and ensures the cursor ends up AFTER the inserted character.
struct WhitespaceReplacer {
    insert_char: char,
}

impl WhitespaceReplacer {
    fn new(c: char) -> Self {
        Self { insert_char: c }
    }
}

impl ConditionalEventHandler for WhitespaceReplacer {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Look at the substring before the cursor
        let prefix = &line[0..pos];

        // Find the index of the last non-whitespace character
        if let Some(last_non_ws_index) = prefix.rfind(|c: char| !c.is_whitespace()) {
            // Calculate how many whitespace characters are between the last non-ws char and the cursor
            let ws_start = last_non_ws_index + 1;
            let ws_count = pos - ws_start;

            if ws_count > 0 {
                // We have whitespace to replace.
                // Strategy: 
                // 1. Move cursor backward by (ws_count + 1) to land on the last non-ws char? 
                //    No, we want to delete the whitespace and insert the char.
                // 
                // The Cmd::Replace(movement, Some(text)) replaces the text covered by 'movement'
                // with 'text', and places the cursor AFTER the inserted text.
                //
                // We want to replace the 'ws_count' whitespace characters with our char.
                // So we need a movement that selects exactly those whitespace characters.
                // The cursor is currently at 'pos'. The whitespace starts at 'ws_start'.
                // We need to move backward by 'ws_count' to select the whitespace.

                let movement = Movement::BackwardChar(ws_count as RepeatCount);
                let replacement = self.insert_char.to_string();

                // Cmd::Replace will delete the selected range (the whitespace) and insert 'replacement'.
                // Crucially, rustyline's implementation of Replace positions the cursor after the inserted text.
                return Some(Cmd::Replace(movement, Some(replacement)));
            }
        }

        // If no preceding whitespace was found, just insert the character normally.
        // We can simulate this by replacing 0 characters (current position) with the char.
        // Or simply return None to let the default handler insert the char? 
        // Returning None might trigger the default behavior which is insertion.
        // However, to be explicit and consistent, let's try to insert at current pos.
        // Cmd::Insert is not directly available here easily without knowing count.
        // Let's just return None to fall back to default insertion if no whitespace found.
        None
    }
}

// Dummy implementation for CommandHelper traits to keep the example self-contained
#[derive(Clone)]
struct CommandHelper;
impl Highlighter for CommandHelper {}
impl Hinter for CommandHelper {
    type Hint = String;
}
impl Validator for CommandHelper {}
impl rustyline::Helper for CommandHelper {}

fn main() -> Result<(), ReadlineError> {
    let mut rl: Editor<CommandHelper, rustyline::history::DefaultHistory> = Editor::new()?;
    rl.set_helper(Some(CommandHelper));

    // Bind '.' key
    let dot_event = KeyEvent::new('.', rustyline::Modifiers::NONE);
    let dot_handler = WhitespaceReplacer::new('.');
    rl.bind_sequence(
        dot_event,
        EventHandler::Conditional(Box::new(dot_handler)),
    );

    // Bind ',' key
    let comma_event = KeyEvent::new(',', rustyline::Modifiers::NONE);
    let comma_handler = WhitespaceReplacer::new(',');
    rl.bind_sequence(
        comma_event,
        EventHandler::Conditional(Box::new(comma_handler)),
    );

    println!("SQL Tool Demo");
    println!("Try typing: SELECT book <TAB> (if you had completer) then '.'");
    println!("Or simply: SELECT book  . (type space space then dot)");
    println!("The dots/commas should eat preceding spaces and leave cursor after them.");
    println!("Press Ctrl+C or Ctrl+D to exit.\n");

    loop {
        let readline = rl.readline("zql> ");
        match readline {
            Ok(line) => {
                rl.add_history_entry(line.as_str())?;
                println!("Executed: {}", line);
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                break;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }

    Ok(())
}
"
}

{
  "Cargo.toml": "[package]
name = "axum-ws-origin-check"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = { version = "0.7", features = ["ws"] }
axum-extra = { version = "0.9", features = ["typed-header"] }
tokio = { version = "1", features = ["full"] }
headers = "0.4"
http = "1"
hyper = "1"
tower = "0.4"
tracing = "0.1"
tracing-subscriber = { version = "0.3", features = ["env-filter"] }
",
  "main.rs": "use axum::{
    extract::{connect_info::ConnectInfo, ws::WebSocketUpgrade, Path},
    response::IntoResponse,
    routing::get,
    Router,
};
use axum_extra::{
    headers::{HeaderMapExt, Origin},
    typed_header::TypedHeader,
};
use http::{HeaderMap, StatusCode};
use std::net::SocketAddr;
use tower::ServiceBuilder;
use tower_http::trace::TraceLayer;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

// Define the allowed origin strictly
const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::new(
            std::env::var("RUST_LOG").unwrap_or_else(|_| "debug".into()),
        ))
        .with(tracing_subscriber::fmt::layer())
        .init();

    // Build the app
    // We use a ServiceBuilder to apply a layer that checks the Origin header
    // before the request even reaches the router/handler.
    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .layer(
            ServiceBuilder::new()
                .layer(TraceLayer::new_for_http())
                .layer_fn(validate_origin_middleware),
        );

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    tracing::info!("Listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

/// A custom middleware function that validates the Origin header.
/// If the origin is missing or not allowed, it returns a 403 Forbidden immediately.
/// This prevents the WebSocket upgrade from happening.
async fn validate_origin_middleware<B>(
    mut request: http::Request<B>,
    next: tower::Service<http::Request<B>, Response = http::Response<axum::body::Body>, Error = std::convert::Infallible>,
>) -> Result<http::Response<axum::body::Body>, std::convert::Infallible> {
    let headers = request.headers();

    // Check if Origin header exists
    if let Some(origin_value) = headers.get(http::header::ORIGIN) {
        let origin_str = origin_value.to_str().unwrap_or("");

        // Strict comparison. In production, you might want more robust parsing
        // to handle ports or subdomains dynamically, but this suffices for exact matches.
        if origin_str == ALLOWED_ORIGIN {
            return Ok(next.call(request).await?);
        }
    }

    // If origin is missing or doesn't match, return 403
    tracing::warn!("Blocked WebSocket connection attempt from invalid or missing Origin");

    let mut response = http::Response::new(axum::body::Body::from("Forbidden: Invalid Origin"));
    *response.status_mut() = StatusCode::FORBIDDEN;
    Ok(response)
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
    // We can still extract the TypedHeader here if we need to use the specific value
    // inside the handler logic, though the middleware already validated it.
    TypedHeader(origin): TypedHeader<Origin>,
) -> impl IntoResponse {
    tracing::info!("Accepted WebSocket connection for session {} from {}", session_id, origin);

    ws.on_upgrade(move |socket| async move {
        // Handle the websocket connection here
        let (mut sender, mut receiver) = socket.split();

        // Simple echo loop for demonstration
        while let Some(msg) = receiver.recv().await {
            if let Ok(msg) = msg {
                if sender.send(msg).await.is_err() {
                    break;
                }
            } else {
                break;
            }
        }
    })
}
"
}

