Task: How to cache tokio_postgres::Client without closing the connection?

 <p>I'm writing a library for creating and dropping postgres databases. I use it in tests to spin up and tear down test databases. Here is a snippet that works (excuse the lack of sql sanitizing. it's only used by myself in tests):</p>
<pre class="lang-rs prettyprint-override"><code>use tokio_postgres::{Client, NoTls};

pub struct DbContainer {
    container_name: String,
    args: Vec&lt;String&gt;,
    db_config: DbConfig,
}

#[derive(Debug)]
pub struct DbConfig {
    pub port: u16,
    pub name: String,
    pub user: String,
    pub postgres_password: String,
    pub db_password: String,
}

impl DbContainer {
    pub fn new&lt;N&gt;(container_name: N, db_config: DbConfig) -&gt; Self
    where
        N: Into&lt;String&gt;,
    {
        Self {
            container_name: container_name.into(),
            args: vec![
                &quot;--env&quot;.to_string(),
                format!(&quot;POSTGRES_PASSWORD={}&quot;, &amp;db_config.postgres_password),
                &quot;--publish&quot;.to_string(),
                format!(&quot;{}:5432&quot;, db_config.port),
            ],
            db_config,
        }
    }

    pub async fn create_database(&amp;self, name: &amp;str) -&gt; Result&lt;(), tokio_postgres::Error&gt; {
        let client = self.connect(None).await?;
        client
            .execute(&amp;format!(&quot;CREATE DATABASE {name}&quot;), &amp;[])
            .await?;
        let client = self.connect(Some(name)).await?;
