/// Wrapper to hold the Client and ensure the Connection task is kept alive.
/// The Connection future must be polled for the Client to remain functional.
/// If the Connection future drops, the connection closes.
struct DbPool {
    client: Client,
    // We store the join handle to ensure the background task outlives the DbPool.
    // Even though the task is spawned globally, holding the JoinHandle here
    // conceptually ties the lifecycle of the connection pump to the pool instance
    // and prevents any confusion about task cancellation if the scope changes.
    _connection_task: tokio::task::JoinHandle<Result<(), Error>>,
}

pub struct DbContainer {
    port: u16,
    password: String,
    // We cache the DEFAULT connection (postgres database) only.
    // Other connections (to specific test DBs) are created on demand and dropped.
    default_pool: Mutex<Option<Arc<DbPool>>>,
}

impl DbContainer {
    pub fn new(port: u16, password: String) -> Self {
        Self {
            port,
            password,
            default_pool: Mutex::new(None),
        }
    }

    /// Returns a cached client for the default 'postgres' database.
    async fn get_default_client(&self) -> Result<Arc<DbPool>, Error> {
        let mut guard = self.default_pool.lock().await;

        if let Some(pool) = guard.as_ref() {
            return Ok(Arc::clone(pool));
        }

        let conn_str = format!(
            "host=localhost port={} user=postgres password={}",
            self.port, self.password
        );

        let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;

        // CRITICAL: The connection future must be polled continuously.
        // We spawn it as a background task.
        let task_handle = tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("Connection error: {}", e);
            }
        });

        let pool = Arc::new(DbPool {
            client,
            _connection_task: task_handle,
        });

        *guard = Some(Arc::clone(&pool));
        Ok(pool)
    }

    /// Creates a new database using the cached default client,
    /// then connects to the new database (non-cached) to load schema.
    pub async fn create_database(&self, name: &str) -> Result<(), Error> {
        // 1. Use cached default client to create the DB
        let pool = self.get_default_client().await?;
        pool.client
            .execute(&format!("CREATE DATABASE {}", name), &[])
            .await?;

        // 2. Connect to the NEW database to load schema.
        // This connection is NOT cached. It is created, used, and dropped.
        let conn_str = format!(
