use tokio::sync::{mpsc, Mutex};

/// This example demonstrates the correct concurrency pattern for interacting
/// with a PTY using `expectrl` in an async environment (like Tauri).
///
/// THE PROBLEM:
/// Holding a `Mutex<Session>` while calling blocking `read()` prevents other
/// threads from acquiring the lock to `write()`, causing a deadlock when the
/// process is waiting for input.
///
/// THE SOLUTION:
/// 1. Use `expectrl`'s polling capabilities (`PollEvent`) to check if data is
///    available without blocking indefinitely.
/// 2. Or, simpler for full-duplex: Use a single owner task that holds the Session,
///    and communicate via MPSC channels for both Input (TX) and Output (RX).
///
/// This implementation uses the "Single Owner + Channels" pattern, which is
/// robust, avoids mutex contention entirely, and fits perfectly with Tauri's
/// event system.

#[tokio::main]
async fn main() -> Result<()> {
    println!("Starting PTY Concurrency Demo...");
    println!("Spawning 'bash' (interactive shell). Try typing commands below.");
    println!("Type 'exit' to quit the demo.");

    // 1. Spawn the PTY session
    // We use bash -i to ensure it behaves like an interactive terminal
    let mut session = spawn("bash", ["-i"])
        .context("Failed to spawn bash process")?;

    // Configure the session for raw mode (essential for TUIs like Codex/Gemini)
    session.set_raw_mode(true)?;

    // 2. Create channels for communication
    // tx_output: Sends data FROM the PTY to the frontend (simulated by stdout here)
    // rx_input: Receives data TO the PTY from the frontend (simulated by stdin here)
    let (tx_output, mut rx_output) = mpsc::unbounded_channel::<String>();
    let (tx_input, mut rx_input) = mpsc::unbounded_channel::<String>();

    // Wrap session in Arc<Mutex> ONLY if we need multiple owners. 
    // However, the best pattern is a SINGLE task owning the session.
    // We will move `session` into a dedicated tokio task.

    // 3. Spawn the PTY Manager Task
    // This task exclusively owns the `Session`. It handles both reading and writing.
    // Because it owns the session, no mutex is needed for the session itself.
    let pty_handle = tokio::task::spawn_blocking(move || {
        run_pty_loop(session, tx_output, rx_input)
    });

    // 4. Simulate the Frontend (Tauri Command / xterm.js)
    // In a real app, `tx_input` would be called inside your `#[tauri::command]`
    // and `rx_output` would be listened to by Tauri's event emitter.
    let frontend_handle = tokio::spawn(async move {
        run_frontend_simulator(tx_input, rx_output).await
    });

    // Wait for both tasks to complete
    let _ = tokio::join!(pty_handle, frontend_handle);

    println!("Demo finished.");
    Ok(())
}

/// The core PTY loop running in a blocking thread (required for expectrl polling mostly,
/// though we mix it with channel recv which needs care).
/// 
/// STRATEGY:
/// We use `session.check_events()` with a timeout. This allows us to:
/// 1. Check if the PTY has output (Read).
/// 2. Check if our channel has input (Write) without blocking the read indefinitely.
fn run_pty_loop(
    mut session: Session,
    tx_output: mpsc::UnboundedSender<String>,
    mut rx_input: mpsc::UnboundedReceiver<String>,
) -> Result<()> {
    let mut buffer = [0u8; 4096];

    loop {
        // We need to check for input from the channel AND output from the PTY.
        // Since `rx_input.recv()` is blocking and `session.check_events` is blocking,
        // we orchestrate them carefully.

        // Approach: Use a short timeout on polling to allow checking the channel periodically,
        // OR use select! if we were fully async. Since expectrl session is not fully async-native
        // in v0.7 without wrappers, we use a hybrid approach.

        // Check for incoming data from Frontend (non-blocking try_recv first)
        if let Ok(data) = rx_input.try_recv() {
            // Write to PTY
            // Note: No mutex needed, we own the session here!
            session.write_all(data.as_bytes())?;
            session.flush()?;
            // Continue loop immediately to prioritize writing
            continue;
        }

        // Poll the PTY for output with a short timeout (e.g., 50ms)
        // This acts as the "heartbeat" allowing us to return control to check rx_input again
        match session.check_events(Some(Duration::from_millis(50))) {
            Ok(events) => {
                for event in events {
                    match event {
                        Event::IO(ev) => {
                            if ev.is_ready_for_read() {
                                match session.read(&mut buffer) {
                                    Ok(n) => {
                                        if n == 0 {
                                            // EOF
                                            let _ = tx_output.send("\n[Process exited]".to_string());
                                            return Ok(());
                                        }
                                        let chunk = String::from_utf8_lossy(&buffer[..n]).to_string();
                                        if tx_output.send(chunk).is_err() {
                                            return Ok(()); // Receiver dropped
                                        }
                                    }
                                    Err(e) => {
                                        if e.kind() != std::io::ErrorKind::WouldBlock {
                                            eprintln!("Read error: {}", e);
                                            return Err(e.into());
                                        }
                                    }
                                }
                            }
                        }
                        Event::Eof(Eof::ProcessExit) => {
                            let _ = tx_output.send("\n[Process terminated]".to_string());
                            return Ok(());
                        }
                        _ => {}
                    }
                }
            }
            Err(e) => {
                // Timeout or interrupted is fine, we just loop again to check rx_input
                if e.kind() != std::io::ErrorKind::TimedOut {
                     // Real error
                     // eprintln!("Poll error: {}", e); 
                     // In expectrl, check_events returning an error usually means timeout if configured,
                     // but let's be safe. If it's a real IO error on the pty fd, we might want to break.
                }
            }
        }
    }
}

/// Simulates the Tauri Frontend:
/// 1. Reads PTY output and prints to console (simulating xterm.js render).
/// 2. Reads user stdin and sends to PTY (simulating Tauri command).
async fn run_frontend_simulator(
    tx_input: mpsc::UnboundedSender<String>,
    mut rx_output: mpsc::UnboundedReceiver<String>,
) {
    // Task: Print PTY output
    let output_task = tokio::spawn(async move {
        while let Some(data) = rx_output.recv().await {
            print!("{}", data);
            // Ensure output is flushed so user sees it immediately
            use std::io::Write;
            std::io::stdout().flush().unwrap();
        }
    });

    // Task: Read User Input and forward to PTY
    // We use tokio::io for async stdin reading so it doesn't block the output task
    use tokio::io::{AsyncBufReadExt, BufReader};
    let stdin = tokio::io::stdin();
    let mut reader = BufReader::new(stdin);
    let mut line = String::new();

    loop {
        // Note: In a real TUI (xterm.js), you wouldn't read line-by-line.
        // You would capture individual keycodes. 
        // For this CLI demo, we read lines to simulate sending a command.
        // To make it feel interactive, we read char by char if we wanted raw mode in the outer console,
        // but let's stick to lines for simplicity of the demo script.

        // Actually, to simulate raw keystrokes better in a console app:
        // We'll just read a line and send it + \n
        line.clear();

        // Use a blocking read in a spawn_blocking or just await if we don't care about 
        // cancelling this specific read. Since we are in tokio::main, await is fine.
        // But std::io::stdin().read_line is blocking. Let's use tokio async.
        if reader.read_line(&mut line).await.unwrap() == 0 {
            break; // EOF
        }

        if line.trim() == "exit" {
            break;
        }

        // Send the line + newline to the PTY
        // In a real xterm integration, you send exact byte sequences (ARROW keys, etc)
        if tx_input.send(line.clone()).is_err() {
            break;
        }
    }

    output_task.abort();
}
"
