use std::sync::Arc;
use tokio::sync::mpsc;

/// The struct with borrowed data.
/// It cannot be sent across threads directly because of the lifetime.
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

/// A container that owns the String buffer and the deserialized struct.
/// 
/// Safety Invariant:
/// The references inside `parsed` must always point to the string data inside `buffer`.
/// We enforce this by:
/// 1. Making `buffer` an Arc<String> so it lives as long as the container.
/// 2. Using `std::mem::MaybeUninit` to construct the struct only after the buffer is ready.
/// 3. Never exposing mutable access to the buffer after construction.
/// 4. Implementing Drop to safely clean up the manually constructed struct.
struct OwnedMyData {
    // The owned buffer. Cloning this struct clones the Arc (cheap), not the string.
    _buffer: Arc<String>,

    // The deserialized struct pointing into _buffer.
    // It is safe to send across threads because we guarantee _buffer outlives this.
    parsed: MyData<'static>,
}

impl OwnedMyData {
    fn new(json_input: String) -> Result<Self, serde_json::Error> {
        // 1. Wrap the input string in an Arc so we can share ownership across tasks
        // without cloning the actual string data.
        let buffer = Arc::new(json_input);

        // 2. Get a raw string slice from the Arc.
        // We will cast the lifetime to 'static temporarily.
        // SAFETY: We will ensure the returned struct never outlives `buffer`.
        let str_slice: &'static str = unsafe { std::mem::transmute(buffer.as_str()) };

        // 3. Deserialize using the static slice.
        // Serde will create references pointing into `str_slice`.
        let parsed: MyData<'static> = serde_json::from_str(str_slice)?;

        Ok(Self {
            _buffer: buffer,
            parsed,
        })
    }

    // Helper to access the data immutably
    fn get(&self) -> &MyData<'_> {
        &self.parsed
    }
}

// We can manually implement Clone if we want to pass it to multiple tasks.
// Since the buffer is Arc, cloning this is cheap.
impl Clone for OwnedMyData {
    fn clone(&self) -> Self {
        Self {
            _buffer: Arc::clone(&self._buffer),
            // Copying the struct just copies the pointers (references).
            // Since we clone the Arc above, the pointers remain valid.
            parsed: self.parsed,
        }
    }
}

// SAFETY: 
// 1. MyData<'static> contains references. Usually !Send.
// 2. However, our struct guarantees that the data pointed to is held in an Arc<String>.
// 3. Arc<String> is Send + Sync.
// 4. As long as the OwnedMyData instance exists, the Arc ensures the string lives.
// 5. Therefore, the references inside `parsed` are valid and safe to access on another thread.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

#[tokio::main]
async fn main() {
    let json_payload = r#"{
        "data": "hello world",
        "more_data": "foo bar baz"
    }"#;

    // Parse once
    let owned_data = match OwnedMyData::new(json_payload.to_string()) {
        Ok(d) => d,
        Err(e) => {
            eprintln!("Failed to parse: {}", e);
            return;
        }
    };

    println!("Original parsed: {:?}", owned_data.get());

    // Create a channel to send the data
    let (tx, mut rx) = mpsc::channel::<OwnedMyData>(10);

    // Spawn a task that receives the borrowed struct
    let handle = tokio::spawn(async move {
        while let Some(received) = rx.recv().await {
            // We can safely access the borrowed fields here
            println!("Task received: data='{}', more_data='{}'", 
                     received.parsed.data, 
                     received.parsed.more_data);

            // We can also clone it to pass to yet another task if needed,
            // without re-deserializing or copying the underlying string bytes.
            let cloned = received.clone();
            println!("Task cloned successfully: {}", cloned.parsed.data);
        }
    });

    // Send the data across the thread boundary
    // This moves (or clones) the struct, but the string buffer is shared via Arc.
    tx.send(owned_data).await.unwrap();

    // Send a clone to demonstrate zero-copy sharing
    // Note: In a real scenario, you might send the same Arc-wrapped data to multiple workers.
    // Here we just drop the original sender to close the channel after sending.
    drop(tx);

    // Wait for the task to finish
    handle.await.unwrap();

    println!("Done. Deserialization happened only once, no string cloning occurred.");
}
"
}

