/// Flips a single line of 4-byte pixels horizontally.
///
/// This implementation uses `copy_nonoverlapping` to move 4 bytes at once,
/// which allows the compiler to generate efficient block memory move instructions
/// (like MOVQ on x86_64 or LDP/STP on ARM64) rather than individual byte swaps.
/// This is generally faster than swapping byte-by-byte while remaining safe
/// regarding aliasing rules compared to raw pointer swapping of overlapping regions
/// (though here regions don't overlap, block copying is idiomatic).
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    let len = line_bytes.len();
    if len == 0 {
        return;
    }

    let mut left = 0;
    let mut right = len - BYTES_PER_PIXEL;

    while left < right {
        unsafe {
            let ptr = line_bytes.as_mut_ptr();

            // Read the 4 bytes from the left pixel into a temporary stack buffer
            let mut temp: [u8; BYTES_PER_PIXEL] = std::mem::MaybeUninit::uninit().assume_init();
            std::ptr::copy_nonoverlapping(ptr.add(left), temp.as_mut_ptr(), BYTES_PER_PIXEL);

            // Copy the 4 bytes from the right pixel to the left position
            std::ptr::copy_nonoverlapping(ptr.add(right), ptr.add(left), BYTES_PER_PIXEL);

            // Copy the saved temp bytes to the right position
            std::ptr::copy_nonoverlapping(temp.as_ptr(), ptr.add(right), BYTES_PER_PIXEL);
