impl<T> Array<T> {
    pub fn new(dims: Vec<usize>, data: Vec<T>) -> Self {
        if data.len() != dims.iter().product() {
            panic!("Data length does not match dimensions");
        }
        let mut strides = vec![0; dims.len()];
        let mut stride = 1;
        for i in (0..dims.len()).rev() {
            strides[i] = stride;
            stride *= dims[i];
