/// Splits a shell command string into tokens, respecting single quotes.
///
/// Behavior:
/// - Text outside quotes is split by whitespace (multiple spaces act as one delimiter).
/// - Text inside single quotes is treated as a single token, preserving internal spaces.
/// - The quotes themselves are removed from the resulting tokens.
/// - Empty tokens are discarded.
fn tokenize(s: &str) -> Vec<String> {
    s.split(''')
     .enumerate()
     .flat_map(|(i, segment)| {
         if i % 2 == 0 {
             // Even index: Outside quotes. Split by whitespace.
             // We map non-empty trimmed parts to Some(String), empty to None.
             segment
                 .split_whitespace()
                 .map(|s| s.to_string())
                 .collect::<Vec<_>>()
         } else {
             // Odd index: Inside quotes. Treat the whole segment as one token.
             // Note: If the shell logic requires preserving leading/trailing spaces inside quotes,
             // we keep them. If the segment is empty (e.g. ''), it results in an empty string.
             vec![segment.to_string()]
         }
     })
     .filter(|s| !s.is_empty())
     .collect()
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("Input: {}", input);
    println!("Token count: {}", tokens.len());
    for (i, token) in tokens.iter().enumerate() {
        println!("[{}]: <{}>", i, token);
    }

    // Verification against expected output:
    // Expected: ["one", " two  three", "four"]
    assert_eq!(tokens.len(), 3);
    assert_eq!(tokens[0], "one");
    assert_eq!(tokens[1], " two  three");
    assert_eq!(tokens[2], "four");

    println!("\nAll assertions passed!");
}"
