// Global Drag State stored in Context
#[derive(Clone, Copy, Debug)]
pub struct DragState {
    pub mouse_pos: Signal<ElementPoint>,
    pub is_dragging: Signal<bool>,
}

impl DragState {
    fn new() -> Self {
        Self {
            mouse_pos: use_signal(|| ElementPoint { x: 0.0, y: 0.0 }),
            is_dragging: use_signal(|| false),
        }
    }
}

#[derive(Clone, Copy, PartialEq, Debug)]
pub struct ElementPoint {
    pub x: f64,
    pub y: f64,
}

impl ElementPoint {
    pub fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
}

#[component]
fn App() -> Element {
    rsx! {
        DragProvider {
            SvgCanvas {}
        }
    }
}

#[component]
fn DragProvider(children: Element) -> Element {
    // Provide the context to all children
    let mut drag_state = use_context_provider(|| DragState::new());

    // We attach global listeners to the container div.
    // This ensures we capture mouse moves even if the cursor leaves the specific SVG element,
    // solving the "breaks when mouse leaves" issue.
    rsx! {
        div {
            style: "width: 100vw; height: 100vh; display: flex; justify-content: center; align-items: center; background-color: #f0f0f0;",

            // Update global mouse position on move
            onmousemove: move |e| {
                let coords = e.element_coordinates();
                drag_state.mouse_pos.set(ElementPoint::new(coords.x as f64, coords.y as f64));
            },

            // Update global drag state
            onmousedown: move |_| {
                drag_state.is_dragging.set(true);
            },
            onmouseup: move |_| {
                drag_state.is_dragging.set(false);
            },
            onmouseleave: move |_| {
                drag_state.is_dragging.set(false);
            },

            {children}
        }
    }
}

#[component]
fn SvgCanvas() -> Element {
    rsx! {
        svg {
            width: "800",
            height: "600",
            style: "background-color: white; border: 1px solid #ccc; cursor: crosshair;",

            DraggablePoint { x: 100.0, y: 100.0, color: "red" }
            DraggablePoint { x: 200.0, y: 150.0, color: "blue" }
            DraggablePoint { x: 300.0, y: 120.0, color: "green" }

            // Visual debug info
            text { x: 10, y: 20, font_size: "14", "Drag the circles! Events are handled globally via Context." }
        }
    }
}

#[component]
fn DraggablePoint(x: f64, y: f64, color: String) -> Element {
    // Local state for this specific point's position
    let mut position = use_signal(|| ElementPoint::new(x, y));

    // Local state to track if THIS specific point was the one clicked
    let mut is_active_point = use_signal(|| false);

    // Access global drag context
    let drag_state = use_context::<DragState>();
    let global_mouse = drag_state.mouse_pos;
    let global_is_dragging = drag_state.is_dragging;

    // The Magic: Use a reactive effect (use_effect) to listen to global signals
    // without requiring the component to re-render via props changes.
    // This runs whenever global_mouse or global_is_dragging changes.
    use_effect(move || {
        let is_globally_dragging = *global_is_dragging.read();
        let current_mouse = *global_mouse.read();
        let my_active = *is_active_point.read();

        if my_active && is_globally_dragging {
            // If this point is active and the mouse is down globally, update position
            position.set(current_mouse);
        } else if !is_globally_dragging {
            // If mouse is released globally, deactivate this point
            if my_active {
                is_active_point.set(false);
            }
        }
    });

    let current_pos = *position.read();

    rsx! {
        circle {
            cx: current_pos.x,
            cy: current_pos.y,
            r: "20",
            fill: color,
            stroke: "black",
            stroke_width: "2",
            style: "cursor: grab;",

            // Only need to set local "active" state on mousedown
            // The rest is handled by the global context + use_effect
            onmousedown: move |_| {
                is_active_point.set(true);
            },
        }
    }
}"
}

