        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn new(elems: Vec<B>, cutoff: f64) -> Self {
        A { elems, cutoff }
    }

    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe sequential implementation answering Q1 and Q2
    /// 
    /// Q1: We avoid unsafe pointers by using indexed access. Since we only read from `elems` 
    /// while mutating specific fields of the current element, we can safely borrow the whole 
    /// vector immutably for reads and use indexed mutation for the specific element.
    /// 
    /// Q2: To modify both elem_i and elem_j, we cannot do it easily in a single pass with 
    /// standard borrowing rules without interior mutability or splitting the logic. 
    /// Here we demonstrate the standard pattern: calculate pairs once, but since the requirement 
    /// is "look for all following elements", we only check j > i. If mutual modification is needed,
    /// we can push to both lists within the same scope if we had unique access, but in a parallel 
    /// or split-borrow scenario, using a Mutex or atomic operations on the specific field is common.
    /// 
    /// This specific implementation focuses on building the neighbor list (nb) for each element.
    pub fn build_lists_safe(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // We iterate by index to avoid borrowing conflicts between the iterator and indexed access
        for i in 0..nelems {
            self.elems[i].nb.clear();

            // Only check following elements (j > i) to avoid duplicate work and self-comparison
            for j in (i + 1)..nelems {
                // Safe immutable borrows of two distinct elements
                let dist_sq = {
                    let elem_i = &self.elems[i];
                    let elem_j = &self.elems[j];
                    elem_i.criterion(elem_j)
