    ///    to allow concurrent pushes from multiple threads.
    /// 3. We parallelize the outer loop (i). Inside, we iterate j > i sequentially (or could use 
    ///    another parallel layer, but usually one level is enough for this O(N^2) pattern).
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // Clear existing lists and wrap the `nb` field in a Mutex for thread-safe mutation
        // We temporarily transform the structure to allow parallel access
        // Note: In a real high-performance scenario, we might use `Vec<SpinLock<...>>` or 
        // pre-allocated buffers with atomic counters to avoid Mutex overhead, but Mutex is safest.

        // To avoid changing the struct definition, we will use a scope where we borrow 
        // the slices and manage synchronization manually.

        // Reset lists sequentially first
        for elem in &mut self.elems {
            elem.nb.clear();
        }

        // Create a vector of Mutexes to guard the neighbor lists during parallel execution
        // We map over the elems to create guards only for the `nb` field, keeping data local
        let nb_guards: Vec<Mutex<Vec<usize>>> = self
            .elems
            .iter()
            .map(|_| Mutex::new(Vec::new()))
            .collect();

        // Parallel iteration over indices
        (0..nelems).into_par_iter().for_each(|i| {
            for j in (i + 1)..nelems {
                let dist_sq = {
                    let elem_i = &self.elems[i];
                    let elem_j = &self.elems[j];
                    elem_i.criterion(elem_j)
                };

                if dist_sq < cutoff {
                    // Lock only the specific vectors we need to modify
                    // This allows high concurrency as locks are fine-grained and short-lived
                    nb_guards[i].lock().unwrap().push(j);
                    nb_guards[j].lock().unwrap().push(i);
                }
            }
        });

        // Move the results back into the original struct
        for (i, elem) in self.elems.iter_mut().enumerate() {
            let mut guard = nb_guards[i].lock().unwrap();
            std::mem::swap(&mut elem.nb, &mut guard);
        }
    }
}

