            B::new(0.5, 0.5, 0.5),
            B::new(10.0, 10.0, 10.0), // Far away
            B::new(0.1, 0.1, 0.1),
        ],
        2.0, // cutoff squared roughly
    );

    println!("Initial state: {:?}", system.elems.iter().map(|b| b.r.clone()).collect::<Vec<_>>());

    // Run Safe Sequential Version
    system.build_lists_safe();
    println!("\nAfter Safe Sequential Build:");
    for (i, elem) in system.elems.iter().enumerate() {
        println!("Element {}: neighbors = {:?}", i, elem.nb);
    }

