/// Returns distance to hit, or None if no hit
fn ray_aabb_intersect(origin: Vec3, dir: Vec3, min: Vec3, max: Vec3) -> Option<f32> {
    let mut t_min = 0.0;
    let mut t_max = f32::INFINITY;

    for i in 0..3 {
        if dir[i].abs() < 1e-6 {
            if origin[i] < min[i] || origin[i] > max[i] {
                return None;
            }
        } else {
            let t1 = (min[i] - origin[i]) / dir[i];
            let t2 = (max[i] - origin[i]) / dir[i];
            let t_near = t1.min(t2);
            let t_far = t1.max(t2);

            t_min = t_min.max(t_near);
            t_max = t_max.min(t_far);

            if t_min > t_max {
                return None;
            }
        }
    }

    if t_max < 0.0 {
        return None;
    }

    Some(if t_min < 0.0 { t_max } else { t_min })
}

/// Creates a Quaternion that rotates `from` to `to`, while trying to keep `reference` aligned with the resulting plane.
/// This is essentially a custom look_at.
fn Quat::from_rotation_arc_align(from: Vec3, to: Vec3, reference: Vec3) -> Quat {
    let rotation = Quat::from_rotation_arc(from, to);

    // Apply the rotation to a temporary up vector to see where it ends up
    let rotated_reference = rotation * reference;

    // We now have a rotation that points `from` to `to`, but it might have spun around `to`.
    // We need to correct the rotation around the `to` axis so that `rotated_reference` 
    // lies in the same plane as the original `reference` and `to`? 
    // Actually, simpler approach: Construct basis vectors directly.

    let z_axis = to.normalize();

    // Calculate X axis: Cross product of reference and Z. 
    // If reference is parallel to Z, this fails, handled by caller picking good reference.
    let mut x_axis = reference.cross(z_axis);
    if x_axis.length_squared() < 1e-6 {
        // Fallback if reference was parallel despite check (safety)
        x_axis = Vec3::X.cross(z_axis);
        if x_axis.length_squared() < 1e-6 {
            x_axis = Vec3::Y.cross(z_axis);
        }
    }
    x_axis = x_axis.normalize();

    let y_axis = z_axis.cross(x_axis);

    Quat::from_mat3(&Mat3::from_cols(x_axis, y_axis, z_axis))
}

