    /// 2. Create a SINGLE builder on the main thread.
    /// 3. Feed the pre-processed data into the builder sequentially.
    ///    (Creating strings/vectors in the builder is extremely fast, so this
    ///     sequential step is rarely the bottleneck).
    pub fn serialize_to_flatbuffer(&self) -> Vec<u8> {
        // ---------------------------------------------------------
        // STEP 1: Parallel Data Preparation (No Builder involved)
        // ---------------------------------------------------------
        // We process the raw data in parallel. This is where rayon shines.
        // We convert our internal types into simple Strings or byte vectors
        // that are owned and safe to move.

        let prepared_strings: Vec<String> = if let Some(fm) = &self.front_matter {
            fm.ignored_parsers
                .par_iter() // Parallel iteration
                .map(|s| {
                    // Perform heavy lifting here if needed (e.g., parsing, transformation)
                    // We just clone/prepare the string here.
                    s.clone() 
                })
                .collect()
        } else {
            Vec::new()
        };

        // Prepare content similarly if it needed heavy processing
        let prepared_content = self.content.clone();

        // ---------------------------------------------------------
        // STEP 2: Sequential Buffer Construction (Single Thread)
        // ---------------------------------------------------------
        // Now we create the builder. This struct manages the memory buffer.
        // It must be mutable, but only on one thread.
        let mut builder = FlatBufferBuilder::new();

        // Create strings in the buffer from our prepared data.
        // This loop is fast because it's mostly memory copying into the pre-allocated buffer.
        let mut string_offsets: Vec<WIPOffset<&str>> = Vec::with_capacity(prepared_strings.len());

        for s in prepared_strings {
            let offset = builder.create_string(&s);
            string_offsets.push(offset);
        }

        // Create the vector of strings in the buffer
        let front_matter_vector = if !string_offsets.is_empty() {
            Some(builder.create_vector(&string_offsets))
        } else {
            None
        };

        // Create the main content string
        let content_offset = builder.create_string(&prepared_content);

        // ---------------------------------------------------------
        // STEP 3: Finalize the Root Object
        // ---------------------------------------------------------
        let root_args = MdxParsingResultBufferArgs {
            parsed_content: Some(content_offset),
            front_matter: front_matter_vector,
            ..Default::default()
        };

        let root_offset = MdxParsingResultBuffer::create(&mut builder, &root_args);
        builder.finish(root_offset, None);

        // Extract the finished bytes
        builder.finished_data().to_vec()
    }
}

fn main() {
