            impl<T, E: std::error::Error + 'static> LogChangeErrForRespExt for Result<T, E> {
                type R = Result<T, FrameworkError>;

                #[track_caller]
                fn log_and_explain_400(self) -> Self::R {
                    match self {
                        Ok(ok) => Ok(ok),
                        Err(err) => {
                            let loc = std::panic::Location::caller();

                            // We emit a special prefix that our custom logger will detect
                            // Format: "CALLER_LOC:<file>:<line>:<original_msg>"
                            log::log!(
                                Level::Warn,
                                "CALLER_LOC:{}:{}: Error: {:?}",
                                loc.file(),
                                loc.line(),
                                err
                            );

                            Err(FrameworkError::Error400(Box::new(err)))
                        }
                    }
                }
            }
        }
    }
}
