// A dummy token for demonstration
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct Token(char);

impl fmt::Display for Token {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.0)
    }
}

/// The core trait. 
/// NOTE: We removed the lifetime `'src` from the trait definition itself.
/// Instead, we make the associated types and methods generic over `'src`.
/// This allows the compiler to infer a new, short lifetime for each call site
/// based on the borrow of the input, rather than being forced to use a 
/// pre-defined `'src` that might outlive the local variable.
pub trait BaseParser {
    // The associated type is now generic over 'src
    type InputToken<'src>: PartialEq + fmt::Display + Clone + 'src;

    // The Input type is also generic over 'src
    type Input<'src>: chumsky::input::Input<'src, Token = Self::InputToken<'src>, Span = SimpleSpan>;

    type Output;

    // The parser method is generic over 'src
    fn parser<'src>() -> impl chumsky::prelude::Parser<
        'src,
        Self::Input<'src>,
        Self::Output,
        extra::Err<Rich<'src, Self::InputToken<'src>, SimpleSpan>>,
    >;

    /// Perform the parsing within this layer.
    /// This method is now generic over 'src, allowing it to accept borrows
    /// that only live as long as the function call.
    fn parse_this<'src>(input: Self::Input<'src>) -> Result<Self::Output, Vec<String>> 
    where
        Self::Input<'src>: 'src,
    {
        Self::parser().parse(input).into_result().map_err(|errors| {
            errors
                .into_iter()
                .map(|e| e.to_string())
                .collect::<Vec<_>>()
        })
    }
}

/// The slice parser trait.
/// NOTE: We removed the lifetime `'src` from the trait definition here as well.
/// Previously, `BaseSliceParser<'src>` forced all implementors and methods 
/// to adhere to that specific lifetime parameter. By removing it, 
/// `parse_this_owned` can define its own internal lifetime scope.
pub trait BaseSliceParser: BaseParser {
    // This method now creates its own lifetime scope internally.
    // It takes ownership of a Vec, creates a slice (which has a short lifetime),
    // and passes it to parse_this. Since parse_this is also generic, 
    // it accepts this short lifetime.
    fn parse_this_owned(input: Vec<Self::InputToken<'_>>) -> Result<Self::Output, Vec<String>> {
        // The lifetime of the slice derived from `input` is inferred here.
        // It does not need to match any external trait lifetime parameter.
        Self::parse_this(input.as_slice())
    }
}

