/// 2. `Cow::Borrowed(&str)` usually comes from static strings or temporary lookups.
///    If we convert these to `String` once during construction, we pay the allocation
///    cost only once. The struct then owns its data completely.
/// 3. This eliminates the lifetime parameter `'a` entirely, making the struct
///    much easier to use (no lifetime errors when putting it in HashMaps, Vecs, etc).
#[derive(Debug, Clone)]
pub struct ResourceRef<R: Resource>
where
    R::DynamicType: Default,
