            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    // We can still return &str efficiently. 
    // The struct owns the String, so we just lend a reference to it.
    // The lifetime of this reference is tied to &self, which is safe.
    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

