    let mut map: std::collections::HashMap<String, ResourceRef<MyResource>> = std::collections::HashMap::new();
    map.insert(resource_ref.name().to_string(), resource_ref.clone());

    println!("Successfully stored in HashMap!");
    println!("Retrieved: {:?}", map.get("my_resource_name"));
