        return;
    }
    if let Some(v) = value_mut.downcast_mut::<bool>() {
        bool_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<NamedTypeValue>() {
        namedvalue_property(ui, title, v, interactable);
        return;
    }
    if let Some(v) = value_mut.downcast_mut::<ArgumentNamedValue>() {
        argnamedvalue_property(ui, title, v, interactable);
        return;
    }

    // 2. Try Generic Containers (Vec and Option) without explicit type enumeration

    // Check for Vec<T>
    // We attempt to downcast to a helper wrapper or use a macro, but since we have &mut dyn Any,
    // we can't directly iterate types. 
    // STRATEGY: We maintain a registry of known "Inner Types" that our app supports in Lists/Options.
    // If the value is a Vec<T>, we try to downcast to Vec<KnownType> for all KnownTypes.
    // To avoid code duplication, we use a macro to generate the checks.

    macro_rules! try_container_downcast {
        ($value:expr, $ui:expr, $title:expr, $interactable:expr, $($t:ty),*) => {
            $(
                // Check Vec<T>
                if let Some(v) = $value.downcast_mut::<Vec<$t>>() {
                    list_property::<$t>($ui, $title, v, $interactable);
                    return;
                }
                // Check Option<T>
                if let Some(v) = $value.downcast_mut::<Option<$t>>() {
                    option_property::<$t>($ui, $title, v, $interactable);
                    return;
                }
            )*
        };
    }

    // List all types that might appear inside Vec<> or Option<> here.
    // This is the ONLY place you need to add a new type to support it in containers.
    try_container_downcast!(
        value_mut, ui, title, interactable,
        String, i32, f32, bool, usize, 
        DataType, ValueType, NamedTypeValue, ArgumentNamedValue
    );

    // Fallback
    ui.label(egui::RichText::new(format!("Field {}: unknown type", title)).color(egui::Color32::LIGHT_RED));
}

// --- App Implementation ---

struct MyApp {
    // A heterogeneous list of properties to demonstrate the downcaster
    properties: Vec<Box<dyn Any + 'static>>,
}

impl MyApp {
    fn new() -> Self {
        let mut properties: Vec<Box<dyn Any + 'static>> = Vec::new();

        // Primitives
        properties.push(Box::new(String::from("Hello World")));
        properties.push(Box::new(42i32));
        properties.push(Box::new(3.14f32));
        properties.push(Box::new(true));
        properties.push(Box::new(100usize));

        // Structs
        properties.push(Box::new(NamedTypeValue::default()));
        properties.push(Box::new(ArgumentNamedValue::default()));

        // Vec<T>
        properties.push(Box::new(vec![String::from("Item 1"), String::from("Item 2")]));
        properties.push(Box::new(vec![1i32, 2, 3]));
        properties.push(Box::new(vec![DataType::default(), DataType::default()]));

        // Option<T>
        properties.push(Box::new(Some(String::from("Optional String"))));
        properties.push(Box::new(None as Option<i32>));
        properties.push(Box::new(Some(DataType::default())));

        Self { properties }
    }
}

impl eframe::App for MyApp {
    fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) {
        egui::SidePanel::left("properties_panel").show(ctx, |ui| {
            ui.heading("Property Editor");
            ui.separator();

            egui::ScrollArea::vertical().show(ui, |ui| {
                for i in 0..self.properties.len() {
                    ui.group(|ui| {
                        // We pass the box content as &mut dyn Any
                        let title = format!("Property #{}", i + 1);
                        if let Some(any_val) = self.properties.get_mut(i) {
                            downcast_property(ui, &title, any_val.as_mut(), true);
                        }
                    });
                    ui.add_space(5.0);
                }
            });
        });
    }
}

fn main() -> eframe::Result<()> {
    let native_options = eframe::NativeOptions {
        viewport: egui::ViewportBuilder::default()
            .with_inner_size([400.0, 300.0])
            .with_min_inner_size([300.0, 200.0]),
        ..Default::default()
    };
    eframe::run_native(
        "Rust Downcast Demo",
        native_options,
        Box::new(|_cc| Ok(Box::new(MyApp::new()))),
    )
}"
}

