// Since standard RNGs are not const-fn in stable Rust yet, we implement a simple,
// deterministic PRNG (PCG32) manually as a const fn to generate the table at compile time.
// This ensures the values are identical every build without runtime cost.

const fn pcg32_random(seed: u64) -> u32 {
    // PCG32 State initialization logic simplified for const context
    // We use a linear congruential generator step followed by output function
    let mut state = seed.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
    state = state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);

    let xorshifted = (((state >> 18) ^ state) >> 27) as u32;
    let rot = (state >> 59) as u32;
