        }
        Ok((pos, vec![]))
    }
}
impl Hinter for ReplHelper {
    type Hint = String;
}
impl Validator for ReplHelper {}
impl Highlighter for ReplHelper {}

/// Raw terminal mode guard to handle mixing rustyline and child output
struct RawModeGuard {
    original_termios: Option<termios>,
    fd: c_int,
    was_raw: bool,
}

impl RawModeGuard {
    fn new() -> io::Result<Self> {
        let fd = libc::STDIN_FILENO;
        let mut original_termios: termios = unsafe { std::mem::zeroed() };
        if unsafe { tcgetattr(fd, &mut original_termios) } != 0 {
            return Err(io::Error::last_os_error());
        }
        Ok(Self {
            original_termios: Some(original_termios),
            fd,
            was_raw: false,
        })
    }

    fn enter_raw_mode(&mut self) -> io::Result<()> {
        if self.was_raw {
            return Ok(());
        }
        let mut raw = self.original_termios.as_ref().unwrap().clone();
        // Disable canonical mode and echo
        raw.c_lflag &= !(ECHO | ICANON);
        raw.c_cc[VMIN as usize] = 0;
        raw.c_cc[VTIME as usize] = 1; // 0.1 second timeout

        if unsafe { tcsetattr(self.fd, TCSANOW, &raw) } != 0 {
            return Err(io::Error::last_os_error());
        }
        self.was_raw = true;
        Ok(())
    }

    fn restore(&mut self) {
        if let Some(orig) = &self.original_termios {
            unsafe { tcsetattr(self.fd, TCSANOW, orig) };
        }
        self.was_raw = false;
    }
}

impl Drop for RawModeGuard {
    fn drop(&mut self) {
        self.restore();
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Spawn child process (e.g., python, bash, or a dummy script)
    // Here we use `python3 -i` as an example interactive REPL. 
    // Ensure python3 is installed or replace with another command like "bc", "node", etc.
    let mut child = Command::new("python3")
        .arg("-i")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    let mut child_stdin = child.stdin.take().expect("Failed to open stdin");
    let child_stdout = child.stdout.take().expect("Failed to open stdout");
    let child_stderr = child.stderr.take().expect("Failed to open stderr");

    let (tx, rx): (Sender<String>, Receiver<String>) = bounded(100);
    let running = Arc::new(AtomicBool::new(true));
    let running_clone = running.clone();

    // Thread to read child stdout/stderr
    let handle_stdout = thread::spawn(move || {
        let mut buf = [0u8; 1024];
        let mut stdout = child_stdout;
        let mut stderr = child_stderr;

        // Simple non-blocking read simulation via threads sleeping is hard without async.
        // Instead, we'll use blocking reads in separate threads and send to channel.
        // Since we can't easily multiplex sync reads, we spawn two threads.
    });

    // Better approach: One thread for stdout, one for stderr
    let tx_out = tx.clone();
    let run_out = running.clone();
    thread::spawn(move || {
        let mut buf = [0u8; 1024];
        let mut stdout = child_stdout;
        while run_out.load(Ordering::Relaxed) {
            // Set non-blocking is tricky with std::io::Read on pipes without async.
            // We rely on the fact that python -i buffers. 
            // For a robust solution, one would use `nix` crate to set O_NONBLOCK.
            // For this self-contained example, we assume data arrives.
            match stdout.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    let text = String::from_utf8_lossy(&buf[..n]);
                    let _ = tx_out.send(text.to_string());
                }
                Err(_) => {
                    thread::sleep(Duration::from_millis(10));
                }
            }
        }
    });

    let tx_err = tx.clone();
    let run_err = running.clone();
    thread::spawn(move || {
        let mut buf = [0u8; 1024];
        let mut stderr = child_stderr;
        while run_err.load(Ordering::Relaxed) {
            match stderr.read(&mut buf) {
                Ok(0) => break,
                Ok(n) => {
                    let text = String::from_utf8_lossy(&buf[..n]);
                    let _ = tx_err.send(text.to_string());
                }
                Err(_) => {
                    thread::sleep(Duration::from_millis(10));
                }
            }
        }
    });

    let config = Config::builder()
        .auto_add_history(true)
        .build();

    let mut rl: Editor<ReplHelper, _> = Editor::with_config(config)?;
    rl.set_helper(Some(ReplHelper));

    let mut raw_guard = RawModeGuard::new()?;
    let mut input_buffer = String::new();
    let mut prompt_displayed = false;

    println!("Hosting child REPL. Type commands. Ctrl+C to exit.");

    // Initial prompt
    print!("> ");
    io::stdout().flush()?;
    prompt_displayed = true;

    // We need to interleave reading from STDIN (user) and the Channel (child output)
    // Since rustyline's readline is blocking and manages terminal state, we cannot use it directly in a select loop easily.
    // Strategy: Manually handle input character-by-character when in raw mode, 
    // and only invoke rustyline features (like history/completion) minimally or simulate them.
    // HOWEVER, the prompt specifically asked for rustyline. 
    // The fundamental conflict: Rustyline takes full control of TTY. 
    // Solution: Use rustyline for the "host" commands, and pass through raw input to child when in "proxy" mode?
    // OR: Implement the loop manually using raw mode to allow interleaving, using rustyline only for completion logic if needed.

    // Given the constraints and the specific problem description (blocking readline), 
    // the most robust way to host *another* REPL with live output is to NOT use rustyline's `readline` loop,
    // but rather implement a custom loop that uses rustyline's *completion engine* manually, 
    // while handling I/O via raw terminal states.

    // Let's implement a hybrid: 
    // 1. Check for child output constantly.
    // 2. Read user input in non-blocking raw mode.
    // 3. Use rustyline's completer only when Tab is pressed.

    raw_guard.enter_raw_mode()?;

    let stdin = io::stdin();
    let mut stdin_handle = stdin.lock();
    let mut stdout = io::stdout();

    // Reset buffer for manual handling
    input_buffer.clear();
    if prompt_displayed {
        // We already printed >, but in raw mode we manage cursor
    }

    while running.load(Ordering::Relaxed) {
        // 1. Check Child Output
        while let Ok(line) = rx.try_recv() {
            // If we are in the middle of typing, we need to save cursor, print output, restore cursor
            if !input_buffer.is_empty() || prompt_displayed {
                // Move cursor to beginning of line, clear to end, print output, newline, reprint prompt + buffer
                print!("\r\033[K{}", line); // \033[K clears to end of line
                if !input_buffer.is_empty() {
                    println!("\r> {}", input_buffer);
                } else {
                    print!("\r> ");
                }
                stdout.flush()?;
            } else {
                print!("{}", line);
                stdout.flush()?;
            }
        }

        // 2. Read User Input (Non-blocking)
        let mut buf = [0u8; 1];
        // Setup select or just poll? Polling is simpler for this self-contained example
        // We need to check if data is available. 
        // Without external crates like `polling` or `mio`, we rely on the VTIME setting in termios.
        // VTIME=1 means read returns after 0.1s if no data.

        match stdin_handle.read(&mut buf) {
            Ok(0) => {
                // EOF
                running.store(false, Ordering::Relaxed);
                break;
            }
            Ok(_) => {
                let c = buf[0] as char;
                match c {
                    '\n' | '\r' => {
                        println!();
                        // Send to child
                        writeln!(child_stdin, "{}", input_buffer)?;
                        child_stdin.flush()?;
                        input_buffer.clear();
                        print!("> ");
                        stdout.flush()?;
                    }
                    '\x03' => { // Ctrl+C
                        println!("^C");
                        running.store(false, Ordering::Relaxed);
                        break;
                    }
                    '\x08' | '\x7f' => { // Backspace
                        if !input_buffer.is_empty() {
                            input_buffer.pop();
                            print!("\r\033[K> {}", input_buffer);
                            stdout.flush()?;
                        }
                    }
                    '\t' => { // Tab Completion
                        let helper = ReplHelper;
                        if let Ok((pos, candidates)) = helper.complete(&input_buffer, input_buffer.len(), &rustyline::Context::new()) {
                            if !candidates.is_empty() {
                                // Simple replacement with first candidate for demo
                                let replacement = &candidates[0].replacement;
                                input_buffer = replacement.clone();
                                print!("\r\033[K> {}", input_buffer);
                                stdout.flush()?;
                            }
                        }
                    }
                    _ => {
                        input_buffer.push(c);
                        print!("{}", c);
                        stdout.flush()?;
                    }
                }
            }
            Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                // No input available, loop continues to check child output
                thread::sleep(Duration::from_millis(10));
            }
            Err(_) => {
                // Other errors
                thread::sleep(Duration::from_millis(10));
            }
        }
    }

    running.store(false, Ordering::Relaxed);
    // Ensure child is cleaned up
    let _ = child.wait();

    // Restore terminal
    drop(raw_guard);

    println!("Exited child REPL.");
    Ok(())
}"
}

