  "main.rs": "use serde::de::{self, Deserialize, Deserializer, MapAccess, SeqAccess, Visitor};
use serde::ser::{Serialize, SerializeStruct, Serializer};
use std::fmt;

// --- Data Structures ---

#[derive(Debug, Clone)]
enum B {
    VariantOne(String),
    VariantTwo(i32),
}

#[derive(Debug, Clone, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

// --- Custom Serializer/Deserializer for Enum B ---

impl Serialize for B {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        match self {
            B::VariantOne(s) => {
                let mut state = serializer.serialize_struct("VariantOne", 1)?;
                state.serialize_field("type", "one")?;
                state.serialize_field("value", s)?;
                state.end()
            }
            B::VariantTwo(i) => {
                let mut state = serializer.serialize_struct("VariantTwo", 1)?;
                state.serialize_field("type", "two")?;
                state.serialize_field("value", i)?;
                state.end()
            }
        }
    }
}

struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a map representing enum B")
    }

    fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut type_val: Option<String> = None;
        let mut value_val: Option<serde_json::Value> = None; // Using Value for flexibility in demo

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "type" => {
                    if type_val.is_some() {
                        return Err(de::Error::duplicate_field("type"));
                    }
                    type_val = Some(map.next_value()?);
                }
                "value" => {
                    if value_val.is_some() {
                        return Err(de::Error::duplicate_field("value"));
                    }
                    // We deserialize to a generic Value first to handle string vs int dynamically
                    value_val = Some(map.next_value()?);
                }
                _ => {
                    // Ignore unknown fields or return error
                    let _: serde_json::Value = map.next_value()?;
                }
            }
        }

        let t = type_val.ok_or_else(|| de::Error::missing_field("type"))?;
        let v = value_val.ok_or_else(|| de::Error::missing_field("value"))?;

        match t.as_str() {
            "one" => {
                let s = v.as_str().ok_or_else(|| de::Error::custom("Expected string for variant one"))?;
                Ok(B::VariantOne(s.to_string()))
            }
            "two" => {
                let i = v.as_i64().ok_or_else(|| de::Error::custom("Expected integer for variant two"))? as i32;
                Ok(B::VariantTwo(i))
            }
            _ => Err(de::Error::unknown_variant(&t, &["one", "two"])),
        }
    }
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(BVisitor)
    }
}

// --- Custom Serializer/Deserializer for Struct A ---

impl Serialize for A {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        let mut state = serializer.serialize_struct("A", 2)?;
        state.serialize_field("x", &self.x)?;
        state.serialize_field("b", &self.b)?; // Relies on B's custom Serialize
        state.end()
    }
}

struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a map representing struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut val = A::default();
        let mut x_found = false;
        let mut b_found = false;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => {
                    if x_found {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    val.x = map.next_value()?;
                    x_found = true;
                }
                "b" => {
                    if b_found {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    // This is the crucial part: Delegate deserialization of Vec<B> to serde.
                    // Since B implements Deserialize, serde knows how to handle Vec<B>
                    // by calling B::deserialize for each element.
                    val.b = map.next_value()?;
                    b_found = true;
                }
                _ => {
                    // Skip unknown fields
                    let _: serde_json::Value = map.next_value()?;
                }
            }
        }

        if !x_found {
            return Err(de::Error::missing_field("x"));
        }
        if !b_found {
            return Err(de::Error::missing_field("b"));
        }

        Ok(val)
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    // Create an instance of A with nested B enums
    let original_a = A {
        x: 42,
        b: vec![
            B::VariantOne("Hello".to_string()),
            B::VariantTwo(123),
            B::VariantOne("World".to_string()),
        ],
    };

    println!("Original Structure: {:?}", original_a);

    // Serialize to JSON string
    let json_string = serde_json::to_string_pretty(&original_a).expect("Failed to serialize");
    println!("\nSerialized JSON:\n{}", json_string);

    // Deserialize back from JSON string
    let deserialized_a: A = serde_json::from_str(&json_string).expect("Failed to deserialize");
    println!("\nDeserialized Structure: {:?}", deserialized_a);

    // Verify round-trip
    assert_eq!(original_a.x, deserialized_a.x);
    assert_eq!(original_a.b.len(), deserialized_a.b.len());

    println!("\nSuccess! Nested custom (de)serialization works correctly.");
}"
}

