                            return Err(serde::de::Error::custom("Invalid $ref format. Expected 'file#path'"));
                        }

                        let file_path = parts[0];
                        let json_pointer = parts[1];

                        // Read the referenced file
                        let content = fs::read_to_string(file_path)
                            .map_err(|e| serde::de::Error::custom(format!("Failed to read referenced file {}: {}", file_path, e)))?;

                        // Parse the referenced file content
                        let root_value: Value = serde_json::from_str(&content)
                            .map_err(|e| serde::de::Error::custom(format!("Failed to parse referenced file: {}", e)))?;

                        // Resolve the JSON pointer (simple implementation for /key)
                        let target_value = resolve_json_pointer(&root_value, json_pointer)
                            .ok_or_else(|| serde::de::Error::custom(format!("JSON pointer '{}' not found in {}", json_pointer, file_path)))?;

                        // Deserialize the target value into Vec<PathBuf>
                        let paths: Vec<PathBuf> = from_value(target_value.clone())
                            .map_err(|e| serde::de::Error::custom(format!("Failed to deserialize referenced data: {}", e)))?;

                        Ok(PathListWrapper { paths })
                    } else {
                        Err(serde::de::Error::custom("$ref value must be a string"))
                    }
                } else {
                    Err(serde::de::Error::custom("Object contains no $ref key and is not an array"))
                }
            }
            _ => Err(serde::de::Error::custom("Expected an array or an object with $ref")),
        }
    }
}

// Helper to resolve a simple JSON pointer like "/p_list"
fn resolve_json_pointer(value: &Value, pointer: &str) -> Option<&Value> {
    if pointer.is_empty() {
        return Some(value);
    }

    if !pointer.starts_with('/') {
        return None;
    }

    let mut current = value;
    for part in pointer.split('/').skip(1) {
        // Simple unescaping could be added here if needed for ~ or /
        match current {
            Value::Object(map) => {
                if let Some(next) = map.get(part) {
                    current = next;
                } else {
                    return None;
                }
            }
            _ => return None,
        }
    }
    Some(current)
}

