  "main.rs": "use anyhow::Result;
use expectrl::{session::Session, spawn, Eof, Needle, Retry};
use std::{
    io::{Read, Write},
    sync::Arc,
    time::Duration,
};
use tokio::sync::{mpsc, Mutex};

/// This example demonstrates the correct pattern for full-duplex PTY interaction.
/// 
/// PROBLEM SOLVED:
/// The original issue was holding a Mutex guard while performing a blocking `read()`,
/// which prevented the `send` function from acquiring the lock to write.
/// 
/// SOLUTION:
/// 1. Single Owner Pattern: Only ONE thread (the Reader/Controller) holds the Session.
/// 2. Command Channel: Write requests are sent via an `mpsc` channel to the owner thread.
/// 3. Non-Blocking Polling: We use `session.expect()` with a short timeout. This allows
///    the loop to wake up periodically to check for incoming write commands, even if
///    the subprocess isn't producing output.

#[tokio::main]
async fn main() -> Result<()> {
    println!("Starting Interactive PTY Demo...");
    println!("Spawning '/bin/bash' (try typing 'vim' or 'cat' to test TUI freezing)...");
    println!("Type commands below. Type 'quit' to exit.");

    // 1. Spawn the PTY Session
    // We use expectrl to spawn a shell. 
    let mut session = spawn("/bin/bash").expect("Failed to spawn shell");

    // Configure the session for better interactivity if needed
    // session.set_raw_mode(true)?; // Often handled by expectrl defaults or terminal emulation

    // 2. Create a channel for sending commands TO the PTY owner thread
    // This decouples the input source (user/tauri) from the PTY lock.
    let (tx, mut rx) = mpsc::channel::<String>(32);

    // 3. Wrap the channel sender in an Arc so we can clone it for the input thread
    let input_tx = Arc::new(tx);

    // --- THREAD 1: INPUT FORWARDEr (Simulates Tauri Command / xterm.js keypress) ---
    // In Tauri, this logic lives inside your `send_to_agent` command, 
    // but instead of locking the session, it just sends to this channel.
    let input_handle = tokio::task::spawn_blocking(move || {
        let mut line = String::new();
        loop {
            line.clear();
            // Read from stdin (simulating frontend input)
            match std::io::stdin().read_line(&mut line) {
                Ok(0) => break, // EOF
                Ok(_) => {
                    let tx = Arc::clone(&input_tx);
                    // Send the data to the PTY owner. This is non-blocking relative to the PTY lock.
                    // If the channel is full, this awaits, but it doesn't block PTY reading.
                    if line.trim() == "quit" {
                        println!("Exiting...");
                        break;
                    }

                    // In a real async app, use tx.send().await. 
                    // In spawn_blocking, we must block or use a runtime handle.
                    // For this simple demo, we create a small runtime to send or use blocking_send.
                    let _ = tx.blocking_send(line.clone());
                }
                Err(e) => {
                    eprintln!("Input error: {}", e);
                    break;
                }
            }
        }
    });

    // --- THREAD 2: PTY CONTROLLER (The Single Owner) ---
    // This loop owns the `session`. It handles both Reading output AND Writing input.
    // Because it owns the session, no Mutex is needed for the session itself.

    let mut buffer = [0u8; 1024];

    loop {
        // STRATEGY: Use `expect` with a short timeout.
        // This acts as a non-blocking read poll. 
        // It waits for output OR until the timeout expires.
        // When it times out, we get a chance to check the `rx` channel for pending writes.

        let read_result = session
            .expect(Eof | Retry::timeout(Duration::from_millis(100)))
            .try_into();

        match read_result {
            Ok((_, capture)) => {
                // 1. Handle Output from PTY
                if let Some(matched) = capture.get(0) {
                    let output = matched.as_bytes();
                    if !output.is_empty() {
                        print!("{}", String::from_utf8_lossy(output));
                        // Flush stdout to ensure immediate display (like forwarding to xterm.js)
                        std::io::stdout().flush().ok();
                    }
                }
            }
            Err(e) => {
                // Expect returns an error on timeout, which is expected behavior for our poll
                if e.to_string().contains("timeout") {
                    // Timeout occurred. No output ready. 
                    // This is our window to process pending writes without blocking.
                } else {
                    // Real error or EOF
                    eprintln!("\nPTY Error or EOF: {}", e);
                    break;
                }
            }
        }

        // 2. Handle Pending Writes (Non-Blocking Check)
        // Try to receive a message. If none available, try_next returns None immediately.
        // We use `try_recv` inside a loop to drain the channel if multiple keys were pressed quickly.
        while let Ok(cmd) = rx.try_recv() {
            // Write to the PTY. Since we own the session here, no mutex lock is needed.
            if let Err(e) = session.send(&cmd) {
                eprintln!("Failed to send to PTY: {}", e);
                break;
            }
            // Note: `session.send` writes to the master FD. 
            // For line-based input, the user usually sends \n which is already in `cmd`.
        }
    }

    // Cleanup
    let _ = input_handle.await;
    println!("\nSession ended.");
    Ok(())
}"
}

