  "main.rs": "use async_trait::async_trait;
use opentelemetry::{global, trace::TraceContextExt, Context, KeyValue};
use opentelemetry_sdk::{trace::TracerProvider, runtime};
use std::time::Duration;
use tokio::time::sleep;
use tracing::{Instrument, Span, info, instrument};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, Registry};

/// Simulates the common context shared across Pingora lifecycle stages.
/// In a real scenario, this would hold connection info, headers, etc.
#[derive(Clone)]
pub struct RequestContext {
    pub request_id: String,
    // We store the OpenTelemetry Context here to "rehydrate" the span later
    otel_context: Option<Context>,
}

impl RequestContext {
    pub fn new(request_id: String) -> Self {
        Self {
            request_id,
            otel_context: None,
        }
    }

    /// Captures the current OpenTelemetry context associated with the active span.
    /// This should be called once at the very beginning of the request lifecycle.
    pub fn capture_span(&mut self) {
        // Get the current context which holds the active span
        let ctx = Context::current();
        self.otel_context = Some(ctx);
        info!(request_id = %self.request_id, "Context captured with active span");
    }

    /// Re-attaches the stored OpenTelemetry context to the current thread.
    /// This makes the original parent span active again, even if we are on a different
    /// thread or deep inside an async call stack.
    pub fn attach_span_guard(&self) -> impl Drop {
        if let Some(ctx) = &self.otel_context {
            // `attach` returns a guard that restores the previous context when dropped
            ctx.attach()
        } else {
            // If no context was captured, attach an empty one to avoid panics,
            // though logically this means no parent relationship will be formed.
            Context::current().attach()
        }
    }
}

/// Simulates the Pingora ProxyHttp trait stages
#[async_trait]
trait ProxyStage {
    async fn on_request_start(&self, ctx: &mut RequestContext);
    async fn on_upstream_selection(&self, ctx: &mut RequestContext);
    async fn on_response(&self, ctx: &mut RequestContext);
}

struct MyProxy;

#[async_trait]
impl ProxyStage for MyProxy {
    // Stage 1: Often called immediately, but might be on a different task in real proxy
    #[instrument(name = "stage_request_start", skip(self, ctx), fields(request_id = %ctx.request_id))]
    async fn on_request_start(&self, ctx: &mut RequestContext) {
        info!("Processing request start");
        sleep(Duration::from_millis(50)).await;

        // IMPORTANT: If the framework calls subsequent stages asynchronously 
        // without awaiting here, we must ensure the context is passed.
        // In this demo, we explicitly capture the context after creating this span
        // so subsequent calls can rehydrate it.
        ctx.capture_span();
    }

    // Stage 2: Simulates a callback happening later or on a different thread pool
    #[instrument(name = "stage_upstream_selection", skip(self, ctx), fields(request_id = %ctx.request_id))]
    async fn on_upstream_selection(&self, ctx: &mut RequestContext) {
        // REHYDRATION STEP:
        // Before doing any work, we attach the stored context.
        // This ensures the span created by `#[instrument]` below becomes a child
        // of the original request span, not a new root.
        let _guard = ctx.attach_span_guard();

        info!("Selecting upstream (Context Rehydrated)");
        sleep(Duration::from_millis(70)).await;

        // Simulate an internal upstream call
        perform_upstream_request(ctx).await;
    }

    // Stage 3: Final response
    #[instrument(name = "stage_response", skip(self, ctx), fields(request_id = %ctx.request_id))]
    async fn on_response(&self, ctx: &mut RequestContext) {
        let _guard = ctx.attach_span_guard();
        info!("Sending response");
        sleep(Duration::from_millis(30)).await;
    }
}

// A helper function to simulate deep nesting or external library calls
#[instrument(name = "upstream_network_call", skip(ctx))]
async fn perform_upstream_request(ctx: &RequestContext) {
    // Because we rehydrated the context in the caller, this function
    // automatically picks up the correct parent span hierarchy.
    info!("Performing actual network I/O to upstream");
    sleep(Duration::from_millis(40)).await;
}

#[tokio::main]
async fn main() {
    // 1. Setup OpenTelemetry Tracer (stdout for demo)
    let tracer_provider = TracerProvider::builder()
        .with_simple_exporter(opentelemetry_stdout::SpanExporter::default())
        .build();
    let tracer = tracer_provider.tracer("pingora-demo");
    global::set_tracer_provider(tracer_provider);

    // 2. Setup Tracing Subscriber with OpenTelemetry Layer
    let telemetry = tracing_opentelemetry::layer().with_tracer(tracer);
    let fmt_layer = tracing_subscriber::fmt::layer().json();

    let subscriber = Registry::default()
        .with(telemetry)
        .with(fmt_layer)
        .with(tracing_subscriber::EnvFilter::try_from_default_env()
            .unwrap_or_else(|_| "info,pingora_tracing_rehydrate=debug".into()));

    tracing::subscriber::set_global_default(subscriber)
        .expect("Failed to set subscriber");

    info!("Starting Pingora-like simulation");

    // Simulate the Request Lifecycle
    let mut ctx = RequestContext::new("req-12345".to_string());
    let proxy = MyProxy;

    // Create the Root Span for the entire request
    // In Pingora, this might wrap the entire connection handling
    let root_span = tracing::span!(tracing::Level::INFO, "request_lifecycle", request_id = %ctx.request_id);

    // Execute the lifecycle within the root span
    async {
        info!("Entering request lifecycle");

        // Stage 1
        proxy.on_request_start(&mut ctx).await;

        // Simulate Framework yielding control, switching threads, or 
        // invoking a callback later (the core problem scenario)
        info!("Framework yielding control / simulating thread switch...");
        sleep(Duration::from_millis(100)).await;

        // Stage 2 (Called back later)
        // Without rehydration, this would appear as a separate trace root
        proxy.on_upstream_selection(&mut ctx).await;

        // Stage 3
        proxy.on_response(&mut ctx).await;

        info!("Request lifecycle complete");
    }
    .instrument(root_span)
    .await;

    // Ensure all spans are flushed
    global::shutdown_tracer_provider();
    println!("\nCheck the stdout above for JSON logs and the OpenTelemetry trace hierarchy.");
    println!("You should see 'stage_upstream_selection' and 'upstream_network_call' nested inside 'request_lifecycle'.");
}
"
}

