async fn queue_handler_task(shutdown_flag: Arc<AtomicBool>) {
    info!("Queue handler started.");
    let mut iteration = 0;

    while !shutdown_flag.load(Ordering::Relaxed) {
        iteration += 1;
        info!("Queue handler processing item #{}...", iteration);

