    let shutdown_flag_clone = Arc::clone(&shutdown_flag);

    // 1. Start the Queue Handler Task
    // We spawn this manually so we can control its lifecycle via the shutdown flag
    let queue_handle: JoinHandle<()> = tokio::spawn(async move {
        queue_handler_task(shutdown_flag_clone).await;
    });

