/// Converts a LanceDB ISO string (with optional fractional seconds) to a Unix timestamp (i64).
///
/// LanceDB often returns strings like:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"
///
/// The standard `parse_from_str` fails if the format string expects fractional seconds
/// but the input string does not have them, or vice versa.
///
/// Strategy:
/// 1. Attempt to parse as a full ISO 8601 string including fractional seconds.
/// 2. If that fails due to format mismatch, try parsing without fractional seconds.
/// 3. Alternatively, use `NaiveDateTime::parse_from_str` with a flexible approach or
///    rely on `DateTime::parse_from_rfc3339` which handles optional fractional seconds naturally.
fn date_string_to_int(d: &str) -> Result<i64, String> {
    // RFC3339 handles optional fractional seconds automatically.
    // Example: "2025-08-02T17:35:41.409" or "2025-08-02T17:35:41"
    // Note: RFC3339 usually requires a timezone offset (e.g., +00:00 or Z).
    // LanceDB strings often omit the timezone, implying UTC.

    // Append 'Z' if no timezone is present to make it valid RFC3339 for UTC
    let normalized = if d.contains('+') || d.contains('-') && d.len() > 19 {
        // Check if it looks like it already has an offset (basic heuristic)
        // A full ISO with offset usually has 24+ chars if it includes microseconds and offset
        d.to_string()
    } else if d.len() == 19 {
        // Exact length of "YYYY-MM-DDTHH:MM:SS"
        format!("{}Z", d)
    } else {
        // Has fractional seconds but no timezone
        format!("{}Z", d)
    };

    match DateTime::parse_from_rfc3339(&normalized) {
        Ok(dt) => Ok(dt.timestamp()),
        Err(e) => {
            // Fallback: Try parsing as NaiveDateTime assuming UTC if RFC3339 strictness fails
            // This handles cases where the string might be slightly non-compliant
            let naive = if normalized.ends_with('Z') {
                &normalized[..normalized.len()-1]
            } else {
                &normalized
            };

            // Try with fractional seconds first
            let format_with_frac = "%Y-%m-%dT%H:%M:%S%.f";
            let format_without_frac = "%Y-%m-%dT%H:%M:%S";

            let naive_dt = NaiveDateTime::parse_from_str(naive, format_with_frac)
                .or_else(|_| NaiveDateTime::parse_from_str(naive, format_without_frac))
                .map_err(|_| format!("Failed to parse date '{}': {}", d, e))?;

            // Assume UTC for naive datetime
            Ok(naive_dt.and_utc().timestamp())
        }
    }
}

fn main() {
