// Revised EventSender that allows explicit shutdown of the ROOT source
#[derive(Debug, Clone)]
pub struct ManagedEventSender {
    tx: Arc<Sender<Event>>,
}

impl ManagedEventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

pub struct EventStreamFactory {
    tx: Sender<Event>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, tokio::sync::broadcast::error::RecvError>> + Send + Unpin {
        let rx = self.tx.subscribe();
        BroadcastStream::new(rx)
    }
}

// Helper to create the channel system
pub fn events_channel() -> (ManagedEventSender, EventStreamFactory) {
    let (tx, _rx) = broadcast::channel::<Event>(20);
    let arc_tx = Arc::new(tx);

    // We return a clone of the Arc for sending
    let sender = ManagedEventSender {
        tx: Arc::clone(&arc_tx),
    };

    // We return a factory that holds the original Sender (or a clone of the inner)
    // Note: BroadcastSender is cheap to clone.
    let factory = EventStreamFactory {
        tx: (*arc_tx).clone(),
    };

    (sender, factory)
}

#[tokio::main]
async fn main() {
    println!("Starting broadcast demo...");

    // Create the channel
    let (sender, factory) = events_channel();

    // Spawn a task that simulates an SSE client
    let mut stream = factory.all_events();

    let handle = tokio::spawn(async move {
        while let Some(res) = stream.next().await {
            match res {
                Ok(event) => println!("Client received: {}", event.message),
                Err(e) => {
                    if e == tokio::sync::broadcast::error::RecvError::Closed {
                        println!("Client detected stream closure (Closed). Shutting down client.");
                        break;
                    } else {
                        println!("Client received error: {:?}", e);
                    }
                }
            }
        }
        println!("Client task finished.");
    });

    // Send some events
    sender.send(Event { message: "Hello World".to_string() }).await;
    sender.send(Event { message: "Still running...".to_string() }).await;

    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;

    println!("\n--- INITIATING SHUTDOWN ---");

    // THE KEY TO SHUTTING DOWN:
    // The stream closes only when ALL instances of Sender are dropped.
    // In our setup, 'sender' holds an Arc<Sender>, and 'factory' holds a cloned Sender.
    // We need to ensure no Senders remain.

    // 1. The 'factory' variable holds a Sender. We must drop it.
    drop(factory);

    // 2. The 'sender' variable holds an Arc<Sender>. We must drop it.
    // If you have cloned 'sender' elsewhere, those must also be dropped.
    drop(sender);

    // Wait for the client to detect the closure
    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;

    // Cleanup task
    let _ = handle.abort();

    println!("Main function ending.");
}

// Note: To make this robust in a large app, you typically wrap the Sender 
// in an Option<Arc<Sender>> inside a struct, and provide a `shutdown(&mut self)` 
// method that does `self.0 = None`. This drops the root reference.
// Any other clones held by workers will keep the channel alive until they 
// also go out of scope or are reset. The broadcast channel specifically 
// signals 'Closed' only when the count of strong senders hits 0."
}

