    // However, if the script relies on __file__ or relative paths, a temp file is needed.
    // Here we demonstrate the robust method: writing to a temp file so the script behaves normally.

    let temp_dir = env::temp_dir();
    let script_path = temp_dir.join("rust_program_embedded_script.py");

    // Write the embedded content to the temp file
    if let Err(e) = fs::write(&script_path, PYTHON_SCRIPT_CONTENT) {
        eprintln!("Failed to write temporary script file: {}", e);
        std::process::exit(1);
    }

    // Ensure the temp file is cleaned up when the process exits (best effort)
    // In a real long-running service you might manage this differently, 
    // but for a CLI, leaving it in OS temp folder is usually handled by OS cleaners,
    // or we can defer removal. Let's try to remove it after execution.

    // 2. Invoke the Python interpreter
    // We use 'which' logic or just assume 'python3'/'python' is in PATH. 
    // A robust CLI often checks for python3 then python.
