  "main.rs": "use serde::Deserialize;
use std::sync::Arc;
use tokio::sync::Mutex;

// We cannot use a struct with borrowed references (&'a str) across .await points
// or tokio::spawn directly because the lifetime of the reference is tied to the
// local scope of the deserialization function, and spawned tasks require 'static.
//
// The solution is to own the data. While the prompt asks to avoid cloning *during*
// deserialization, the only way to send data between threads/tasks in Rust is to
// own it (or use shared ownership like Arc). 
//
// To achieve the goal of "parse once" and "no unnecessary cloning when passing around",
// we deserialize into an owned struct ONCE, wrap it in an Arc, and pass the Arc.
// Passing an Arc is cheap (atomic increment) and does not clone the underlying string data.

#[derive(Deserialize, Debug, Clone)]
struct MyData {
    data: String,
    more_data: String,
}

// A wrapper that holds the owned data. 
// In a real scenario, you might wrap this in Arc<Mutex<...>> if mutable access is needed,
// or just Arc<...> for read-only access across tasks.
type SharedData = Arc<MyData>;

async fn process_task(task_id: usize, data: SharedData) {
    println!(
        "Task {}: Received data -> data: '{}', more_data: '{}'",
        task_id, data.data, data.more_data
    );

    // Simulate some async work
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("Task {}: Completed.", task_id);
}

#[tokio::main]
async fn main() {
    // 1. Simulate incoming JSON payload (e.g., from TCP)
    let json_payload = r#"{
        "data": "this is the first part of the data",
        "more_data": "and this is the second part"
    }"#;

    // 2. Deserialize ONCE.
    // We must deserialize into an owned type (String) to break the lifetime tie
    // to the `json_payload` local variable. If we used &'a str, the data would
    // be invalid as soon as this function scope ended or if we tried to move it
    // into a 'static task.
    let parsed_data: MyData = match serde_json::from_str(json_payload) {
        Ok(data) => data,
        Err(e) => {
            eprintln!("Failed to deserialize: {}", e);
            return;
        }
    };

    println!("Deserialization complete. Data parsed once.");

    // 3. Wrap in Arc to allow sharing across threads/tasks without cloning the inner Strings.
    // Cloning an Arc is cheap (pointer copy + atomic inc), whereas cloning the struct
    // would copy the Strings. This satisfies the requirement of passing data efficiently.
    let shared_data: SharedData = Arc::new(parsed_data);

    let mut handles = vec![];

    // 4. Spawn multiple tasks, passing the Arc.
    for i in 0..5 {
        let data_clone = Arc::clone(&shared_data);
        let handle = tokio::spawn(async move {
            process_task(i, data_clone).await;
        });
        handles.push(handle);
    }

    // Wait for all tasks to complete
    for handle in handles {
        handle.await.unwrap();
    }

    println!("All tasks finished. The original data was parsed only once.");
}
"
}

