  "main.rs": "use axum::{
    extract::{Path, State, WebSocketUpgrade},
    http::{HeaderValue, StatusCode},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use axum_extra::{
    headers::{HeaderMapExt, Origin},
    TypedHeader,
};
use http::header;
use std::{net::SocketAddr, sync::Arc};
use tower_http::cors::{Any, CorsLayer};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

// Application state to hold the allowed origin
#[derive(Clone)]
struct AppState {
    allowed_origin: HeaderValue,
}

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::new(
            std::env::var("RUST_LOG").unwrap_or_else(|_| "info".into()),
        ))
        .with(tracing_subscriber::fmt::layer())
        .init();

    // Define the allowed origin
    let allowed_origin_str = "https://www.example.com";
    let allowed_origin = HeaderValue::from_str(allowed_origin_str)
        .expect("Invalid origin header value");

    let state = AppState {
        allowed_origin: allowed_origin.clone(),
    };

    // CORS layer for standard HTTP requests (GET/POST/etc)
    // Note: As you noted, this does not enforce Origin checks for WebSockets automatically.
    let cors = CorsLayer::new()
        .allow_origin(allowed_origin)
        .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .layer(cors)
        .with_state(state);

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    tracing::info!("Listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
    State(state): State<AppState>,
    headers: http::HeaderMap,
) -> Response {
    // Manually extract and validate the Origin header for WebSockets
    // We use HeaderMap directly to handle cases where the header might be missing or invalid
    // without relying on TypedHeader which might reject the request immediately with 400

    let origin_valid = if let Some(origin_value) = headers.get(header::ORIGIN) {
        origin_value == &state.allowed_origin
    } else {
        // Decide if you want to allow requests without an Origin header (e.g., from some CLI tools)
        // Usually for browsers, Origin is present. If strict, return false.
        false;
    };

    if !origin_valid {
        tracing::warn!("Blocked websocket connection from unauthorized origin");
        return StatusCode::FORBIDDEN.into_response();
    }

    tracing::info!("Accepted websocket connection for session: {}", session_id);

    ws.on_upgrade(|socket| async move {
        // Handle the websocket connection here
        let (mut sink, mut stream) = socket.split();

        // Example: Just close immediately or implement logic
        use futures_util::{StreamExt, SinkExt};
        while let Some(msg) = stream.next().await {
            if let Ok(msg) = msg {
                if let axum::extract::ws::Message::Text(text) = msg {
                    let _ = sink.send(axum::extract::ws::Message::Text(format!("Echo: {}", text))).await;
                }
            } else {
                break;
            }
        }
    })
}
"
