  "main.rs": "use std::sync::Arc;
use tokio::sync::Mutex;
use tokio_postgres::{Client, NoTls, Error};

/// A wrapper that holds the Client and ensures the Connection task is spawned
/// and kept alive for the lifetime of the wrapper.
///
/// The key insight: The `tokio_postgres::Connection` future MUST be polled
/// (usually via a spawned task) for the `Client` to remain functional.
/// If the task storing the `Connection` future drops, the connection closes,
/// even if the `Client` is still held elsewhere.
///
/// In the user's failed attempt, they likely stored the `Client` in a cache
/// but the scope handling the `Connection` future (or the task spawning it)
/// was tied to a temporary scope or dropped prematurely.
///
/// By wrapping both the `Client` and the `JoinHandle` of the connection task
/// in an Arc, we ensure that as long as the Client is alive, the Task keeping
/// the connection alive is also alive.
struct PooledClient {
    client: Client,
    // We hold the handle to the spawned task. As long as this struct exists,
    // the task is considered "joined" or at least referenced, preventing
    // premature cleanup logic if we were to implement custom drop logic,
    // but primarily this struct represents the "active connection unit".
    // Note: Simply spawning the task in `tokio::spawn` returns a JoinHandle.
    // If we drop the JoinHandle, the task keeps running in the background.
    // However, to logically group them, we keep them together.
    _handle: tokio::task::JoinHandle<Result<(), Error>>,
}

impl PooledClient {
    fn new(client: Client, handle: tokio::task::JoinHandle<Result<(), Error>>) -> Self {
        Self {
            client,
            _handle: handle,
        }
    }
}

struct DbManager {
    // We cache the PooledClient. 
    // Using Mutex<Option<...>> allows lazy initialization.
    // Using Arc ensures we can clone the reference if needed, though 
    // inside a single struct instance, a Mutex is sufficient for interior mutability.
    cached_client: Mutex<Option<Arc<PooledClient>>>,
    connection_params: String,
}

impl DbManager {
    fn new(host: &str, port: u16, user: &str, password: &str) -> Self {
        let conn_str = format!(
            "host={} port={} user={} password={}",
            host, port, user, password
        );
        Self {
            cached_client: Mutex::new(None),
            connection_params: conn_str,
        }
    }

    /// Gets a client, creating and caching it if it doesn't exist.
    /// This demonstrates the correct way to cache without closing the connection.
    async fn get_client(&self) -> Result<Arc<PooledClient>, Error> {
        let mut guard = self.cached_client.lock().await;

        if let Some(client) = guard.as_ref() {
            // Return existing cached client
            return Ok(Arc::clone(client));
        }

        println!("Establishing new connection...");
        let (client, connection) = tokio_postgres::connect(&self.connection_params, NoTls).await?;

        // CRITICAL STEP:
