  "main.rs": "use futures::future::Future;
use futures::task::{Context, Poll, Waker, RawWaker, RawWakerVTable};
use std::pin::Pin;
use std::sync::Arc;
use std::task::Waker;

/// Result of trying to poll a future once without yielding.
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// A no-op waker. Since we only poll once and expect immediate readiness,
/// if the future returns Pending, it means it needs a real runtime to proceed.
/// This waker satisfies the trait requirements but does nothing when called.
fn noop_waker() -> Waker {
    fn raw_clone(_: *const ()) -> RawWaker {
        raw_waker()
    }
    fn raw_wake(_: *const ()) {}
    fn raw_wake_by_ref(_: *const ()) {}
    fn raw_drop(_: *const ()) {}

    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        raw_clone,
        raw_wake,
        raw_wake_by_ref,
        raw_drop,
    );

    unsafe { Waker::from_raw(raw_waker()) }
}

fn raw_waker() -> RawWaker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_: *const ()| raw_waker(),
        |_: *const ()| {},
        |_: *const ()| {},
        |_: *const ()| {},
    );
    RawWaker::new(std::ptr::null(), &VTABLE)
}

/// Attempts to poll the future once.
/// - If Ready, returns the value.
/// - If Pending, returns Pending (the future is unchanged and can be polled again later).
fn try_poll<X>(future: &mut Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// A simple future that completes immediately if the input is true,
/// otherwise it waits for a delay (simulating async work).
async fn conditional_future(should_complete_immediately: bool) -> String {
    if should_complete_immediately {
        "Completed immediately!".to_string()
    } else {
        tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
        "Completed after delay!".to_string()
    }
}

/// This is a synchronous function running inside an async context.
fn process_future_sync(should_complete_immediately: bool) {
    // Box the future so we have a stable pointer to pin against
    let mut fut = Box::pin(conditional_future(should_complete_immediately));

    // Cast to trait object for our helper function
    let fut_trait: &mut Pin<&mut dyn Future<Output = String>> = &mut fut;

    match try_poll(fut_trait) {
        TryPollResult::Ready(value) => {
            println!("[Sync Path] Future was ready immediately: {}", value);
        }
        TryPollResult::Pending => {
            println!("[Sync Path] Future was pending. Spawning task to await it...");

            // Since it's pending, we move the future into a spawned task
            tokio::spawn(async move {
                let result = fut.await;
                println!("[Async Task] Future completed in background: {}", result);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("Test 1: Future that completes immediately");
    process_future_sync(true);

    println!("\nTest 2: Future that requires waiting");
    process_future_sync(false);

    // Give the spawned task time to finish before exiting
    tokio::time::sleep(tokio::time::Duration::from_millis(800)).await;
    println!("\nMain function exiting.");
}
