/// This implementation uses `copy_nonoverlapping` to swap 4-byte chunks.
/// On modern compilers (LLVM/Rustc) for x86_64 and aarch64, this typically
/// compiles down to efficient unaligned load/store or dedicated swap instructions
/// (like MOVQ on x86 or LDP/STP on ARM), effectively utilizing the 4-byte alignment
/// without needing explicit unsafe intrinsics which are harder to maintain.
///
/// We avoid `swap_nonoverlapping` in a loop with variable lengths if possible,
/// but here the length is constant (4), so the compiler can fully unroll and optimize.
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    let len = line_bytes.len();
    let mut left = 0;
    let mut right = len.saturating_sub(BYTES_PER_PIXEL);

    while left < right {
        unsafe {
            // We use a temporary stack variable to hold one pixel during the swap.
            // This pattern is often better optimized by the compiler than `swap_nonoverlapping`
            // for small, fixed sizes because it allows register allocation instead of 
            // forcing a memory-to-memory swap function call semantics.
            let mut temp = [0u8; BYTES_PER_PIXEL];

            let left_ptr = line_bytes.as_mut_ptr().add(left);
            let right_ptr = line_bytes.as_mut_ptr().add(right);

