        if !char_before.is_whitespace() {
            return None;
        }

        // Find the start of the whitespace run immediately before the cursor
        let mut ws_start = pos;
        for (i, c) in line[..pos].char_indices().rev() {
            if c.is_whitespace() {
                ws_start = i;
            } else {
                break;
            }
        }

        let whitespace_len = pos - ws_start;

        if whitespace_len > 0 {
            // Strategy:
            // 1. Move cursor backward by the length of the whitespace.
            // 2. Delete the whitespace (ForwardChar).
            // 3. Insert the special character ('.' or ',').
            //
            // Since we cannot return a list of commands, we use Cmd::Replace.
            // Cmd::Replace(movement, Some(text)) does:
            //   1. Execute movement (moves cursor).
            //   2. Deletes the text covered by the movement (if any).
            //   3. Inserts `text`.
            //   4. Leaves cursor AFTER `text`.
            //
            // To delete the whitespace that is *behind* us, we must move the cursor
            // back over it, so that the whitespace falls under the "selection" of the movement.
            // However, Movement::BackwardChar(n) moves the cursor but doesn't inherently 
            // select the text passed over for deletion in the way Replace expects unless 
            // we consider the range between old_pos and new_pos.
            //
            // Actually, Cmd::Replace(Movement::BackwardChar(n), Some(s)) works as follows in rustyline:
            // It moves the cursor back n steps. The text BETWEEN the original position and the new position
            // is considered the target for replacement.

            let movement = Movement::BackwardChar(whitespace_len as RepeatCount);
            let replacement = self.char_to_insert.to_string();

            return Some(Cmd::Replace(movement, Some(replacement)));
        }

        None
    }
}

fn bind_special_keys<H: Helper>(editor: &mut Editor<H, rustyline::history::DefaultHistory>) {
    // Bind '.'
    let dot_event = KeyEvent::new('.', rustyline::event::Modifiers::NONE);
    let dot_handler = Box::new(DotCommaHandler::new('.'));
    editor.bind_sequence(dot_event, EventHandler::Conditional(dot_handler));

    // Bind ','
    let comma_event = KeyEvent::new(',', rustyline::event::Modifiers::NONE);
    let comma_handler = Box::new(DotCommaHandler::new(','));
    editor.bind_sequence(comma_event, EventHandler::Conditional(comma_handler));
}

