/// Splits a shell command string into tokens, respecting single quotes.
///
/// Logic:
/// 1. Split by single quotes `'`. This creates alternating segments:
///    - Even indices (0, 2, ...): Unquoted regions where whitespace separates tokens.
///    - Odd indices (1, 3, ...): Quoted regions where whitespace is literal.
/// 2. Process unquoted regions: Group consecutive characters by "is whitespace".
///    - Whitespace groups become separators.
///    - Non-whitespace groups become potential tokens.
/// 3. Process quoted regions: Treat the entire segment as a single literal token content.
/// 4. Flatten the structure and re-group adjacent non-whitespace segments.
///    - This handles cases like `' two  'three` where a quoted segment ends with spaces
///      and the next unquoted segment starts with text, merging them into one token.
/// 5. Filter out pure whitespace segments.
fn tokenize(s: &str) -> Vec<String> {
    s.split('\'')
     .enumerate()
     .flat_map(|(i, segment)| {
         if i % 2 == 0 {
             // Unquoted: split by whitespace boundaries
             // group_by returns an iterator of (key, group_iterator)
             // key is true if the char is a space, false otherwise
             segment
                 .chars()
                 .group_by(|c| c.is_whitespace())
                 .into_iter()
                 .map(|(is_space, chars)| (is_space, chars.collect::<String>()))
                 .collect::<Vec<_>>()
         } else {
             // Quoted: keep as a single literal block (标记为 non-space logically to allow merging if needed,
             // though logically quoted content is always a token part)
             // We use false (non-space) so that if a quote ends with space and next starts with text,
             // they might merge? Actually, the split happens at the quote boundary.
             // Let's trace: ' two  'three
             // Split: ["", " two  ", "three"]
             // 0 ("": unquoted) -> [] (empty or whitespace)
             // 1 (" two  ": quoted) -> [(false, " two  ")]
             // 2 ("three": unquoted) -> [(false, "three")]
             // Flat: [(false, " two  "), (false, "three")]
             // Next group_by(!is_space) groups them together because both are false!
             // Result: " two  three". This matches the requirement.
             vec![(false, segment.to_string())]
         }
     })
     .group_by(|(is_space, _)| !is_space)
     .into_iter()
     .filter_map(|(is_token, group)| {
         if is_token {
             Some(group.map(|(_, s)| s).join(""))
         } else {
             None
         }
     })
     .filter(|s| !s.is_empty())
     .collect()
}

