  "main.rs": "use serde_json::{Value, from_str, to_string_pretty};
use std::fs;
use std::path::Path;

const FILE_PATH: &str = "output.json";

/// Loads the existing JSON file into a Value, or returns an empty array if the file doesn't exist.
fn load_or_create() -> Value {
    let path = Path::new(FILE_PATH);

    if !path.exists() {
        // File doesn't exist, return an empty JSON array
        return Value::Array(Vec::new());
    }

    // File exists, try to read and parse it
    let data = match fs::read_to_string(path) {
        Ok(content) => content,
        Err(e) => {
            eprintln!("Error reading file: {}", e);
            return Value::Array(Vec::new());
        }
    };

    match from_str::<Value>(&data) {
        Ok(json) => json,
        Err(e) => {
            eprintln!("Error parsing JSON: {}. Starting with empty list.", e);
            Value::Array(Vec::new())
        }
    }
}

/// Appends a new item to the JSON array and saves it back to the file.
fn append_item(new_item: &str) {
    // 1. Load existing data or create empty array
    let mut data = load_or_create();

    // 2. Ensure it's an array and push the new item
    if let Value::Array(arr) = &mut data {
        arr.push(Value::String(new_item.to_string()));
    } else {
        eprintln!("Root of JSON file is not an array. Overwriting with new array.");
        data = Value::Array(vec![Value::String(new_item.to_string())]);
    }

    // 3. Serialize back to pretty-printed JSON string
    let json_string = to_string_pretty(&data).expect("Failed to serialize JSON");

    // 4. Write the entire content back to the file (overwriting)
    // Note: JSON files cannot be strictly "appended" to like text logs because
    // the closing bracket ']' must move. We must rewrite the whole file.
    fs::write(FILE_PATH, json_string).expect("Unable to write file");

    println!("Successfully added: '{}'", new_item);
}

fn main() {
    // Simulate adding some tasks
    append_item("Buy milk");
    append_item("Learn Rust");
    append_item("Write JSON to file");

    // Display final content
    println!("\nCurrent contents of {}:", FILE_PATH);
    let final_content = fs::read_to_string(FILE_PATH).unwrap();
    println!("{}", final_content);
}
"
