// Helper to deserialize either a String or an i32
#[derive(Debug)]
enum UntypedValue {
    Str(String),
    Num(i32),
}

struct UntypedValueSeed;

impl<'de> de::DeserializeSeed<'de> for UntypedValueSeed {
    type Value = UntypedValue;

    fn deserialize<D>(self, deserializer: D) -> Result<Self::Value, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct UntypedValueVisitor;

        impl<'de> Visitor<'de> for UntypedValueVisitor {
            type Value = UntypedValue;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a string or an integer")
            }

            fn visit_str<E>(self, v: &str) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(UntypedValue::Str(v.to_string()))
            }

            fn visit_i32<E>(self, v: i32) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(UntypedValue::Num(v))
            }

            fn visit_i64<E>(self, v: i64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                // Narrow to i32 for demo simplicity
                if v >= i32::MIN as i64 && v <= i32::MAX as i64 {
                    Ok(UntypedValue::Num(v as i32))
                } else {
                    Err(E::custom("Number out of range for i32"))
                }
            }
        }

        deserializer.deserialize_any(UntypedValueVisitor)
    }
}

// Visitor for Struct A
struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a map representing struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<&str>()? {
            match key {
                "x" => {
                    x = Some(map.next_value()?);
                }
                "b" => {
                    // This is the nested part: We define a visitor for Vec<B>
                    // Since Vec<B> implements Deserialize if B implements Deserialize,
                    // and we implemented Deserialize for B (via the visitor below),
                    // we can just call next_value::<Vec<B>>().
                    // HOWEVER, B does not derive Deserialize, we wrote a custom visitor.
                    // We need to associate the visitor with B.

                    // To do this cleanly, we usually implement `impl<'de> Deserialize<'de> for B` 
                    // which delegates to our visitor. Then next_value::<Vec<B>>() works automatically.
                    b = Some(map.next_value()?);
                }
                _ => {
                    let _: de::IgnoredAny = map.next_value()?;
                }
            }
        }

        let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
        let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

        Ok(A { x, b })
    }
}

// Implement Deserialize for B using our custom visitor
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(BVisitor)
    }
}

// Implement Deserialize for A using our custom visitor
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_map(AVisitor)
    }
}

fn main() {
