fn main() {
    // Example input: Vec<Vec<usize>> with varying inner sizes
    let a: Vec<Vec<usize>> = vec![
        vec![1, 2, 3],
        vec![4, 5],
        vec![6, 7, 8, 9],
        vec![10],
    ];

    // Process in parallel while preserving structure
    // We map over the outer vector in parallel, and for each inner vector,
    // we map its elements (also in parallel if they are large enough, though
    // for small vectors standard iter() is often faster due to overhead).
    //
    // Here we demonstrate: 
    // 1. par_iter() on the outer vector.
    // 2. A transformation function applied to each usize (e.g., converting to String with index info).

    let result: Vec<Vec<String>> = a
        .par_iter()
        .map(|inner_vec| {
            inner_vec
                .iter()
                .map(|&x| format!("Value: {}", x * 2)) // Example function: double and stringify
                .collect()
        })
        .collect();

    // Print results to verify structure preservation
    println!("Original: {:?}", a);
    println!("Processed: {:?}", result);

    // Verify lengths match
    assert_eq!(a.len(), result.len());
    for (i, (orig, proc)) in a.iter().zip(result.iter()).enumerate() {
        assert_eq!(orig.len(), proc.len(), "Length mismatch at index {}", i);
    }

    println!("Success: Structure preserved and parallel processing completed.");
