/// you cannot store that in a struct that owns the argument unless the argument is 'static.
///
/// Solution 1 (Recommended): Change the struct to own the data (String).
/// This is usually the right move for HashMap keys anyway, as it makes the key self-contained.
#[derive(Debug, Clone)]
pub struct ResourceRefOwned<R: Resource>
where
    R::DynamicType: Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<String>,
    kind: String,
    name: String,
}

