where
    R::DynamicType: Default,
{
    pub fn new_named(name: &str) -> Self {
        let dynamic_type = R::DynamicType::default();

        // We convert the borrowed &str to an owned String immediately.
        // This breaks the lifetime dependency on the local `dynamic_type` variable.
        let group_str = R::group(&dynamic_type);
        let group = if group_str.is_empty() {
            None
        } else {
            Some(group_str.to_string())
        };

        let kind = R::kind(&dynamic_type).to_string();

        Self {
            type_: PhantomData,
            dynamic_type,
            group,
            kind,
            name: name.to_string(),
        }
    }

    pub fn group(&self) -> Option<&str> {
        self.group.as_deref()
    }

    pub fn kind(&self) -> &str {
        &self.kind
    }

    pub fn name(&self) -> &str {
        &self.name
    }
}

