/// This only works if the strings returned by R::group/kind are actually 'static
/// (e.g., string literals) and the API just happens to tie the lifetime to the argument.
/// If the crate generates strings dynamically based on the instance, this approach is impossible
/// without unsafe code or changing the crate's API.
///
/// We force the lifetime to 'static here. If the crate returns non-'static data derived from
/// the specific instance content, this will compile but crash at runtime or be rejected by the borrow checker
/// if the compiler can prove non-staticness.
#[derive(Debug, Clone)]
pub struct ResourceRefStatic<'a, R: Resource>
where
    R::DynamicType: 'static + Default,
{
    type_: PhantomData<R>,
    dynamic_type: R::DynamicType,
    group: Option<Cow<'a, str>>,
    kind: Cow<'a, str>,
