/// but DOES NOT load the actual texture data yet. It acts as a map.
#[derive(TypePath, Asset)]
pub struct WadArchive {
    pub entries: std::collections::HashMap<String, WadEntryInfo>,
    pub source_path: PathBuf,
}

#[derive(Clone, Debug)]
