impl AssetLoader for WadLoader {
    type Asset = WadArchive;
    type Settings = Settings;
    type Error = anyhow::Error;

    fn load<'a>(
        &'a self,
        reader: &'a mut bevy::asset::IoReader,
        settings: &'a Self::Settings,
        load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;

            let mut cursor = Cursor::new(bytes);

            // --- Minimal WAD3 Parsing Logic (GoldSrc style) ---
            // Header: Magic (4), NumEntries (4), DirOffset (4)
            let mut magic = [0u8; 4];
            cursor.read_exact(&mut magic)?;
            if &magic != b"WAD3" {
                // Fallback for demo if file doesn't exist or is wrong format, 
                // in real usage return Err. Here we create a dummy to prevent crash if no file.
                return Ok(WadArchive {
                    entries: std::collections::HashMap::new(),
                    source_path: PathBuf::new(),
                });
            }

            let num_entries = cursor.read_u32::<LittleEndian>()?;
            let dir_offset = cursor.read_u32::<LittleEndian>()?;

            let mut entries = std::collections::HashMap::new();

            // Seek to directory
            cursor.seek(std::io::SeekFrom::Start(dir_offset as u64))?;

            for _ in 0..num_entries {
                // Dir Entry: FilePos(4), DiskSize(4), Size(4), Type(1), Compression(1), Unknown(2), Name(16)
                let file_pos = cursor.read_u32::<LittleEndian>()?;
                let _disk_size = cursor.read_u32::<LittleEndian>()?;
                let size = cursor.read_u32::<LittleEndian>()?;
                let _type_byte = cursor.read_u8()?;
                let _compressed = cursor.read_u8()?;
                cursor.seek(std::io::SeekFrom::Current(2))?; // Unknown

                let mut name_bytes = [0u8; 16];
                cursor.read_exact(&mut name_bytes)?;

                // Clean name (remove null terminators)
                let name = String::from_utf8_lossy(&name_bytes)
                    .trim_end_matches(char::from(0))
                    .to_string();

                if name.is_empty() {
                    continue;
                }

                // Simulate reading header of the texture at file_pos to get dimensions
                // In a real WAD3, you'd seek to file_pos and read the MIP header.
                // For this lazy loader demo, we assume fixed size or fake it if we can't seek easily in this buffer.
                // To make it truly lazy, we store the `file_pos` and `size`.
                // We will pretend dimensions are 64x64 for the demo unless we parse further.

                entries.insert(
                    name.clone(),
                    WadEntryInfo {
                        file_pos,
                        size,
                        width: 64,
                        height: 64,
                    },
