  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(i32);

// We define a trait to represent the type-erased async function.
// This avoids the complex higher-ranked trait bounds (HRTB) in the enum directly
// and allows us to use `async-trait` to handle the boxing/pinning internally.
#[async_trait::async_trait]
trait AsyncWork: Send {
    async fn run(&mut self, ctx: &mut Context);
}

// The wrapper struct that holds the closure.
// `F` is the closure, `Fut` is the future it returns.
struct WorkWrapper<F, Fut>
where
    F: FnMut(&mut Context) -> Fut + Send,
    Fut: Future<Output = ()> + Send,
{
    work: F,
}

#[async_trait::async_trait]
impl<F, Fut> AsyncWork for WorkWrapper<F, Fut>
where
    F: FnMut(&mut Context) -> Fut + Send + Sync,
    Fut: Future<Output = ()> + Send,
{
    async fn run(&mut self, ctx: &mut Context) {
        (self.work)(ctx).await;
    }
}

pub enum InnerAsyncEvent {
    DoWithContext {
        // We box the trait object. The lifetime issues are resolved by the trait.
        block: Box<dyn AsyncWork>,
    },
}

/// Helper function to wrap a simple async closure and send it.
/// 
/// This accepts an `async fn` or an async closure that takes `&mut Context`.
/// It handles the boxing and pinning internally.
pub fn with_context_async<F, Fut>(
    work_sender: &mpsc::Sender<InnerAsyncEvent>,
    block: F,
) -> Result<(), mpsc::error::SendError<InnerAsyncEvent>>
where
    F: FnMut(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    let wrapper = WorkWrapper { work: block };

    work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(wrapper),
    }).await
}

#[tokio::main]
async fn main() {
    let (tx, mut rx) = mpsc::channel::<InnerAsyncEvent>(10);

    // Spawn a worker thread (simulated by a task here) that processes events
    let worker = tokio::spawn(async move {
        let mut ctx = Context(0);
        println!("Worker started. Initial context: {}", ctx.0);

        while let Some(event) = rx.recv().await {
            match event {
                InnerAsyncEvent::DoWithContext { mut block } => {
                    block.run(&mut ctx).await;
                    println!("Work completed. Context is now: {}", ctx.0);
                }
            }
        }
        println!("Worker finished.");
    });

    // --- Usage Example 1: Async Closure ---
    // This is the nice syntax the user wanted.
    with_context_async(&tx, |ctx: &mut Context| async move {
        println!("Running first task...");
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        ctx.0 += 10;
    })
    .await
    .unwrap();

    // --- Usage Example 2: Another Async Closure capturing variables ---
    let multiplier = 5;
    with_context_async(&tx, |ctx: &mut Context| async move {
        println!("Running second task with multiplier {}...", multiplier);
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        ctx.0 *= multiplier;
    })
    .await
    .unwrap();

    // Drop sender to signal worker to stop
    drop(tx);

    // Wait for worker to finish
    worker.await.unwrap();
}"
}

