name = "async-harness-fix"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full"] }
",
  "main.rs": "use std::future::Future;
use std::pin::Pin;

// The async function we want to test.
// Async functions in Rust are sugar for functions returning impl Future.
// The lifetime of the reference passed in is tied to the returned Future.
async fn simple_test(string: &mut String) {
    string.push_str("test result\n");
}

// The harness needs to accept any function T that:
// 1. Takes a mutable string reference with *any* lifetime ('a).
// 2. Returns a Future that is valid for that same lifetime ('a).
//
// The original code failed because `Fut` was a single concrete type determined
// at the start of the function call, but the closure needs to work for *any*
// lifetime the harness chooses to provide locally.
//
// We solve this by using Higher-Ranked Trait Bounds (HRTB) directly on the return
// type of the function pointer/trait bound, rather than introducing a generic `Fut`.
async fn harness<T>(test: T)
where
    T: for<'a> Fn(&'a mut String) -> Pin<Box<dyn Future<Output = ()> + 'a>>,
{
    let mut string = String::new();
    test(&mut string).await;
    println!("new string is:\n{string}");
}

#[tokio::main]
async fn main() {
    // We must wrap the async function call in a closure that explicitly boxes the future.
    // This matches the signature expected by `harness`:
    // It takes a reference, and returns a boxed future tied to that reference's lifetime.
    harness(|s| Box::pin(simple_test(s))).await;
}
"
}

