  "main.rs": "use actix_web::{web, App, HttpServer, HttpResponse};
use actix_web::rt;
use log::{info, warn, error};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::time::Duration;
use tokio::signal;
use tokio::task::JoinHandle;
use anyhow::Result;

/// Simulates a long-running queue handler task.
/// It checks a shutdown flag to stop gracefully.
async fn queue_handler_task(shutdown_flag: Arc<AtomicBool>) -> Result<()> {
    info!("Queue handler started");
    let mut counter = 0;

    while !shutdown_flag.load(Ordering::Relaxed) {
        // Simulate processing work
        info!("Queue handler processing item {}...", counter);
        tokio::time::sleep(Duration::from_secs(2)).await;
        counter += 1;
    }

    info!("Queue handler received shutdown signal, finishing current work...");
    // Simulate final cleanup work
    tokio::time::sleep(Duration::from_millis(500)).await;
    info!("Queue handler shut down gracefully");
    Ok(())
}

#[actix_web::main]
async fn main() -> Result<()> {
    // Initialize logger
    env_logger::init_from_env(env_logger::Env::default().default_filter_or("info"));

    info!("Starting application with graceful shutdown demonstration");

    // Shared shutdown flag for the custom task
    let shutdown_flag = Arc::new(AtomicBool::new(false));
    let shutdown_flag_clone = Arc::clone(&shutdown_flag);

    // 1. Start the Actix Web Server
    // We keep the server handle to stop it later manually if needed, 
    // though actix usually responds to Ctrl+C automatically. 
    // However, to coordinate with our custom task, we manage the flow explicitly.
    let server = HttpServer::new(|| {
        App::new()
            .route("/", web::get().to(|| async { HttpResponse::Ok().body("Hello World!") }))
    })
    .bind(("127.0.0.1", 8080))?
    .run();

    let server_handle = server.handle();

    // Spawn the server future
    let server_task: JoinHandle<Result<(), std::io::Error>> = rt::spawn(server);

    // Spawn the custom queue handler task
    let queue_task: JoinHandle<Result<()>> = tokio::spawn(queue_handler_task(shutdown_flag_clone));

    info!("Server running on http://127.0.0.1:8080");
    info!("Press Ctrl+C to initiate graceful shutdown");

    // 2. Wait for Ctrl+C signal
    // This awaits until the user presses Ctrl+C
    signal::ctrl_c().await.expect("Failed to listen for ctrl+c event");

    warn!("Ctrl+C detected! Initiating graceful shutdown sequence...");

    // 3. Signal the custom task to stop
    // Set the flag. The next loop iteration in queue_handler_task will see this and exit.
    shutdown_flag.store(true, Ordering::Relaxed);

    // 4. Stop the Actix server gracefully
    // true means wait for workers to finish current requests
    info!("Stopping Actix Web server...");
    server_handle.stop(true).await;

    // 5. Wait for both tasks to actually finish
    // This ensures no background processes are left hanging
    info!("Waiting for tasks to join...");

    match queue_task.await {
        Ok(Ok(())) => info!("Queue task completed successfully"),
        Ok(Err(e)) => error!("Queue task failed: {}", e),
        Err(e) => error!("Queue task panicked: {}", e),
    }

    match server_task.await {
        Ok(Ok(())) => info!("Server task completed successfully"),
        Ok(Err(e)) => error!("Server task failed: {}", e),
        Err(e) => error!("Server task panicked: {}", e),
    }

    info!("Application shut down completely");
    Ok(())
}
