use axum_extra::{
    extract::TypedHeader,
    headers::{Origin},
};
use std::sync::Arc;
use tokio::net::TcpListener;
use tracing::{info, warn};

// Application state to hold the allowed origin
#[derive(Clone)]
struct AppState {
    allowed_origin: HeaderValue,
}

#[tokio::main]
async fn main() {
    // Initialize tracing
    tracing_subscriber::fmt::init();

    // Define the allowed origin
    let allowed_origin_str = "https://www.example.com";
    let allowed_origin = HeaderValue::from_str(allowed_origin_str)
        .expect("Invalid allowed origin");

    let state = AppState {
        allowed_origin,
    };

    // Build the router
    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .with_state(state);

    // Start the server
    let addr = "127.0.0.1:3000";
    let listener = TcpListener::bind(addr).await.unwrap();
    info!("Listening on {}", addr);

    axum::serve(listener, app).await.unwrap();
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
    State(state): State<AppState>,
    origin: Option<TypedHeader<Origin>>,
) -> impl IntoResponse {
    // 1. Check if Origin header exists
    let origin_header = match origin {
        Some(TypedHeader(origin)) => origin,
        None => {
            warn!("WebSocket connection rejected: Missing Origin header");
            return (StatusCode::FORBIDDEN, "Missing Origin header").into_response();
        }
    };

    // 2. Validate the origin against the allowed list
    // We compare the string representation of the incoming origin with the allowed one.
    // Note: HeaderValue::eq ignores case for the scheme/host as per spec, 
    // but strict string comparison is often safer for exact matches.
    if origin_header.as_str() != state.allowed_origin.as_str() {
        warn!(
            "WebSocket connection rejected: Invalid origin '{}' (expected '{}')", 
            origin_header.as_str(), 
            state.allowed_origin.to_str().unwrap_or("invalid")
        );
        return (StatusCode::FORBIDDEN, "Invalid Origin").into_response();
    }

    info!("WebSocket connection accepted from {}", origin_header.as_str());

    // 3. Proceed with the WebSocket upgrade
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(socket: WebSocket, session_id: String) {
    let (mut sender, mut receiver) = socket.split();

    info!("Session {} connected", session_id);

    // Simple echo loop for demonstration
    while let Some(msg) = receiver.recv().await {
        match msg {
            Ok(msg) => {
                if let Err(e) = sender.send(msg).await {
                    warn!("Send error: {}", e);
                    break;
                }
            }
            Err(e) => {
