// Simulates the common context shared across async stages
#[derive(Clone)]
pub struct RequestContext {
    pub request_id: String,
    // We store the OpenTelemetry Context, which contains the span relationship info
    pub otel_context: Context,
}

impl RequestContext {
    pub fn new() -> Self {
        let request_id = Uuid::new_v4().to_string();

        // Create the root span for the request
        let tracer = global::tracer("pingora-proxy");
        let span = tracer
            .span_builder("request_parent")
            .with_attributes(vec![KeyValue::new("request.id", request_id.clone())])
            .start(&tracer);

        // Capture the current context which now includes the new span
        let otel_context = Context::current_with_span(span);

        Self {
            request_id,
            otel_context,
        }
    }

    // This is the key function: it re-attaches the stored OTEL context to the current thread/task
    pub fn attach_context(&self) -> tracing_opentelemetry::WithContextGuard {
