    // this automatically becomes a child of "request_parent"
    let span = tracing::span!(tracing::Level::INFO, "stage_1");
    let _enter = span.enter();

    tracing::info!("Processing Stage 1");
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;

    // Call next stage, passing the same context
    stage_2(ctx).await;
}

async fn stage_2(ctx: RequestContext) {
    // Rehydrate again for this new async boundary
    let _guard = ctx.attach_context();

    let span = tracing::span!(tracing::Level::INFO, "stage_2");
    let _enter = span.enter();

    tracing::info!("Processing Stage 2");
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;

    simulate_upstream_call(ctx).await;
}

async fn simulate_upstream_call(ctx: RequestContext) {
    let _guard = ctx.attach_context();

    let span = tracing::span!(tracing::Level::INFO, "upstream_call");
    let _enter = span.enter();

    tracing::info!("Calling Upstream Service");
    tokio::time::sleep(tokio::time::Duration::from_millis(30)).await;
}

#[tokio::main]
