    // 3. Initialize Request Context (creates root span)
    let ctx = RequestContext::new();
    let root_request_id = ctx.request_id.clone();

    // 4. Simulate entering the first stage.
    // In a real Pingora app, this might happen in a different task or thread.
    // We must attach the context immediately upon entry to restore the hierarchy.
    {
