    http_body_util::BodyImpl::new(body)
}

async fn handle_request(req: Request<hyper::body::Incoming>) -> Result<Response<http_body_util::BodyImpl<impl hyper::body::Body<Data = Bytes, Error = std::io::Error>>>, Infallible> {
    // Extract path (simplified for demonstration)
    let path_str = req.uri().path().trim_start_matches('/');
    if path_str.is_empty() {
        return Ok(Response::builder()
            .status(StatusCode::BAD_REQUEST)
            .body(http_body_util::BodyImpl::new(http_body_util::Empty::new()))
            .unwrap());
    }

    let path = Path::new(path_str);

    // Try to open the file
    let file = match File::open(path).await {
        Ok(f) => f,
        Err(_) => {
            return Ok(Response::builder()
                .status(StatusCode::NOT_FOUND)
                .body(http_body_util::BodyImpl::new(http_body_util::Empty::new()))
                .unwrap());
        }
    };

