  "main.rs": "use futures::future::{Future, FutureExt};
use std::pin::Pin;
use std::task::{Context, Poll, Waker};
use tokio::runtime::Handle;

/// Result of a non-blocking poll attempt
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future once without yielding.
///
/// Uses a no-op waker. If the future returns `Pending`, it implies it needs
/// an external event to progress, so we return `Pending`. If it returns `Ready`,
/// we return the value.
fn try_poll<X>(future: &mut Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    // Create a no-op waker. 
    // If the future returns Pending, it usually registers this waker to be notified later.
    // Since we don't care about notification (we just want to know if it's ready *now*),
    // a no-op waker is safe and efficient for this specific "try" pattern.
    let waker = futures::task::noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// A helper to easily pin a future for our try_poll function
fn try_poll_wrapper<F, T>(f: &mut F) -> TryPollResult<T>
where
    F: Future<Output = T> + Unpin,
{
    let mut pinned = Pin::new(f);
    // We cast to dyn Future to match the signature logic, though direct pin works too.
    // Here we just call poll directly on the pinned generic for simplicity in usage.
    let waker = futures::task::noop_waker();
    let mut cx = Context::from_waker(&waker);

    match pinned.as_mut().poll(&mut cx) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

#[tokio::main]
async fn main() {
    println!("Starting manual poll demonstration...");

    // Case 1: A future that is immediately ready
    let mut immediate_future = async { 42 };

    // We are in an async context, but inside a standard function logic flow
    match try_poll_wrapper(&mut immediate_future) {
        TryPollResult::Ready(val) => {
            println!("[Sync] Immediate future completed instantly with value: {}", val);
        }
        TryPollResult::Pending => {
            println!("[Sync] Immediate future was pending (unexpected)");
            // Spawn task logic would go here
        }
    }

    // Case 2: A future that is NOT ready immediately (requires yielding)
    let mut delayed_future = async {
        tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
        "Delayed Result"
    };

    match try_poll_wrapper(&mut delayed_future) {
        TryPollResult::Ready(val) => {
            println!("[Sync] Delayed future completed instantly: {}", val);
        }
        TryPollResult::Pending => {
            println!("[Sync] Delayed future is NOT ready yet. Spawning a task to handle it...");

            // Since the future is Unpin (because it's a simple async block without self-references),
            // we can move it into a spawn. 
            // Note: In a real scenario, you might need to Box::pin if the future isn't Unpin,
            // but `tokio::spawn` requires the future to be 'static + Send.

            // We recreate the future for the spawn because the original one was partially polled
            // and might be in an invalid state to be moved if it wasn't Unpin, 
            // BUT since our `delayed_future` is Unpin, we can actually move the *remaining* part
            // if we didn't borrow it mutably in a way that prevents moving. 
            // However, `try_poll_wrapper` took a mutable reference. 
            // To strictly follow the prompt: "spawn a tokio task to await on THE future",
            // we need to ensure ownership. 

            // Approach: Wrap the logic in a function that returns the future, 
            // so we can try_poll one instance, and if pending, create/spawn a new one 
            // OR use a pinned box if we must continue the exact same instance.

            // Let's demonstrate continuing the EXACT same future instance by boxing it.
            let mut boxed_future = Box::pin(async {
                tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
                "Delayed Result (Boxed)"
            });

            // Try poll the boxed version
            let waker = futures::task::noop_waker();
            let mut cx = Context::from_waker(&waker);

            if let Poll::Pending = boxed_future.as_mut().poll(&mut cx) {
                println!("[Sync] Boxed future is pending. Moving it to a spawned task now.");

                // Spawn the task. We need to move `boxed_future` into the async block.
                // Since it's a Box<Pin<...>>, we can move it.
                tokio::spawn(async move {
                    let result = boxed_future.await;
                    println!("[Async Task] Future completed in background with: {}", result);
                });
            }
        }
    }

    // Keep the main thread alive long enough to see the spawned task finish
    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
    println!("Done.");
}
"
}

