/// A custom handler that deletes trailing whitespace before the cursor
/// and inserts a specific character (like '.' or ','), then ensures
/// the cursor is positioned AFTER the inserted character.
struct DotInsertHandler {
    char_to_insert: char,
}

impl DotInsertHandler {
    fn new(c: char) -> Self {
        Self { char_to_insert: c }
    }
}

impl ConditionalEventHandler for DotInsertHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // We only care about the part of the line before the cursor
        let prefix = &line[..pos];

        // Find the index of the last non-whitespace character
        if let Some(last_non_ws_idx) = prefix.rfind(|c: char| !c.is_whitespace()) {
            let whitespace_start = last_non_ws_idx + 1;
            let whitespace_count = pos - whitespace_start;

            if whitespace_count > 0 {
                // Strategy:
                // 1. Move cursor back by the number of whitespace characters.
                // 2. Delete those whitespace characters (BackwardChar count).
                // 3. Insert the new character.
