                //
                // Let's try to construct the command explicitly:
                // We want to delete `whitespace_count` chars to the left and insert `self.char_to_insert`.
                return Some(Cmd::Replace(
                    Movement::BackwardChar(whitespace_count as RepeatCount),
                    Some(self.char_to_insert.to_string()),
