  "main.rs": "// This example demonstrates the solution to the enum_dispatch dependency dilemma.
//
// The Problem:
// enum_dispatch requires the Trait and the Enum to be in the same crate.
// However, you want:
// 1. `al` (Abstract Layer) to hold the Trait.
// 2. `il` (Implementation Layer) to hold the structs (Foo, Boo).
// 3. `bl` (Business Layer) to hold the Enum and logic.
//
// Creating separate crates causes a cycle because `bl` needs `al` (for trait) and `il` (for structs),
// but the Enum in `bl` cannot implement the Trait from `al` without `enum_dispatch` seeing both.
//
// The Solution:
// Create a "Core" crate (simulated here as the root module) that owns BOTH the Trait and the Enum.
// - The Trait is defined here.
// - The Enum is defined here (annotated with #[enum_dispatch]).
// - The `il` layer becomes a dependency that only implements the trait for structs.
// - The `bl` layer uses the Core crate.
//
// In this self-contained file, we simulate the crates using modules:
// - `core_layer`: Acts as the combined `al` + `enum_definition` crate.
// - `impl_layer`: Acts as the `il` crate.
// - `business_layer`: Acts as the `bl` crate.

use enum_dispatch::enum_dispatch;

// ============================================================================
// MODULE: core_layer (Simulates a crate containing Abstract Layer + Enum)
// ============================================================================
mod core_layer {
    use super::impl_layer::{Foo, Boo};
    use enum_dispatch::enum_dispatch;

    // --- Abstract Layer (al) ---

    /// The trait defining network services.
    /// In a real multi-crate setup, this trait and the Item enum below
    /// MUST exist in the same crate (e.g., `my_project_core`).
    #[enum_dispatch]
    pub trait Rest {
        fn get(&self, path: &str) -> String;
        fn post(&self, path: &str, data: &str) -> String;
        // Imagine 18 more methods here...
        fn delete(&self, path: &str) -> bool;
    }

    // --- The Enum Definition ---

    /// The dispatch enum.
    /// Because it is in the same module/crate as the `Rest` trait above,
    /// `enum_dispatch` can automatically generate the implementation.
    /// 
    /// NOTE: We must import the concrete types (Foo, Boo) here so the macro
    /// can verify they implement `Rest`. In a real workspace, this crate
    /// would depend on the `il` crate.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo,
        Boo,
    }
}

// ============================================================================
// MODULE: impl_layer (Simulates the Implementation Layer crate `il`)
// ============================================================================
mod impl_layer {
    use crate::core_layer::Rest;

    pub struct Foo {
        pub name: String,
    }

    pub struct Boo {
        pub id: u32,
    }

    impl Rest for Foo {
        fn get(&self, path: &str) -> String {
            format!("Foo::get on {} at {}", self.name, path)
        }

        fn post(&self, path: &str, data: &str) -> String {
            format!("Foo::post to {} with data: {}", path, data)
        }

        fn delete(&self, path: &str) -> bool {
            println!("Foo deleting {}", path);
            true
        }
    }

    impl Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("Boo::get ID {} at {}", self.id, path)
        }

        fn post(&self, path: &str, data: &str) -> String {
            format!("Boo::post ID {} to {}", self.id, path)
        }

        fn delete(&self, path: &str) -> bool {
            println!("Boo deleting {}", path);
            false
        }
    }
}

// ============================================================================
// MODULE: business_layer (Simulates the Business Layer crate `bl`)
// ============================================================================
mod business_layer {
    // The business layer only depends on the `core_layer`.
    // It does NOT need to know about the concrete structs (Foo, Boo) directly
    // if it only works with the `Item` enum.
    use crate::core_layer::{Item, Rest};
    use crate::impl_layer::{Foo, Boo};

    pub fn run_system() {
        println!("--- Starting Business Logic ---");

        // Instantiate concrete types from the implementation layer
        let foo_instance = Foo { name: "ServiceA".to_string() };
        let boo_instance = Boo { id: 42 };

        // Wrap them in the Enum defined in the core layer
        let item_foo: Item = foo_instance.into();
        let item_boo: Item = boo_instance.into();

        // Use them via static dispatch through the trait
        // The compiler resolves these calls efficiently thanks to enum_dispatch
        process_resource(&item_foo, "/users");
        process_resource(&item_boo, "/logs");

        cleanup_resource(&item_foo, "/temp");
    }

    fn process_resource(resource: &dyn Rest, path: &str) {
        let get_result = resource.get(path);
        let post_result = resource.post(path, "payload");

        println!("[Business] GET Result: {}", get_result);
        println!("[Business] POST Result: {}", post_result);
    }

    fn cleanup_resource(resource: &dyn Rest, path: &str) {
        if resource.delete(path) {
            println!("[Business] Cleanup successful");
        } else {
            println!("[Business] Cleanup failed or not needed");
        }
    }
}

fn main() {
    business_layer::run_system();
}"
}

