  "main.rs": "use rxrust::prelude::*;
use std::cell::RefCell;
use std::convert::Infallible;
use std::rc::Rc;

type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

fn nand(name: String, a: Type, b: Type) -> Type {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |(a, b)| print!("nand {name} ({a}, {b})"))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!(" = {v}"))
        .box_it_clone()
}

fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Use Rc<RefCell> to hold the subjects so they can be shared and mutated
    // without triggering borrow conflicts during synchronous emission.
    let s2_cell: Rc<RefCell<LocalBehaviorSubject<bool, Infallible>>> =
        Rc::new(RefCell::new(Local::behavior_subject(false)));
    let r2_cell: Rc<RefCell<LocalBehaviorSubject<bool, Infallible>>> =
        Rc::new(RefCell::new(Local::behavior_subject(false)));

    // Clone the cells for the closures
    let s2_cell_sub = s2_cell.clone();
    let r2_cell_sub = r2_cell.clone();

    // Create observables from the subjects
    let s2_obs = s2_cell.borrow().clone().box_it_clone();
    let r2_obs = r2_cell.borrow().clone().box_it_clone();

    // Build the NAND gates
    let q1 = nand("s".to_string(), s, s2_obs);
    let q2 = nand("r".to_string(), r, r2_obs);

    // Store subscriptions to keep them alive
    // We use a dummy vec just to hold the subscription objects if needed,
    // but mostly we rely on the closure logic.

    // Subscribe q1 to update r2
    // We must ensure we don't hold a borrow on the RefCell while calling .next()
    q1.clone().subscribe(move |val| {
        // Borrow briefly, call next, then drop the borrow immediately
        r2_cell_sub.borrow().next(val);
    });

    // Subscribe q2 to update s2
    q2.clone().subscribe(move |val| {
        s2_cell_sub.borrow().next(val);
    });

    // Return the output observables (q1 and q2)
    // We need to box them again if they weren't already, but nand returns Type
    (q1.box_it_clone(), q2.box_it_clone())
}

fn main() {
    // Inputs
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q1, q2) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    // Monitor outputs
    q1.combine_latest(q2, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("Output state: (Q1: {q1:?}, Q2: {q2:?})"));

    println!("Initial state (S=true, R=true)");

    println!("\nSetting S to false...");
    s.next(false); // Expect Q1=true, Q2=false

    println!("\nSetting S back to true...");
    s.next(true); // Expect hold state (Q1=true, Q2=false)

    println!("\nSetting R to false...");
    r.next(false); // Expect Q1=false, Q2=true

    println!("\nSetting R back to true...");
    r.next(true); // Expect hold state (Q1=false, Q2=true)
}
