  "main.rs": "use futures_util::StreamExt;
use std::sync::Arc;
use tokio::sync::broadcast::{self, Sender, Receiver, RecvError};
use tokio_stream::wrappers::BroadcastStream;

#[derive(Debug, Clone)]
pub struct Event {
    pub message: String,
}

// We wrap the Sender in an Arc so we can explicitly drop all references
// by clearing the Arc container, rather than relying on scope exit.
#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Arc<Sender<Event>>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        // Ignoring errors here as receivers might have dropped
        let _ = self.tx.send(event);
    }

    // Explicitly close the channel by dropping the underlying sender
    // if this is the last reference, or just removing this reference.
    // To force a shutdown of ALL subscribers, the owner of the master
    // Arc must drop their copy or clear a container holding the master copy.
    pub fn shutdown_signal(&self) {
        println!("Shutdown signal received on sender.");
        // In this pattern, the actual "stop" happens when the master
        // Arc<Sender> is dropped. This method is just a marker.
    }
}

pub struct EventStreamFactory {
    tx: Arc<Sender<Event>>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> BroadcastStream<Event> {
        let rx = self.tx.subscribe();
        BroadcastStream::new(rx)
    }
}

// Helper to create the channel with Arc wrapping
pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel::<Event>(20);
    let tx_arc = Arc::new(tx);

    (
        EventSender { tx: Arc::clone(&tx_arc) },
        EventStreamFactory { tx: tx_arc },
    )
}

#[tokio::main]
async fn main() {
    let (sender, factory) = events_channel();

    // Keep a master copy of the Arc to control the lifecycle.
    // As long as `master_tx` exists, the channel is considered "open"
    // even if `sender` is dropped, because `master_tx` holds a ref.
    let master_tx = sender.tx.clone();

    // Spawn a subscriber task
    let subscriber_handle = tokio::spawn(async move {
        let mut stream = factory.all_events();

        println!("[Subscriber] Waiting for events...");

        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("[Subscriber] Received: {}", event.message),
                Err(RecvError::Lagged(n)) => println!("[Subscriber] Lagged by {} messages", n),
                Err(RecvError::Closed) => {
                    println!("[Subscriber] Stream closed (Sender dropped). Exiting loop.");
                    break;
                }
            }
        }
        println!("[Subscriber] Task finished.");
    });

    // Spawn a sender task to pump some events
    let sender_handle = tokio::spawn(async move {
        for i in 1..=5 {
            sender.send(Event { message: format!("Event #{}", i) }).await;
            tokio::time::sleep(tokio::time::Duration::from_millis(200)).await;
        }
        println!("[Sender] Finished sending events.");
    });

    // Wait for sender to finish
    let _ = sender_handle.await;

    // Simulate an interrupt or shutdown condition
    println!("\n[Main] Triggering shutdown (dropping all Sender references)...");

    // 1. Drop the local `sender` wrapper
    drop(sender);

    // 2. Crucially, drop the `master_tx` Arc we kept at the top level.
    // Once this is dropped, if no other clones exist, the inner `broadcast::Sender`
    // is dropped, causing all `BroadcastStream`s to return `Closed`.
    drop(master_tx);

    // Wait for the subscriber to detect the closure and exit
    let _ = subscriber_handle.await;

    println!("[Main] Application shutdown complete.");
}
"
}

