        transform.rotation = Quat::from_rotation_y(time.elapsed_secs() * 0.5)
            * Quat::from_rotation_x(time.elapsed_secs() * 0.3);
    }
}

fn draw_gizmo(
    gizmos: ResMut<Gizmos>,
    query: Query<&Transform, With<RotatingCube>>,
) {
    // In a real raycaster, `hit.normal` comes from the collision. 
    // Since we don't have physics here, we simulate a hit on the "Front" face (+Z) of the cube.
    // However, the normal must be in WORLD SPACE.

    if let Ok(cube_transform) = query.get_single() {

        // 1. Define the local normal of the face we are hitting (e.g., Front face = +Z)
        let local_normal = Vec3::Z;

        // 2. Transform the local normal to World Space using the cube's rotation.
        // This is crucial: if the cube rotates, the "front" face's normal rotates with it.
        let world_normal = cube_transform.rotation.mul_vec3(local_normal).normalize();

        // 3. Calculate the center of the face in World Space.
        // Cube is 1x1x1, so center is at translation + (rotation * local_offset)
        let local_offset = local_normal * 0.5; // Half unit out from center
        let world_offset = cube_transform.rotation.mul_vec3(local_offset);
        let face_center = cube_transform.translation + world_offset;

        // --- THE MATH SOLUTION ---
        // We need a rotation that:
        // A. Aligns the Gizmo's forward axis (let's say Z) with the `world_normal`.
        // B. Maintains the cube's rotational "twist" so the gizmo doesn't spin arbitrarily around the normal.

        // Approach: 
        // 1. Start with the cube's rotation. This gives us correct X/Y alignment relative to the world.
        // 2. The cube's rotation already points its local +Z to `world_normal` (because we derived normal from it).
        // 3. However, `Quat::from_rotation_arc` creates a rotation from identity. 
        //    If we just use the cube's rotation, the gizmo (which draws a rect on XY plane usually) 
        //    might be oriented incorrectly depending on how `gizmos.rect` defines its plane.

        // Let's assume `gizmos.rect` draws on the XY plane of the transform, meaning Z is the normal.
        // If the cube's Z axis is aligned with the face normal, then `cube_transform.rotation` IS the answer,
        // PROVIDED the gizmo's local Z axis corresponds to the face normal.

        // BUT, often we want the gizmo to align specifically. 
        // The robust way to combine them when you have a specific target normal and a reference up/right:

        // Let's construct the basis manually to be safe and clear.
        // We know the Normal (Z axis of our gizmo).
        let gizmo_z = world_normal;

        // We need an Up vector. We can take the Cube's Up vector (transformed Y) and project it onto the plane perpendicular to Normal.
        // This ensures the gizmo stays aligned with the cube's edges.
        let cube_up_raw = cube_transform.rotation.mul_vec3(Vec3::Y);

        // Gram-Schmidt process to make sure gizmo_y is perpendicular to gizmo_z
        let gizmo_y = (cube_up_raw - gizmo_z * cube_up_raw.dot(gizmo_z)).normalize();

        // Cross product to get X
        let gizmo_x = gizmo_y.cross(gizmo_z);

        // Construct Rotation Matrix -> Quaternion
        let mut basis = Mat3::IDENTITY;
        basis.x_axis = gizmo_x;
        basis.y_axis = gizmo_y;
        basis.z_axis = gizmo_z;

        let final_rotation = Quat::from_mat3(&basis);

        // Draw the gizmo slightly offset from the face
        let offset_pos = face_center + world_normal * 0.02;

        gizmos.rect(
            Transform::from_translation(offset_pos)
                .with_rotation(final_rotation),
            Vec2::new(0.8, 0.8),
            Color::WHITE,
        );

        // Debug: Draw the normal vector to verify calculation
        gizmos.arrow(face_center, face_center + world_normal * 0.5, Color::GREEN);
    }
}
