    ///
    /// To answer Q2 (modifying both): Since the relationship is symmetric (distance i->j == j->i),
    /// we can record the pair (i, j) and update both i.nb and j.nb.
    pub fn build_lists_parallel(&mut self) {
        let n = self.elems.len();
        let cutoff = self.cutoff;

        // We use a Mutex<Vec<Vec<usize>>> to collect neighbors safely from parallel threads.
        // Alternatively, we could collect a list of pairs (i, j) and process them sequentially,
        // but updating a pre-allocated vector of vectors via Mutex is often efficient enough for this pattern.
        // However, a finer-grained approach is to use a Mutex for each element's neighbor list? 
