struct PointProps {
    initial_x: f64,
    initial_y: f64,
    draggable: bool,
    r: f64,
}

#[component]
fn Point(props: PointProps) -> Element {
    // Local state for this specific point
    let mut coords = use_signal(|| ElementPoint::new(props.initial_x, props.initial_y));
    let mut is_dragging_this = use_signal(|| false);

    // Access global drag state from context
    let drag_state = use_context::<DragState>();
    let global_mouse = drag_state.mouse_position;
    let global_is_dragged = drag_state.is_dragged;

    // This effect runs whenever signals accessed inside change.
    // It acts as the "custom event" mechanism:
    // When global_mouse updates, this effect checks if we should update local coords.
    use_effect(move || {
        // If this point isn't currently being dragged, do nothing
        if !*is_dragging_this.read() {
            return;
        }

        // If the global mouse button is released, stop dragging this point
        if !*global_is_dragged.read() {
            is_dragging_this.set(false);
            return;
        }

        // Update local coordinates to match global mouse position
        // We use .read() here to track dependency, but .peek() or direct access works too 
        // since we are inside an effect triggered by the signal change.
        let current_mouse = *global_mouse.read();

        // Only update if changed to avoid unnecessary cycles (though Signal handles deduping mostly)
        if *coords.read() != current_mouse {
            coords.set(current_mouse);
        }
    });

    let handle_mouse_down = move |_| {
        if props.draggable {
            is_dragging_this.set(true);
            // Ensure global state knows we are dragging immediately
            // (In case the global listener missed the exact frame or for logic consistency)
            drag_state.is_dragged.set(true);
        }
    };

