    fn new(json_input: String) -> Result<Self, serde_json::Error> {
        // First, deserialize borrowing from the input string
        // We must ensure the input string doesn't move during this scope if we were just referencing it,
        // but we are going to move it into the struct.

        // Trick: We deserialize first, then move the string into the struct.
        // But the references would point to the temporary argument `json_input`.
        // That's a dangling pointer risk if we just do:
        // let data: MyData = from_str(&json_input)?;
        // Self { _buffer: json_input, data } -> DATA POINTS TO DROPPED ARGUMENT.

        // SAFE PATTERN:
        // 1. Heap allocate the String so its address is stable.
        // 2. Get a reference to it.
        // 3. Deserialize using that reference.
        // 4. Construct the struct taking ownership of the Box/String.
        // 5. Transmute the lifetime of the result to 'static because the struct
        //    now owns the buffer and guarantees it lives as long as the data.

        let box_str = Box::new(json_input);
        let str_ref: &str = &box_str;

        // Deserialize borrowing from the boxed string
        let data_borrowed: MyData<'_> = serde_json::from_str(str_ref)?;

        // Safety: 
        // 1. `box_str` is moved into `_buffer` field of `OwnedMyData`.
        // 2. As long as `OwnedMyData` exists, `_buffer` exists and is not moved.
        // 3. Therefore, the references inside `data_borrowed` (which point to `_buffer`'s content)
        //    remain valid for the lifetime of `OwnedMyData`.
        // 4. We extend the lifetime of `data` to 'static to allow storing it in the struct
        //    without a self-referential lifetime parameter (which Rust doesn't support directly).
        //    This is safe because we never allow access to `data` without the guarantee 
        //    that the struct (and thus `_buffer`) is still alive.
        let data_static: MyData<'static> = unsafe {
            std::mem::transmute::<MyData<'_>, MyData<'static>>(data_borrowed)
        };

        Ok(Self {
            _buffer: *box_str, // Move string out of box into struct
            data: data_static,
        })
    }

    fn get_data(&self) -> &MyData<'_> {
        &self.data
    }
}

#[derive(Deserialize, Debug, Clone)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

#[tokio::main]
async fn main() {
    // Simulate incoming JSON
    let json_payload = r#"{
        "data": "hello world",
        "more_data": "foo bar baz"
    }"#.to_string();

    // Deserialize once into our self-referential wrapper
    let owned_data = OwnedMyData::new(json_payload).expect("Failed to deserialize");

    // Wrap in Arc to share across tasks. 
    // Arc<OwnedMyData> is Send + Sync.
    let shared_data = Arc::new(owned_data);

    let (tx, mut rx) = mpsc::channel::<Arc<OwnedMyData>>(10);

    // Spawn a producer task
    let producer_data = shared_data.clone();
    let handle1 = tokio::spawn(async move {
        println!("Task 1: Sending data...");
        // We send the Arc, not the data itself. No cloning of the string content occurs.
        tx.send(producer_data).await.unwrap();
    });

    // Spawn a consumer task
    let handle2 = tokio::spawn(async move {
        if let Some(data_wrapper) = rx.recv().await {
            // Access the borrowed data safely
            let inner = data_wrapper.get_data();
            println!("Task 2: Received data without cloning strings!");
            println!("  data: {}", inner.data);
            println!("  more_data: {}", inner.more_data);

            // Verify they are borrowed (pointers) not owned copies by checking logic
            // (In a real app, you'd process these slices directly)
        }
    });

    // Wait for tasks to complete
    let _ = tokio::join!(handle1, handle2);

    // When `shared_data` (the last Arc) is dropped, the String and the references drop together.
    println!("Done. Memory cleaned up safely.");
}
