  "main.rs": "use itertools::Itertools;

/// Splits a shell command string into tokens, respecting single quotes.
///
/// Logic:
/// 1. Split by single quotes `'`. 
///    - Even indices (0, 2, ...) are unquoted regions.
///    - Odd indices (1, 3, ...) are quoted regions.
/// 2. Process unquoted regions: Group consecutive characters by whether they are whitespace.
///    This separates words from the spaces between them.
/// 3. Process quoted regions: Treat the entire region as a single unit (preserving internal spaces).
/// 4. Flatten the list of segments.
/// 5. Group consecutive non-space segments together. 
///    (This handles the case where a quoted string is immediately adjacent to a word, e.g., `'a'b`).
/// 6. Join the segments in each group to form the final token.
/// 7. Filter out any tokens that are purely whitespace.
fn tokenize(s: &str) -> Vec<String> {
    s.split('\'')
     .enumerate()
     .flat_map(|(i, segment)| {
         if i % 2 == 0 {
             // Unquoted: Split by whitespace boundaries, keeping the delimiters
             // We group by `is_whitespace`. 
             // Result: Vec<Vec<char>>
             segment
                 .chars()
                 .chunk_by(|c| c.is_whitespace())
                 .into_iter()
                 .map(|(_, group)| group.collect::<Vec<char>>())
                 .collect::<Vec<Vec<char>>>()
         } else {
             // Quoted: Keep the whole segment as one unit, even if it contains spaces
             vec![segment.chars().collect::<Vec<char>>()]
         }
     })
     .chunk_by(|chars| !chars.iter().all(|c| c.is_whitespace()))
     .into_iter()
     .filter_map(|(is_non_space, group)| {
         if !is_non_space {
             return None; // Skip pure whitespace groups
         }
         // Flatten the group of char-vecs into a single string
         let token: String = group
             .into_iter()
             .flatten()
             .collect();

         // Final safety check: ensure the token isn't empty or just spaces
         if token.trim().is_empty() {
             None
         } else {
             Some(token)
         }
     })
     .collect()
}

fn main() {
    let input = " one  ' two  'three    four";
    println!("Input: {}", input);

    let tokens = tokenize(input);

    println!("{} args:", tokens.len());
    for token in tokens {
