    /// - Adding Acquire/Release on the inner load/store is redundant because the CS boundaries
    ///   enforce the ordering relative to code outside the CS.
    fn get_next_index(&self) -> usize {
        critical_section::with(|_cs| {
            // Load current value. Relaxed is safe because we hold the lock.
            let old_val = self.channel_index.load(Ordering::Relaxed);

            // Calculate new value
            let new_val = old_val + 1;

            // Store new value. Relaxed is safe because we hold the lock.
            // No other actor can see an intermediate state.
            self.channel_index.store(new_val, Ordering::Relaxed);

            old_val
        })
    }
}

