use rustyline::error::ReadlineError;
use rustyline::highlight::{Highlighter, MatchingBracketHighlighter};
use rustyline::hint::{Hinter, HistoryHinter};
use rustyline::validate::{MatchingBracketValidator, Validator};
use rustyline::{Cmd, CompletionType, Config, Context, DefaultEditor, EditMode, Editor, EventHandler, Helper, KeyCode, KeyEvent, Modifiers, Result};

/// A custom Helper that combines filename completion with basic highlighting and validation.
///
/// To enable tab-completion, we must implement the `Helper` trait (or a combination of
/// `Completer`, `Hinter`, `Highlighter`, `Validator`). The `Editor::set_helper` method
/// expects a type that implements `Helper`.
#[derive(Helper)]
struct MyHelper {
    /// Delegates actual completion logic to FilenameCompleter
    completer: FilenameCompleter,
    /// Provides bracket matching highlighting
    highlighter: MatchingBracketHighlighter,
    /// Provides optional hints from history
    hinter: HistoryHinter,
    /// Validates matching brackets
    validator: MatchingBracketValidator,
}

impl Completer for MyHelper {
    type Candidate = Pair;

    fn complete(
        &self,
        line: &str,
        pos: usize,
        ctx: &Context<'_>,
    ) -> Result<(usize, Vec<Pair>)> {
        // Delegate to the filename completer
        self.completer.complete(line, pos, ctx)
    }
}

impl Hinter for MyHelper {
    type Hint = String;

    fn hint(&self, line: &str, pos: usize, ctx: &Context<'_>) -> Option<Self::Hint> {
        self.hinter.hint(line, pos, ctx)
    }
}

impl Highlighter for MyHelper {
    fn highlight_prompt<'b, 's: 'b, 'p: 'b>(
        &'s self,
        prompt: &'p str,
        default: bool,
    ) -> Cow<'b, str> {
        self.highlighter.highlight_prompt(prompt, default)
    }

    fn highlight_hint<'h>(&self, hint: &'h str) -> Cow<'h, str> {
        self.highlighter.highlight_hint(hint)
    }

    fn highlight<'l>(&self, line: &'l str, pos: usize) -> Cow<'l, str> {
        self.highlighter.highlight(line, pos)
    }

    fn highlight_char(&self, line: &str, pos: usize, forced: bool) -> bool {
        self.highlighter.highlight_char(line, pos, forced)
    }
}

impl Validator for MyHelper {
    fn validate(&self, ctx: &mut rustyline::validate::ValidationContext) -> Result<rustyline::validate::ValidationResult> {
        self.validator.validate(ctx)
    }
}

fn main() -> Result<()> {
    // Configure the editor to use Tab for completion explicitly (though it's often default)
    let config = Config::builder()
        .completion_type(CompletionType::List)
        .edit_mode(EditMode::Emacs)
        .build();

    let mut rl: Editor<MyHelper, _> = Editor::with_config(config)?;

    // Initialize our custom helper with a FilenameCompleter
    let helper = MyHelper {
        completer: FilenameCompleter::new(),
        highlighter: MatchingBracketHighlighter::new(),
        hinter: HistoryHinter::new(),
        validator: MatchingBracketValidator::new(),
    };

    // Register the helper. This is the key step to enable tab-completion.
    rl.set_helper(Some(helper));

    // Optional: Bind Tab key explicitly to complete action if not working by default
    rl.bind_sequence(
        KeyEvent::new(KeyCode::Tab, Modifiers::NONE),
        EventHandler::Simple(Cmd::Complete),
    );

    #[cfg(feature = "with-file-history")]
    if rl.load_history("history.txt").is_err() {
