    let c_name = std::ffi::CString::new(shm_name.as_str()).unwrap();

    let fd = unsafe {
        shm_open(c_name.as_ptr(), libc::O_CREAT | libc::O_RDWR, 0o600)
    };

    if fd == -1 {
