  "main.rs": "use expectrl::{session::Session, spawn, Eof, NotMatched};
use serde::Serialize;
use std::{
    io::{Read, Write},
    sync::Arc,
    time::Duration,
};
use tokio::sync::{mpsc, Mutex};

/// Mock Tauri Event Payload
#[derive(Serialize, Clone, Debug)]
struct EventPayload {
    event: String,
    data: String,
}

/// The Agent struct no longer wraps Session in a Mutex.
/// Instead, it owns the Session and runs a dedicated async task
/// that handles both reading and writing via channels.
/// This eliminates the Read-Write deadlock entirely.
pub struct Agent {
    /// Channel to send keystrokes/commands INTO the agent
    input_tx: mpsc::UnboundedSender<String>,
    /// Handle to the background task (optional, for cleanup)
    _handle: tokio::task::JoinHandle<()>,
}

impl Agent {
    pub async fn new(command: &str) -> Result<Self, Box<dyn std::error::Error>> {
        // Spawn the PTY session
        let mut session = spawn(command)?;

        // Configure PTY for interactive use (raw mode usually handled by spawn,
        // but ensuring we don't block indefinitely on read is key).
        session.set_input_timeout(Duration::from_millis(100))?;

        // Create channels for internal communication
        let (input_tx, mut input_rx) = mpsc::unbounded_channel::<String>();
        let (output_tx, mut output_rx) = mpsc::unbounded_channel::<String>();

        // Spawn the single-owner background task
        // This task owns `session` exclusively. No Mutex needed.
        let handle = tokio::task::spawn(async move {
            let mut buf = [0u8; 1024];

            loop {
                // We use tokio::select! to concurrently wait for:
                // 1. Data coming from the frontend (via input_rx)
                // 2. Data coming from the PTY (via session.read)

                tokio::select! {
                    // Handle Incoming Input from Frontend
                    Some(data) = input_rx.recv() => {
                        // Write directly to the session. 
                        // Since we own the session in this task, no lock is needed.
                        if let Err(e) = session.write_all(data.as_bytes()) {
                            eprintln!("Write error: {}", e);
                            break;
                        }
                        // Flush is often important for interactive CLIs
                        let _ = session.flush();
                    },

                    // Handle Incoming Output from PTY
                    res = session.read_async(&mut buf) => {
                        match res {
                            Ok(n) => {
                                if n == 0 {
                                    let _ = output_tx.send("[Process Terminated]".to_string());
                                    break;
                                }
                                let output = String::from_utf8_lossy(&buf[..n]).to_string();
                                // In a real app, emit to Tauri here
                                // For this demo, we print to stdout prefixed
                                print!("{}", output);

                                // Also send to channel if we needed to forward to UI thread
                                let _ = output_tx.send(output);
                            },
                            Err(e) => {
                                // Handle timeout or Eof
                                if e.kind() == std::io::ErrorKind::TimedOut {
                                    // Timeout is expected when no output is available.
                                    // We loop back immediately to check for new input.
                                    continue;
                                }
                                eprintln!("Read error: {}", e);
                                break;
                            }
                        }
                    }
                }
            }
        });

        // Drain the output channel just to keep the stream alive in this demo
        // In Tauri, you wouldn't drain here; the `session.write` above is the critical part.
        tokio::task::spawn(async move {
            while let Some(msg) = output_rx.recv().await {
                // In real Tauri: app.emit("agent-output", msg)
                // We already printed in the loop above for immediate feedback
            }
        });

        Ok(Self {
            input_tx,
            _handle: handle,
        })
    }

    /// Non-blocking send. 
    /// Since we just push to a channel, this returns immediately 
    /// regardless of whether the PTY is reading or writing.
    pub fn send(&self, data: &str) -> Result<(), Box<dyn std::error::Error>> {
        self.input_tx.send(data.to_string())?;
        Ok(())
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting Interactive PTY Demo (Fix for Mutex Deadlock)");
    println!("Spawning /bin/bash...");
    println!("Type commands below. They will be sent to the PTY without blocking reads.");
    println!("--------------------------------------------------");

    // 1. Initialize Agent
    let agent = Agent::new("/bin/bash").await?;

    // 2. Create a task to read user input from STDIN and forward to Agent
    // This simulates the Tauri Command `send_to_agent`
    let agent_clone = agent.clone(); // Agent needs to be Clone or Arc'd if used in multiple places, 
                                     // but for this single-threaded async main, we can just move reference or use Arc.
                                     // Let's wrap agent in Arc for safety in this specific demo structure.

    let agent_arc = Arc::new(agent);
    let agent_reader = agent_arc.clone();

    // Task: Read from Terminal (STDIN) and forward to PTY
    let stdin_handle = tokio::task::spawn_blocking(move || {
        let mut input = String::new();
        let stdin = std::io::stdin();

        loop {
            input.clear();
            // Blocking read on STDIN is okay here because it's a separate thread
            // and the Agent's internal logic is non-blocking.
            if stdin.read_line(&mut input).is_err() {
                break;
            }

            // Simulate sending to Tauri Command -> Agent
            // Note: We append \n because read_line keeps it, but sometimes 
            // xterm sends raw chars. For bash, \n is usually expected.
            if let Err(e) = agent_reader.send(&input) {
                eprintln!("Failed to send to agent: {}", e);
                break;
