        }
    });

    // Keep the main async runtime alive
    stdin_handle.await?;

    Ok(())
}

// Note: To make `Agent` cloneable for the demo above, we implement it manually 
// since mpsc::UnboundedSender is Clone.
impl Clone for Agent {
    fn clone(&self) -> Self {
        Self {
            input_tx: self.input_tx.clone(),
