// Helper extension for expectrl Session to make it async-friendly with timeouts
// expectrl 0.7.1 doesn't have native `read_async` that returns immediately on timeout 
// without configuration, so we rely on `set_input_timeout` and standard read behavior 
// inside the tokio::select! which works well because the read will return Err(TimedOut) quickly.
// However, standard `session.read` is blocking. 
// To make this truly non-blocking in Tokio without blocking a thread pool worker excessively,
// we should wrap the blocking read in `tokio::task::spawn_blocking` OR use expectrl's async features if available.
// 
// CORRECTION FOR STANDALONE COMPATIBILITY:
// expectrl's `Session` implements `Read`. Calling `read` directly in `tokio::select` 
// will block the async thread if not careful. 
// The robust pattern for expectrl + tokio is to run the Read loop in a `spawn_blocking` task
// that communicates via channels, OR use `set_input_timeout` and accept that `read` blocks 
// for a very short duration (the timeout value).
//
// Below is a corrected `Agent::new` implementation that uses `spawn_blocking` for the 
// read/write loop to ensure the async runtime never stalls, which is the production-ready fix.

mod production_pattern {
    use super::*;
    use std::io::{Read, Write};
    use tokio::sync::mpsc;

    pub struct AgentProd {
        input_tx: mpsc::UnboundedSender<String>,
    }

    impl AgentProd {
        pub fn new(command: &str) -> Result<Self, Box<dyn std::error::Error>> {
            let mut session = spawn(command)?;
            // Set a very short timeout so the read loop can check for incoming messages frequently
            session.set_input_timeout(Duration::from_millis(50))?;

            let (input_tx, input_rx) = mpsc::unbounded_channel::<String>();

            // Move the session into a blocking thread. 
            // This is the safest way to handle blocking I/O libraries with Tokio.
            std::thread::spawn(move || {
                let mut input_rx = input_rx;
                let mut buf = [0u8; 1024];

                loop {
                    // Check for input first (non-blocking check roughly)
                    // Since we are in a thread, we can do a try_recv or timeout recv
                    // But to keep it simple and responsive, we prioritize Read with a timeout.

                    // Attempt to read with timeout (configured in session)
                    match session.read(&mut buf) {
                        Ok(n) => {
                            if n == 0 { break; }
                            let out = String::from_utf8_lossy(&buf[..n]);
                            print!("{}", out); // Emit to UI
                        },
                        Err(e) => {
                            if e.kind() != std::io::ErrorKind::TimedOut {
                                eprintln!("Error: {}", e);
                                break;
                            }
                            // Timeout occurred, loop back to check input channel
                        }
                    }

                    // Now check for pending input from the frontend
                    // We drain all available input to catch up quickly
                    while let Ok(data) = input_rx.try_recv() {
                        let _ = session.write_all(data.as_bytes());
                        let _ = session.flush();
                    }
                }
            });

            Ok(Self { input_tx })
        }

        pub fn send(&self, data: &str) -> Result<(), Box<dyn std::error::Error>> {
            self.input_tx.send(data.to_string())?;
            Ok(())
        }
    }
}

// Re-alias Agent to the production pattern for the main function to use the most robust version
// This ensures the demo works perfectly without blocking the async runtime.
type Agent = production_pattern::AgentProd;
"
}

