struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("a struct representing enum B")
    }

    fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
    where
        V: MapAccess<'de>,
    {
        if let Some(key) = map.next_key::<&str>()? {
            match key {
                "VariantOne" => {
                    let value: String = map.next_value()?;
                    // Ensure no extra fields
                    if map.next_key::<&str>()?.is_some() {
                        return Err(de::Error::duplicate_field("extra_field"));
                    }
                    Ok(B::VariantOne(value))
                }
                "VariantTwo" => {
                    let value: u32 = map.next_value()?;
                    if map.next_key::<&str>()?.is_some() {
                        return Err(de::Error::duplicate_field("extra_field"));
                    }
