  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

// Example context structure
pub struct Context(i32);

// The enum holding the boxed trait object.
// We use a helper trait 'AsyncBlock' to avoid the complex nested closure syntax
// and to allow us to constrain the Send bound correctly on the future.
pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<dyn FnOnce(&mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>>>,
    },
}

// Helper trait to normalize the async closure into a concrete Future type
// that we can box and send.
trait AsyncBlock: Send {
    fn call_once(self: Box<Self>, ctx: &mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>>;
}

// Implementation for any closure that satisfies the bounds.
// F: The closure itself (impl AsyncFnOnce equivalent)
// Fut: The future returned by the closure
impl<F, Fut> AsyncBlock for F
where
    F: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    fn call_once(self: Box<Self>, ctx: &mut Context) -> Pin<Box<dyn Future<Output = ()> + Send>> {
        // Call the closure to get the future, then box and pin it.
        // Since Fut: Send + 'static, the resulting Box<dyn Future + Send> is valid.
        Box::pin((*self)(ctx))
    }
}

/// Nicely wraps an async closure and sends it to the worker channel.
/// 
/// This accepts a standard async closure (or any function returning a Future)
/// and handles the boxing/pinning internally.
pub fn with_context_async<F, Fut>(
    work_sender: &mpsc::Sender<InnerAsyncEvent>,
    block: F,
) -> Result<(), mpsc::error::SendError<InnerAsyncEvent>>
where
    F: FnOnce(&mut Context) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    // Box the closure as our helper trait object
    let boxed_block: Box<dyn AsyncBlock> = Box::new(block);

    // Wrap it in the event enum, converting the trait object to the raw function pointer
    // expected by InnerAsyncEvent.
    let event = InnerAsyncEvent::DoWithContext {
        block: Box::new(|ctx| boxed_block.call_once(ctx)),
    };

    work_sender.send(event)
}

#[tokio::main]
async fn main() {
    // Create a channel to send work items
    let (tx, mut rx) = mpsc::channel::<InnerAsyncEvent>(10);

    // Spawn the worker thread/task
    let worker = tokio::spawn(async move {
        while let Some(event) = rx.recv().await {
            let mut ctx = Context(0);
            println!("Worker: Received event, initial context value: {}", ctx.0);

            match event {
                InnerAsyncEvent::DoWithContext { block } => {
                    // Execute the boxed future
                    let fut = block(&mut ctx);
                    fut.await;
                }
            }
            println!("Worker: Work complete, final context value: {}", ctx.0);
        }
        println!("Worker: Channel closed, shutting down.");
    });

    // --- Usage Example 1: Simple async closure ---
    println!("Main: Sending task 1...");
    let res = with_context_async(&tx, |ctx| async move {
        println!("Task 1: Sleeping...");
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        ctx.0 += 10;
        println!("Task 1: Added 10 to context.");
    });

    if let Err(e) = res {
        eprintln!("Failed to send task 1: {}", e);
    }

    // --- Usage Example 2: Closure capturing variables ---
    println!("Main: Sending task 2...");
    let multiplier = 5;
    let res = with_context_async(&tx, move |ctx| async move {
        println!("Task 2: Using captured multiplier {}", multiplier);
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        ctx.0 *= multiplier;
        println!("Task 2: Multiplied context by {}.", multiplier);
    });

    if let Err(e) = res {
        eprintln!("Failed to send task 2: {}", e);
    }

    // Drop sender to signal completion
    drop(tx);

    // Wait for worker to finish
    worker.await.unwrap();
    println!("Main: All done!");
}
