use rustyline::completion::Completer as CompleterTrait;
use std::borrow::Cow;

// A simple helper to satisfy the Editor type requirements
#[derive(Completer, Helper, Hinter, Validator)]
struct MyHelper;

impl Highlighter for MyHelper {
    fn highlight_hint<'h>(&self, hint: &'h str) -> Cow<'h, str> {
        Cow::Borrowed(hint)
    }
}

/// Custom Event Handler to insert a character while consuming preceding whitespace
/// and ensuring the cursor ends up *after* the inserted character.
struct InsertCharHandler {
    insert: String,
}

impl InsertCharHandler {
    fn new(insert: char) -> Self {
        Self {
            insert: insert.to_string(),
        }
    }
}

impl ConditionalEventHandler for InsertCharHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Look at the text before the cursor
        let prefix = &line[..pos];

        // Find the index of the last non-whitespace character
        if let Some(last_non_ws_idx) = prefix.rfind(|c: char| !c.is_whitespace()) {
            let whitespace_start = last_non_ws_idx + 1;
            let whitespace_count = pos - whitespace_start;

            if whitespace_count > 0 {
                // Strategy:
                // 1. Move cursor backward over the whitespace.
                // 2. Delete the whitespace (effectively moving to the position of the last non-ws char + 1).
                // 3. Insert the new character.
                //
                // In rustyline, Cmd::Replace(Movement::BackwardChar(n), Some(str)) 
                // deletes 'n' characters backward and inserts 'str'. 
                // The cursor naturally lands after the inserted string.

                return Some(Cmd::Replace(
                    Movement::BackwardChar(whitespace_count as RepeatCount),
                    Some(self.insert.clone()),
                ));
            }
        }

        // If no preceding whitespace to consume, just insert normally.
        // We still use Replace with count 0 to ensure consistent behavior or fallback to default.
        // Actually, returning None here lets rustyline handle the default insertion, 
        // which places the cursor correctly for a standard insert.
        None
    }
}

fn main() -> Result<()> {
    let mut rl: Editor<MyHelper, rustyline::history::DefaultHistory> = Editor::new()?;
    rl.set_helper(Some(MyHelper));

    // Bind '.' and ',' to our custom handler
    let dot_event = KeyEvent::new('.', rustyline::Modifiers::NONE);
    let comma_event = KeyEvent::new(',', rustyline::Modifiers::NONE);

    rl.bind_sequence(
        dot_event,
        EventHandler::Conditional(Box::new(InsertCharHandler::new('.'))),
    );

    rl.bind_sequence(
        comma_event,
        EventHandler::Conditional(Box::new(InsertCharHandler::new(','))),
    );

