use chrono::{DateTime, FixedOffset, NaiveDateTime, Utc};

/// Converts a LanceDB ISO string (with optional fractional seconds) to a unix timestamp (i64).
///
/// LanceDB often returns timestamps in ISO 8601 format. The challenge is that the fractional
/// seconds part (e.g., `.409`) is optional. Standard `chrono` parsing requires a fixed format.
///
/// Strategy:
/// 1. Attempt to parse with fractional seconds first.
/// 2. If that fails, attempt to parse without fractional seconds.
/// 3. Since the input string lacks timezone info (e.g., 'Z' or '+00:00'), we assume UTC.
pub fn date_string_to_int(d: &str) -> Result<i64> {
    // Format with fractional seconds (up to 9 digits, but .f handles variable length if present in strict mode)
    // Note: parse_from_str is strict. We will try two specific formats.
    let format_with_frac = "%Y-%m-%dT%H:%M:%S%.f";
    let format_without_frac = "%Y-%m-%dT%H:%M:%S";

    let naive_dt = NaiveDateTime::parse_from_str(d, format_with_frac)
        .or_else(|_| NaiveDateTime::parse_from_str(d, format_without_frac))
        .with_context(|| format!("Failed to parse date string: {}", d))?;

    // Assume UTC since the string has no offset information
    let utc_dt: DateTime<Utc> = DateTime::from_naive_utc_and_offset(naive_dt, Utc);

    Ok(utc_dt.timestamp())
}

/// Alternative robust approach using manual string manipulation to normalize the format
/// before parsing. This can be safer if the fractional seconds vary wildly in length.
pub fn date_string_to_int_robust(d: &str) -> Result<i64> {
    // If there is no decimal point, parse as simple ISO
    if !d.contains('.') {
        let naive_dt = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S")
            .with_context(|| format!("Failed to parse date string: {}", d))?;
        let utc_dt: DateTime<Utc> = DateTime::from_naive_utc_and_offset(naive_dt, Utc);
        return Ok(utc_dt.timestamp());
    }

    // If there is a decimal point, ensure we handle the fractional part correctly.
    // chrono's %.f expects the dot to be there if the format includes it, but sometimes
    // splitting and reconstructing is clearer for variable precision.
    // Actually, parse_from_str with "%.f" usually works for variable length fractions 
    // IF the fraction exists. The error in the user prompt "NotEnough" often implies 
    // the parser expected more digits or the format string didn't match the optional nature.

    // Let's stick to the try-two-formats approach which is idiomatic for optional parts in chrono.
    date_string_to_int(d)
}

