  "main.rs": "use futures::future::FutureExt;
use futures::task::{waker_ref, ArcWake, Context, Poll};
use std::future::Future;
use std::sync::Arc;
use tokio::runtime::Handle;

/// A simple waker that does nothing when woken.
/// This is safe to use for a single synchronous poll attempt because
/// if the future returns Pending, we simply abandon this poll cycle
/// and spawn a real task with a real waker.
struct NoopWaker;

impl ArcWake for NoopWaker {
    fn wake_by_ref(_arc_self: &Arc<Self>) {
        // Intentionally left empty. 
        // If the future panics or expects to be woken, that's a logic error in the caller's usage pattern.
    }
}

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future once synchronously.
/// 
/// If the future completes immediately, returns TryPollResult::Ready.
/// If the future yields (returns Pending), returns TryPollResult::Pending.
///
/// Safety/Context: This uses a NoopWaker. This is valid ONLY if you are prepared
/// to handle the Pending case by spawning the future into an executor (which provides
/// a real waker) or dropping it. You cannot call this repeatedly in a loop expecting
/// progress without a real executor.
fn try_poll<X>(future: &mut impl Future<Output = X>) -> TryPollResult<X> {
    let waker = waker_ref(&Arc::new(NoopWaker));
    let mut context = Context::from_waker(&waker);

    // Safety: We are pinning the future mutably on the stack for the duration of this call.
    // Since `future` is `&mut`, it cannot move during this function call.
    let pinned_future = unsafe { std::pin::Pin::new_unchecked(future) };

    match pinned_future.poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// A helper future that resolves immediately if `immediate` is true,
// otherwise it sleeps for a short duration (forcing a Pending state on first poll).
async fn conditional_future(immediate: bool, val: i32) -> i32 {
    if !immediate {
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
    }
    val
}

/// A non-async function that attempts to evaluate a future synchronously.
fn process_future_sync(mut fut: impl Future<Output = i32> + Send + 'static) {
    println!("[Sync Function] Attempting to poll future synchronously...");

    match try_poll(&mut fut) {
        TryPollResult::Ready(value) => {
            println!("[Sync Function] Future completed immediately! Value: {}", value);
            // Use the value directly here
            println!("[Sync Function] Processing immediate value: {}", value * 2);
        }
        TryPollResult::Pending => {
            println!("[Sync Function] Future is pending. Spawning task to await it...");

            // Spawn a task to handle the rest of the future's lifecycle
            tokio::spawn(async move {
                // Now we can safely await because we are in an async context/task
                let value = fut.await;
                println!("[Spawned Task] Future completed in background! Value: {}", value);
                println!("[Spawned Task] Processing deferred value: {}", value * 2);
            });
        }
    }
}

#[tokio::main]
async fn main() {
    println!("=== Scenario 1: Future resolves immediately ===");
    // Create a future that resolves immediately
    let fut_immediate = conditional_future(true, 42);
    process_future_sync(fut_immediate);

    // Give tokio a moment to flush prints if any background tasks were spawned (none expected here)
    tokio::time::sleep(tokio::time::Duration::from_millis(50)).await;

    println!("\n=== Scenario 2: Future requires awaiting ===");
    // Create a future that will sleep (return Pending on first poll)
    let fut_deferred = conditional_future(false, 99);
    process_future_sync(fut_deferred);

    // Wait long enough for the spawned task to complete so we see the output before exit
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;

    println!("\nDone.");
}
"
}

