impl Agent {
    pub fn spawn(command: &str, args: &[&str]) -> Result<Self, Box<dyn std::error::Error>> {
        // 1. Spawn the PTY session
        let mut session = Session::spawn(command, args)?;

        // 2. Duplicate the File Descriptor (FD)
        // The Session owns the master FD. We need a second FD that points to the same
        // underlying kernel object so we can read and write concurrently without locking.
        //
        // Safety: `as_fd()` gives us a borrowed reference. `dup()` creates a new owned FD.
        // We must ensure the original session stays alive (which it does in this scope).
        let raw_fd = session.master().as_fd().as_raw_fd();
        let dup_fd = dup(raw_fd)?;

        // 3. Create independent Read and Write streams from the duplicated FD
        // We convert the raw int back into a Rust File-like object.
        // Note: In a real app, you'd wrap this in `std::fs::File::from` or similar safe abstractions.
        // Here we use raw pointers for demonstration of the concept with `nix`.
        use std::os::unix::io::FromRawFd;
        let reader_file = unsafe { std::fs::File::from_raw_fd(dup_fd) };
        let mut reader = std::io::BufReader::new(reader_file);

        // For writing, we keep using the original `session` object, but we will move it
        // to a dedicated writer thread to avoid contention with the main thread or Tauri commands.

        // 4. Setup Channels for Communication
        let (write_tx, write_rx) = bounded::<String>(100);
        let (output_tx, output_rx) = bounded::<String>(100);

        // 5. Spawn the Reader Thread
        // This thread blocks on read() but holds NO mutex that the writer needs.
        thread::spawn(move || {
            let mut buf = [0u8; 1024];
            loop {
                match reader.read(&mut buf) {
                    Ok(0) => {
                        let _ = output_tx.send("[Process Ended]".to_string());
                        break;
                    }
                    Ok(n) => {
                        let chunk = String::from_utf8_lossy(&buf[..n]).to_string();
                        if output_tx.send(chunk).is_err() {
                            break; // Receiver dropped
                        }
                    }
                    Err(e) => {
                        eprintln!("Read error: {}", e);
                        break;
                    }
                }
            }
        });

        // 6. Spawn the Writer Thread
        // This thread owns the `session` exclusively. It receives strings from the channel
        // and writes them to the PTY. No mutex required.
        thread::spawn(move || {
            while let Ok(data) = write_rx.recv() {
                if let Err(e) = session.send(&data) {
                    eprintln!("Write error: {}", e);
                    break;
                }
            }
            // Optional: Wait for process to exit cleanly if needed
            // let _ = session.wait().unwrap();
        });

        Ok(Self {
            write_tx,
            output_rx,
        })
    }

