    store: Vec<T>,
    dims: Vec<usize>,
    strides: Vec<usize>,
}

impl<T> Array<T> {
    pub fn new(dims: Vec<usize>, data: Vec<T>) -> Self {
        assert_eq!(dims.iter().product::<usize>(), data.len(), "Dimension mismatch");
        let mut strides = vec![1; dims.len()];
        for i in (0..dims.len() - 1).rev() {
            strides[i] = strides[i + 1] * dims[i + 1];
        }
        Self { store: data, dims, strides }
    }

    fn get_index(&self, indices: &[usize]) -> usize {
        indices.iter().zip(self.strides.iter()).map(|(i, s)| i * s).sum()
    }

    pub fn get(&self, indices: &[usize]) -> &T {
        &self.store[self.get_index(indices)]
    }

    pub fn get_mut(&mut self, indices: &[usize]) -> &mut T {
        let idx = self.get_index(indices);
        &mut self.store[idx]
    }
}

