unsafe impl<'a, T: Send> Send for ArrayIteratorFromDynMut<'a, T> {}
unsafe impl<'a, T: Sync> Sync for ArrayIteratorFromDynMut<'a, T> {}

impl<'a, T> ArrayIteratorFromDynMut<'a, T> {
