    pub entry_name: String,
}

/// System: Watches for PendingWadLoad components, reads the archive metadata,
/// and spawns the actual WadTexture asset if not already loaded.
pub fn lazy_wad_loading_system(
    mut commands: Commands,
    archives: Res<Assets<WadArchive>>,
    mut textures: ResMut<Assets<WadTexture>>,
    query: Query<(Entity, &PendingWadLoad)>,
    asset_server: Res<AssetServer>,
) {
    for (entity, pending) in query.iter() {
        // 1. Check if the archive is loaded
        let archive = match archives.get(&pending.archive_handle) {
            Some(a) => a,
            None => continue, // Archive not ready yet, wait for next frame
