            };

            let handle = textures.add(texture);

            // Attach the loaded handle to the entity or replace the marker
            commands.entity(entity).insert(handle);
            commands.entity(entity).remove::<PendingWadLoad>();

            info!("Lazy loaded texture: {} from archive", pending.entry_name);
        } else {
            warn!("Entry {} not found in archive", pending.entry_name);
            commands.entity(entity).remove::<PendingWadLoad>();
        }
    }
}

