  "main.rs": "use anyhow::{Context, Result};
use std::env;
use std::fs;
use std::path::PathBuf;
use std::process::Command;

// The content of the Python script is embedded directly into the binary at compile time.
// This ensures the script is always available and packaged with the executable.
const PYTHON_SCRIPT_CONTENT: &str = r#"
import sys
import os

def main():
    print("Hello from the embedded Python script!")
    print(f"Python executable: {sys.executable}")
    print(f"Arguments received: {sys.argv[1:]}")

    # Example logic: create a temp file to prove execution
    script_dir = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
    print(f"Script running in context of: {script_dir}")

if __name__ == "__main__":
    main()
"#;

fn main() -> Result<()> {
    // 1. Determine a path to store the temporary script.
    // We use the OS temp directory to ensure write permissions.
    let temp_dir = env::temp_dir();
    let script_file_name = "rust_program_embedded_script.py";
    let script_path = temp_dir.join(script_file_name);

    // 2. Write the embedded script content to the temporary file.
    // This effectively "packages" the script by extracting it at runtime.
    fs::write(&script_path, PYTHON_SCRIPT_CONTENT)
        .with_context(|| format!("Failed to write embedded script to {:?}", script_path))?;

    // 3. Locate the Python interpreter.
    // We use the 'which' crate logic (or fallback to standard lookup) to find 'python3' or 'python'.
    let python_exe = which::which("python3")
        .or_else(|_| which::which("python"))
        .with_context(|| "Could not find 'python3' or 'python' in PATH. Please ensure Python is installed.")?;

    // 4. Invoke the Python interpreter with the path to the temporary script.
    // We pass any command-line arguments received by the Rust program to the Python script.
    let mut cmd = Command::new(python_exe);
    cmd.arg(&script_path);

    // Forward arguments from the Rust CLI to the Python script
    let args: Vec<String> = env::args().skip(1).collect();
    if !args.is_empty() {
        cmd.args(&args);
    }

    let status = cmd.status()
        .with_context(|| format!("Failed to execute Python interpreter at {:?}", python_exe))?;

    if !status.success() {
        anyhow::bail!("Python script exited with error code: {}", status);
    }

    // Optional: Clean up the temporary file after execution
    let _ = fs::remove_file(&script_path);

    Ok(())
}"
}

