/// Splits a shell command string into tokens, respecting single quotes.
///
/// Logic:
/// 1. Split the string by single quotes `'`.
/// 2. Even indices (0, 2, ...) are unquoted regions: split by whitespace groups, keeping non-space groups.
/// 3. Odd indices (1, 3, ...) are quoted regions: treat the whole segment as a single token content.
/// 4. Flatten and collect the resulting tokens.
fn tokenize(s: &str) -> Vec<String> {
    s.split('\'')
        .enumerate()
        .flat_map(|(i, segment)| {
            if i % 2 == 0 {
                // Unquoted: split by whitespace sequences, keep non-empty non-space tokens
                segment
                    .split(|c: char| c.is_whitespace())
                    .filter(|s| !s.is_empty())
                    .map(|s| s.to_string())
                    .collect::<Vec<_>>()
            } else {
                // Quoted: keep the segment exactly as is (including internal spaces)
                vec![segment.to_string()]
            }
        })
        .collect()
}

fn main() {
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("{} args:", tokens.len());
    for token in tokens {
        println!("<{token}>");
    }
}
