const BYTES_PER_PIXEL: usize = 4;

/// Flips a single line of 4-byte pixels horizontally.
/// 
/// This implementation uses `copy_nonoverlapping` to swap 4-byte chunks.
/// On modern compilers (LLVM/Rust), this typically compiles down to efficient
/// wide loads/stores (e.g., MOV on x86, LDR/STR on ARM) or even SIMD instructions
/// when unrolled or vectorized, which is ideal for embedded targets like Raspberry Pi.
/// 
/// It avoids the overhead of four individual byte swaps per pixel while maintaining
/// safety through explicit bounds checks (via debug_assert) and non-overlapping guarantees.
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0, "Line length must be a multiple of pixel size");

    let len = line_bytes.len();
    if len == 0 {
        return;
    }

    let mut left = 0;
    let mut right = len - BYTES_PER_PIXEL;

    // We swap pixels from the outside in until the pointers meet or cross
    while left < right {
        unsafe {
            // Create a temporary buffer to hold one pixel during the swap
            let mut temp = [0u8; BYTES_PER_PIXEL];

            let src_left = line_bytes.as_ptr().add(left);
            let src_right = line_bytes.as_ptr().add(right);
            let dst_left = line_bytes.as_mut_ptr().add(left);
            let dst_right = line_bytes.as_mut_ptr().add(right);

            // Copy right pixel to temp
            std::ptr::copy_nonoverlapping(src_right, temp.as_mut_ptr(), BYTES_PER_PIXEL);
            // Copy left pixel to right position
            std::ptr::copy_nonoverlapping(src_left, dst_right, BYTES_PER_PIXEL);
            // Copy temp (original right) to left position
            std::ptr::copy_nonoverlapping(temp.as_ptr(), dst_left, BYTES_PER_PIXEL);
