        // and use that as our reference for "Up" relative to the new normal.
        // However, a simpler robust way is:
        // 1. Define the desired Forward = Normal.
        // 2. Define a reference Right or Up from the cube, projected onto the plane perpendicular to Normal.

        let cube_up = cube_rot * Vec3::Y;
        let cube_right = cube_rot * Vec3::X;

        // Project cube's up onto the plane defined by the normal to find the new "Up"
