        // We recurse into children. The current_path acts as the prefix.
        for sub_tree in list.use_trees() {
            // Clone path for the branch so siblings don't interfere
            process_use_tree(editor, &sub_tree, current_path.clone());
        }
    } else {
        // This is a leaf node (or the end of a specific branch).
        // Attempt to rewrite the full accumulated path.
        attempt_rewrite(editor, tree, &current_path);
    }
