                        break; // Receiver dropped, stop thread
                    }
                }
            }
        }

        // If loop finishes (EOF or break), check flag again
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }
    }
}

fn yield_signals(sender: Sender<Message>, stop_flag: Arc<AtomicBool>) {
    use signal_hook::consts::{SIGINT, SIGTERM};
    use signal_hook::iterator::Signals;

    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    for sig in signals.forever() {
        if stop_flag.load(Ordering::Relaxed) {
            break;
        }

        let msg = match sig {
            SIGINT => Message::Signal("SIGINT"),
            SIGTERM => Message::Signal("SIGTERM"),
            _ => continue,
        };

        if sender.send(msg).is_err() {
            // Receiver dropped, stop thread
            break;
        }
    }
}

fn main() {
    let (sender, receiver) = mpsc::channel::<Message>();
    let stop_flag = Arc::new(AtomicBool::new(false));
    let flag_clone_keys = Arc::clone(&stop_flag);
    let flag_clone_signals = Arc::clone(&stop_flag);

    // Spawn signal listener
    thread::spawn(move || {
        yield_signals(sender, flag_clone_signals);
    });

    // Spawn key listener
    thread::spawn(move || {
        yield_keys(sender, flag_clone_keys);
    });

    println!("Listening for events. Press 'q' to quit, or Ctrl+C.");

    // Event Loop
    for msg in receiver.iter() {
        match msg {
            Message::KeyPressed(c) => {
                println!("Key pressed: {}", c);
                if c == 'q' {
                    println!("Quit requested.");
                    // 1. Set the stop flag so other threads know to exit their loops
                    stop_flag.store(true, Ordering::Relaxed);

                    // 2. Break the main loop. 
                    // IMPORTANT: Breaking here drops `receiver`.
                    // When `receiver` is dropped, any subsequent `sender.send()` in the 
                    // worker threads will return `Err`, causing them to break their infinite loops.
                    break;
                }
            }
            Message::Signal(sig) => {
                println!("Received signal: {}", sig);
                stop_flag.store(true, Ordering::Relaxed);
                break;
            }
            Message::Quit => {
                stop_flag.store(true, Ordering::Relaxed);
                break;
            }
        }
    }

    println!("Event loop finished. Waiting for threads to clean up...");

    // Optionally join threads if we kept their handles, but since they break on send() error,
    // they will terminate shortly. The process will exit naturally.
    thread::sleep(Duration::from_millis(200)); // Small delay to let threads print/exit cleanly
    println!("Program exited gracefully.");
}
"
}

