/// This allows us to generate deterministic pseudo-random numbers at compile time
/// without relying on external crates that don't support const contexts yet.
///
/// Parameters chosen from Numerical Recipes (simple, fast, sufficient for Zobrist).
const fn lcg_next(state: u64) -> u64 {
    // LCG parameters: a = 6364136223846793005, c = 1442695040888963407
    state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407)
}

/// Generates the Zobrist keys array at compile time.
const fn generate_zobrist_seeds(seed: u64) -> [u64; 781] {
    let mut result = [0u64; 781];
    let mut state = seed;
    let mut i = 0;

    while i < 781 {
        state = lcg_next(state);
        result[i] = state;
        i += 1;
    }

    result
}

