// Implementation Layer (il)
// ==========================================
// In a real setup, this is the `il` crate depending on `al`.

pub struct Foo;
pub struct Boo;

impl Rest for Foo {
    fn get_data(&self) -> String {
        "Foo GET".to_string()
    }
    fn post_data(&self, data: &str) -> String {
        format!("Foo POST: {}", data)
    }
}

impl Rest for Boo {
    fn get_data(&self) -> String {
        "Boo GET".to_string()
    }
    fn post_data(&self, data: &str) -> String {
        format!("Boo POST: {}", data)
    }
}

// ==========================================
// Business Layer (bl)
// ==========================================
// In a real setup, this is the `bl` crate depending on `al` and `il`.
//
// THE SOLUTION:
// Instead of defining the enum in the `al` crate (which forces `al` to know 
// about `il` types or requires merging crates), we define the dispatch Enum 
// HERE in the business layer (or a glue layer).
//
// We use the #[enum_dispatch(Rest)] attribute on the Enum. 
// The `enum_dispatch` crate allows the Enum to be in a different crate 
// than the Trait, provided the Trait is in scope and the Enum is annotated.
// The constraint is that the *implementations* (Foo, Boo) must be visible 
// where the Enum is defined so the macro can generate the match arms.

#[enum_dispatch(Rest)]
pub enum Item {
    Foo(Foo),
    Boo(Boo),
}

fn main() {
    // Create concrete instances from the implementation layer
    let foo_instance = Foo;
    let boo_instance = Boo;

    // Wrap them in the Business Layer Enum
    // This achieves static dispatch without the BL needing to 
    // manually write 20 match arms for every trait method.
    let items: Vec<Item> = vec![
        Item::from(foo_instance),
        Item::from(boo_instance),
