        // These calls are statically dispatched (near zero overhead)
        // despite iterating over a collection of different types.
        println!("{}", item.get_data());
        println!("{}", item.post_data("payload"));
        println!("---");
    }

    println!("Success: No circular dependency required!");
    println!("- 'al' defines the trait.");
    println!("- 'il' implements the trait.");
    println!("- 'bl' defines the Enum and uses enum_dispatch to bridge them.");
