  "main.rs": "use chrono::{DateTime, FixedOffset, NaiveDateTime, Utc};
use anyhow::{Result, Context};

/// Parses LanceDB ISO strings which may or may not have fractional seconds.
/// LanceDB often outputs formats like "2025-08-02T17:35:41.409" or "1970-01-01T00:00:00".
/// The standard `parse_from_str` fails if the format string expects fractions but none exist,
/// or vice-versa, unless handled dynamically.
fn parse_lancedb_date(date_str: &str) -> Result<DateTime<Utc>> {
    // Strategy: Try parsing with fractional seconds first. If that fails due to format mismatch,
    // try without fractional seconds. 
    // Note: We use NaiveDateTime first because the input string usually lacks timezone info (UTC implied by Lance/Arrow).

    let formats_with_frac = [
        "%Y-%m-%dT%H:%M:%S%.f",
        "%Y-%m-%d %H:%M:%S%.f",
    ];

    let formats_without_frac = [
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%d %H:%M:%S",
    ];

    // Try formats with fractional seconds
    for fmt in &formats_with_frac {
        if let Ok(ndt) = NaiveDateTime::parse_from_str(date_str, fmt) {
            return Ok(ndt.and_utc());
        }
    }

    // Try formats without fractional seconds
    for fmt in &formats_without_frac {
        if let Ok(ndt) = NaiveDateTime::parse_from_str(date_str, fmt) {
            return Ok(ndt.and_utc());
        }
    }

    anyhow::bail!("Failed to parse date string: {}", date_str)
}

fn date_string_to_int(d: &str) -> Result<i64> {
    let dt = parse_lancedb_date(d)?;
    Ok(dt.timestamp())
}

