  "main.rs": "use nalgebra::{DMatrix, DVector, DimName, Const, GenericArray};

fn main() {
    // Create a sample 3x2 matrix (3 rows, 2 columns)
    // Row 0: [1.0, 4.0]
    // Row 1: [2.0, 5.0]
    // Row 2: [3.0, 6.0]
    let mut matrix = DMatrix::from_row_slice(3, 2, &[1.0, 4.0, 2.0, 5.0, 3.0, 6.0]);

    println!("Original Matrix:");
    println!("{}\n", matrix);

    // Step 1: Compute the mean of each column.
    // `column_mean()` returns a DVector of length `ncols` (k).
    let means = matrix.column_mean();
    println!("Column Means: {:?}\n", means);

    // Step 2: Subtract the mean from every column.
    // Nalgebra does not have implicit broadcasting for binary operators like `-` between
    // a Matrix and a Vector. We must iterate over columns or use `map_mut`.
    //
    // Approach: Iterate over each column index, get the mutable column view,
    // and subtract the scalar mean for that specific column.

    for i in 0..matrix.ncols() {
        let mean_val = means[i];
        // `column_mut(i)` gives a mutable view of the i-th column.
        // We can subtract a scalar from the entire column view directly.
        matrix.column_mut(i).add_assign(-mean_val);
    }

    println!("Centered Matrix (Column Means should be ~0):");
    println!("{}", matrix);

    // Verification: Recompute means to ensure they are close to 0.0
    let new_means = matrix.column_mean();
    println!("\nNew Column Means (Verification): {:?}", new_means);
}"
