/// expected by `InnerAsyncEvent`.
trait AsyncFnOnceWrapper<Ctx>: Send {
    fn call_once_pinned(
        self,
        ctx: &mut Ctx,
    ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>>;
