// - The closure itself is Send + 'static
impl<Ctx, F, Fut> AsyncFnOnceWrapper<Ctx> for F
where
    F: FnOnce(&mut Ctx) -> Fut + Send + 'static,
    Fut: Future<Output = ()> + Send + 'static,
{
    fn call_once_pinned(
        self,
        ctx: &mut Ctx,
    ) -> Pin<Box<dyn Future<Output = ()> + Send + '_>> {
        // Call the closure to get the future
        let future = self(ctx);
        // Pin and box it. Since Fut is 'static, this is safe to cast to '_
        Box::pin(future) as Pin<Box<dyn Future<Output = ()> + Send + '_>>
    }
