    fn raw_clone(_: *const ()) -> RawWaker {
        raw_waker()
    }
    fn raw_wake(_: *const ()) {}
    fn raw_wake_by_ref(_: *const ()) {}
    fn raw_drop(_: *const ()) {}

    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        raw_clone,
        raw_wake,
        raw_wake_by_ref,
        raw_drop,
    );

    unsafe { Waker::from_raw(raw_waker()) }
}

fn raw_waker() -> RawWaker {
    const VTABLE: RawWakerVTable = RawWakerVTable::new(
        |_: *const ()| raw_waker(),
        |_: *const ()| {},
        |_: *const ()| {},
        |_: *const ()| {},
    );
    unsafe { RawWaker::new(std::ptr::null(), &VTABLE) }
}

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

/// Attempts to poll a future once.
/// If it returns Ready, we return the value.
/// If it returns Pending, we return Pending.
fn try_poll<X>(future: &mut Pin<&mut dyn Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut context = Context::from_waker(&waker);

    match future.as_mut().poll(&mut context) {
        Poll::Ready(val) => TryPollResult::Ready(val),
        Poll::Pending => TryPollResult::Pending,
    }
}

// A helper to box the future so we can pass it as a trait object to try_poll
fn try_poll_boxed<X>(mut future: Pin<Box<dyn Future<Output = X>>>) -> (TryPollResult<X>, Pin<Box<dyn Future<Output = X>>>) {
    let result = try_poll(future.as_mut());
    (result, future)
}

#[tokio::main]
async fn main() {
    println!("Starting manual poll demo...");

    // Case 1: A future that is already ready (immediate)
    let immediate_future = Box::pin(async { 42 });
    let (res, mut remaining_future) = try_poll_boxed(immediate_future);

    match res {
        TryPollResult::Ready(val) => {
            println!("Case 1 (Immediate): Future completed synchronously! Value: {}", val);
        }
        TryPollResult::Pending => {
            println!("Case 1 (Immediate): Unexpectedly pending.");
            // In a real app, we would spawn here
            tokio::spawn(async move {
                let val = remaining_future.await;
                println!("Case 1 Spawned: {}", val);
            });
        }
    }

    // Case 2: A future that must yield (not ready immediately)
    // We use yield_now() to guarantee it returns Pending on the first poll
    let delayed_future = Box::pin(async {
        tokio::task::yield_now().await;
        100
    });

    let (res, mut remaining_future) = try_poll_boxed(delayed_future);

    match res {
        TryPollResult::Ready(val) => {
            println!("Case 2 (Delayed): Future completed synchronously! Value: {}", val);
        }
        TryPollResult::Pending => {
            println!("Case 2 (Delayed): Future is pending. Spawning a task to handle it.");

            // Spawn a task to await the future
            let handle = Handle::current();
            handle.spawn(async move {
                let val = remaining_future.await;
                println!("Case 2 Spawned: Future completed asynchronously! Value: {}", val);
            });
        }
    }

    // Give the spawned task time to run before exiting
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    println!("Demo complete.");
}
"
