use rustyline::validate::Validator;
use rustyline::{
    Cmd, ConditionalEventHandler, Event, EventContext, EventHandler, KeyEvent, Movement,
    RepeatCount, Editor, Helper, Result,
};
use rustyline::completion::{Completer, FilenameCompleter};
use rustyline::history::DefaultHistory;

/// A custom event handler that deletes preceding whitespace before inserting
/// a specific character (like '.' or ',') and ensures the cursor ends up AFTER
/// the inserted character.
struct WhitespaceReplacingHandler {
    insert_char: char,
}

impl WhitespaceReplacingHandler {
    fn new(c: char) -> Self {
        Self { insert_char: c }
    }
}

impl ConditionalEventHandler for WhitespaceReplacingHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Look at the text before the cursor
        let prefix = &line[..pos];

        // Find the index of the last non-whitespace character
        if let Some(last_non_ws_idx) = prefix.rfind(|c: char| !c.is_whitespace()) {
            let whitespace_start = last_non_ws_idx + 1;
            let whitespace_len = pos - whitespace_start;

            if whitespace_len > 0 {
                // We found whitespace immediately before the cursor.
                // Strategy:
                // 1. Move cursor backward over the whitespace.
                // 2. Delete the whitespace.
                // 3. Insert the new character.
                //
                // Cmd::Replace(Movement::BackwardChar(n), Some(string)) replaces the n characters
                // before the cursor with the string. The cursor naturally lands after the replacement.

                let movement = Movement::BackwardChar(whitespace_len as RepeatCount);
                let replacement = self.insert_char.to_string();

                return Some(Cmd::Replace(movement, Some(replacement)));
            }
        }

        // If no preceding whitespace, just insert the character normally.
        // Cmd::Insert(1, string) inserts the string at the current cursor position.
        Some(Cmd::Insert(1, self.insert_char.to_string()))
    }
}

