use tokio::sync::Mutex;

/// This example demonstrates how to solve the "blocking read holds mutex" problem
/// in a Tauri + expectrl setup.
///
/// THE PROBLEM:
/// If you wrap the Session in an Arc<Mutex<Session>> and have one thread blocking on
/// session.read() while holding the lock, any other thread trying to session.write()
/// will block forever waiting for the lock.
///
/// THE SOLUTION:
/// 1. Do NOT share the Session object directly between threads via a Mutex.
/// 2. Instead, duplicate the underlying File Descriptor (FD) using `dup()`.
/// 3. Create two independent File objects from the FDs.
/// 4. Use one File for a dedicated Reader Thread (blocking read is fine here).
/// 5. Use the other File for a Writer Channel (send writes to a single owner thread
///    or use the independent File handle directly if the OS supports concurrent R/W on the same FD).
///
/// Note: On macOS/Linux, reading and writing to the same PTY FD from different threads
/// is generally safe at the OS level, but Rust's Session struct is not Sync/Send safe
/// for concurrent method calls. Duplicating the FD gives us two distinct File handles
/// that can be owned by separate threads without needing a Mutex around the IO operations.

struct PtyHandle {
    write_tx: Sender<String>,
    _reader_thread: thread::JoinHandle<()>,
    _writer_thread: thread::JoinHandle<()>,
}

impl PtyHandle {
    pub fn new(mut session: Session) -> Result<Self, Box<dyn std::error::Error>> {
        // 1. Get the raw FD from the session's PTY master
        // Note: expectrl::Session wraps a PtyMaster which implements AsRawFd
        let raw_fd = session.pty().as_raw_fd();

        // 2. Duplicate the FD. Now we have two references to the same underlying PTY.
        // We need to prevent `session` from closing the original FD when it goes out of scope
        // if we were to move it, but here we will consume `session` to extract the FD.
        // Actually, simpler approach: Just dup the FD immediately.
        let reader_fd = dup(raw_fd)?;
        let writer_fd = dup(raw_fd)?;

        // We no longer need the original session object if we are managing FDs manually,
        // but we must ensure it doesn't close the FD prematurely. 
        // In this pattern, we usually let the original session drop, but since we dup'd,
        // the kernel refcount keeps the PTY open. 
        // HOWEVER, expectrl Session might do cleanup on drop. 
        // Safer pattern: Keep the session alive or extract the internal file.
        // Let's extract the internal file if possible, or just rely on the dup'd fds
        // and drop the session (which closes one ref, but our dup'd refs keep it open).
        drop(session); 

        // 3. Create independent File handles from the duplicated FDs
        let mut reader_file = unsafe { File::from_raw_fd(reader_fd) };
        let mut writer_file = unsafe { File::from_raw_fd(writer_fd) };

        // 4. Create a channel for write requests to serialize writes if needed,
        // or simply pass the file to a writer thread.
        let (write_tx, write_rx): (Sender<String>, Receiver<String>) = bounded(100);

        // --- READER THREAD ---
        // This thread blocks on read indefinitely. It does NOT hold a mutex.
        let _reader_thread = thread::spawn(move || {
            let mut buf = [0u8; 1024];
            loop {
                match reader_file.read(&mut buf) {
                    Ok(0) => {
                        eprintln!("[PTY] EOF received");
                        break;
                    }
                    Ok(n) => {
                        let output = String::from_utf8_lossy(&buf[..n]);
                        // In Tauri, you would emit an event here: app.emit("agent-output", output)
                        print!("{}", output); // Simulating frontend output
                        std::io::stdout().flush().ok();
                    }
                    Err(e) => {
                        eprintln!("[PTY] Read error: {}", e);
                        break;
                    }
                }
            }
        });

        // --- WRITER THREAD ---
        // This thread handles all writes. It owns the writer_file exclusively.
        // No mutex contention with the reader.
        let _writer_thread = thread::spawn(move || {
            while let Ok(data) = write_rx.recv() {
                if let Err(e) = writer_file.write_all(data.as_bytes()) {
                    eprintln!("[PTY] Write error: {}", e);
                    break;
                }
                if let Err(e) = writer_file.flush() {
                    eprintln!("[PTY] Flush error: {}", e);
                    break;
                }
            }
        });

        Ok(PtyHandle {
            write_tx,
            _reader_thread,
            _writer_thread,
        })
    }

    pub fn send(&self, data: &str) -> Result<(), flume::SendError<String>> {
        self.write_tx.send(data.to_string())
    }
