    // the expected output must be independent of 'e (e.g. owned data).

    // If the user's Cons<'e> holds references to the interner, the expected_output
    // MUST be created using the same interner instance to be equal (pointer equality).
    // Therefore, we pass a closure that receives the `symbol_interner` and `filename` 
    // (or the whole state) and returns the ExOut.

    mut parser: P,
    expected_factory: impl FnOnce(&SymbolInterner, &'i str) -> ExOut,
) where
    // P must be a parser for ANY lifetime 'e (HRTB)
    // The Output type of P depends on 'e. We don't name it POut.
    for<'e> P: ModalParser<SStream<'i, 'e>, ContextError>,
    // The Output type associated with P for a specific 'e must be comparable to ExOut.
    // We use a where clause that projects the associated type.
    // Note: Syntax for associated type bounds with lifetimes in HRTB is tricky.
    // We might need to rely on inference inside the function body.

    // Constraint: The output of parsing (which has lifetime 'e) must be PartialEq with ExOut.
    // Since ExOut is created inside the function using 'e resources, it can also effectively
    // be treated as having 'e (or being compatible).

    // We relax the bounds and let the body enforce the logic.
    ExOut: Debug,
    // We need to assert that <P as ModalParser<...>>::Output implements PartialEq<ExOut>
    // This must hold for the specific 'e used in the body.
    // Since we can't easily write `for<'e> <P as ...>::Output<'e>: PartialEq<ExOut>` 
    // if ExOut doesn't depend on 'e, but here ExOut IS created from 'e resources.

    // Actually, the cleanest way in modern Rust is to not constrain POut in the WHERE clause
    // but let the usage in the function body drive the inference, provided the HRTB on P is correct.
    // The error the user got was because they tried to name POut as a generic param 'static-ish
    // while it actually varies with 'e.
{
    let symbol_interner = SymbolInterner::new();
    let filename_interner = FilenameInterner::new();
    let filename = filename_interner.intern("<test>");

    let mut stateful = SStream {
        input: LocatingSlice::new(input),
        state: State {
            filename,
            symbol_interner: &symbol_interner,
        },
    };

    // Parse
    // The type of `parsed` is <P as ModalParser<SStream<'i, 'e>, _>>::Output
    // where 'e is the lifetime of `symbol_interner`.
    let parsed = match parser.parse(&mut stateful) {
        Ok(parsed) => parsed,
        Err(e) => {
            panic!(
                "Failed on:\n\tinput: {input:?}\n\terror: {e:?}"
            )
        }
    };

    // Create expected output using the SAME interners so references match
    let expected_output = expected_factory(&symbol_interner, filename);

    eprintln!("Testing:\n\tinput: {input:?}");

    // This comparison works because both `parsed` and `expected_output` 
    // contain references valid for the lifetime of this function scope ('e).
    assert_eq!(parsed, expected_output);
}

