",
  "main.rs": "use anyhow::Result;
use opentelemetry::{global, trace::TraceContextExt, Context, KeyValue};
use opentelemetry_otlp::WithExportConfig;
use opentelemetry_sdk::{trace, runtime};
use std::time::Duration;
use tokio::time::sleep;
use tracing::{info, instrument, Level, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, Registry};

/// Simulates the common context passed between Pingora stages.
/// In a real app, this would hold request metadata, headers, etc.
#[derive(Clone)]
struct RequestContext {
    // We store the Context (which contains the OTel Span) to rehydrate later.
    // This is the key to solving the "thread hop" or "async boundary" issue.
    otel_context: Option<Context>,
    request_id: String,
}

impl RequestContext {
    fn new(request_id: String) -> Self {
        Self {
            otel_context: None,
            request_id,
        }
    }

    /// Captures the current tracing/OTel context into this struct.
    /// Call this at the very beginning of the request lifecycle.
    fn capture_context(&mut self) {
        self.otel_context = Some(Context::current());
        info!(request_id = %self.request_id, "Context captured at start of lifecycle");
    }

    /// Rehydrates the stored context, making it the "current" context for this scope.
    /// This ensures that any spans created inside this guard become children of the
    /// original parent span, even if executed on a different thread or later in time.
    fn enter_context(&self) -> Option<ContextGuard> {
        self.otel_context.as_ref().map(|ctx| {
            let guard = ctx.attach();
            info!(request_id = %self.request_id, "Context rehydrated");
            ContextGuard(guard)
        })
    }
}

/// A RAII guard to ensure the context is detached when the function/stage returns.
struct ContextGuard(opentelemetry::ContextGuard);

impl Drop for ContextGuard {
    fn drop(&mut self) {
        // Automatically detaches the context when dropped
    }
}

/// Simulates Pingora Stage 1
async fn stage_process_headers(ctx: &RequestContext) -> Result<()> {
    // Rehydrate the context before doing work
    let _guard = ctx.enter_context();

    // Create a span for this specific stage. 
    // Because we rehydrated, this will automatically be a child of the Root Span.
    let span = tracing::span!(Level::INFO, "stage_process_headers");
    let _enter = span.enter();

    info!("Processing HTTP headers...");
    sleep(Duration::from_millis(50)).await;

    Ok(())
}

/// Simulates Pingora Stage 2 (e.g., Upstream selection)
async fn stage_select_upstream(ctx: &RequestContext) -> Result<()> {
    let _guard = ctx.enter_context();

    let span = tracing::span!(Level::INFO, "stage_select_upstream");
    let _enter = span.enter();

    info!("Selecting upstream backend...");
    sleep(Duration::from_millis(30)).await;

    // Simulate calling an async upstream function that might lose context without rehydration
    call_upstream_service(ctx).await?;

    Ok(())
}

/// Simulates an external upstream call
async fn call_upstream_service(ctx: &RequestContext) -> Result<()> {
    let _guard = ctx.enter_context();

    let span = tracing::span!(Level::INFO, "upstream_request");
    let _enter = span.enter();

    info!("Sending request to upstream...");
    sleep(Duration::from_millis(100)).await;
    info!("Received response from upstream");

    Ok(())
}

#[tokio::main]
async fn main() -> Result<()> {
    // 1. Initialize OpenTelemetry Tracer
    let tracer = opentelemetry_otlp::new_pipeline()
        .tracing()
        .with_exporter(
            opentelemetry_otlp::new_exporter()
                .tonic()
                .with_endpoint("http://localhost:4317"), // Default OTLP endpoint
        )
        .with_trace_config(
            trace::config().with_resource(opentelemetry_sdk::Resource::new(vec![
                KeyValue::new("service.name", "pingora-proxy-demo"),
            ])),
        )
        .install_batch(runtime::Tokio)?;

    // 2. Initialize Tracing Subscriber with OTel Layer and Console Layer
    // The Console layer allows you to see the hierarchy in stdout even if OTLP collector is missing
    let telemetry = tracing_opentelemetry::layer().with_tracer(tracer);
    let fmt_layer = tracing_subscriber::fmt::layer()
        .with_target(false)
        .with_thread_ids(true)
        .with_file(false)
        .with_line_number(false);

    let subscriber = Registry::default()
        .with(telemetry)
        .with(fmt_layer)
        .with(tracing_subscriber::EnvFilter::try_from_default_env()
            .unwrap_or_else(|_| "info".into()));

    tracing::subscriber::set_global_default(subscriber)?;

    info!("Starting Pingora Proxy Simulation...");

    // Simulate an incoming request
    let request_id = "req-12345".to_string();
    let mut ctx = RequestContext::new(request_id.clone());

    // --- START OF REQUEST LIFECYCLE ---

    // Create the Root Span for the entire request
    let root_span = tracing::span!(Level::INFO, "request_lifecycle", request_id = %request_id);
    let _root_enter = root_span.enter();

    // Capture the context immediately while inside the root span
    ctx.capture_context();

    // Simulate Tokio/Pingora calling stage functions asynchronously.
    // In a real scenario, these might happen in different tasks or threads.

    // Stage 1
    stage_process_headers(&ctx).await?;

    // Simulate some gap or logic where context might be lost if not stored
    sleep(Duration::from_millis(10)).await;

    // Stage 2
    stage_select_upstream(&ctx).await?;

    // --- END OF REQUEST LIFECYCLE ---

    info!("Request lifecycle complete");

    // Ensure all spans are flushed
    global::shutdown_tracer_provider();

    Ok(())
}
"
}

