  "main.rs": "use serde::Deserialize;
use std::sync::Arc;
use tokio::sync::mpsc;

// The struct with borrowed data
#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// A container that owns the String and holds a reference to the parsed data.
// We use a raw pointer trick to tie the lifetime of the reference to the owned String
// within the same allocation, allowing us to send it across threads safely.
struct OwnedMyData {
    _owner: String,
    // This pointer is safe to dereference as long as `OwnedMyData` exists,
    // because `_owner` guarantees the string data survives.
    data_ptr: *const MyData<'static>,
}

impl OwnedMyData {
    fn new(json_input: String) -> Result<Self, serde_json::Error> {
        // Deserialize into a struct borrowing from the string.
        // We explicitly tie the lifetime of the borrow to the local `json_input`.
        let parsed: MyData<'_> = serde_json::from_str(&json_input)?;

        // Safety: We are transmuting the lifetime of the reference to 'static.
        // This is safe ONLY because we store the `String` (_owner) in the same struct.
        // As long as `OwnedMyData` is alive, `_owner` is alive, so the pointers inside `parsed` are valid.
        // We prevent external access to the raw pointer without going through this struct.
        let static_ref: &'static MyData<'static> = unsafe { std::mem::transmute(parsed) };

        Ok(Self {
            _owner: json_input,
            data_ptr: static_ref,
        })
    }

    fn get(&self) -> &MyData<'_> {
        // Safety: We know the data pointed to is valid because `_owner` is still held by `self`.
        unsafe { &*self.data_ptr }
    }
}

// Ensure OwnedMyData can be sent across threads.
// Safety: Since `OwnedMyData` owns the String that the pointer references,
// moving the struct moves both the owner and the pointer together.
// No other thread can invalidate the reference while this struct is held.
unsafe impl Send for OwnedMyData {}
unsafe impl Sync for OwnedMyData {}

#[tokio::main]
async fn main() {
    let json_payload = r#"{"data": "hello world", "more_data": "foo bar"}"#.to_string();

    // 1. Deserialize once, binding the lifetime internally
    let owned_data = OwnedMyData::new(json_payload).expect("Failed to parse JSON");

    // 2. Share across tasks using Arc to allow multiple readers
    let shared_data = Arc::new(owned_data);

    let (tx, mut rx) = mpsc::channel::<Arc<OwnedMyData>>(10);

    // Spawn a task that receives the data
    let handle = tokio::spawn(async move {
        if let Some(data_arc) = rx.recv().await {
            let inner = data_arc.get();
            println!("Task received: data='{}', more_data='{}'", inner.data, inner.more_data);
        }
    });

    // Send the data across the channel
    tx.send(shared_data).await.unwrap();

    // Wait for the task to finish
    handle.await.unwrap();

    println!("Success: Deserialized once, borrowed data passed across threads without cloning the string content.");
}
"
}

