  "main.rs": "use axum::{
    extract::{Path, State, WebSocketUpgrade},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use axum_extra::{
    headers::{HeaderMapExt, Origin},
    TypedHeader,
};
use http::{header, HeaderMap, HeaderValue, StatusCode};
use std::{net::SocketAddr, sync::Arc};
use tower::ServiceBuilder;
use tower_http::cors::{Any, CorsLayer};
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

// Application state to hold allowed origins
#[derive(Clone)]
struct AppState {
    allowed_origins: Vec<String>,
}

#[tokio::main]
async fn main() {
    // Initialize logging
    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::new(
            std::env::var("RUST_LOG").unwrap_or_else(|_| "axum_ws_origin_check=debug,tower_http=debug".into()),
        ))
        .with(tracing_subscriber::fmt::layer())
        .init();

    // Define allowed origins (e.g., your specific website)
    // Note: TypedHeader<Origin> gives us the scheme + host + port. 
    // We will check if the hostname matches or the full origin matches.
    let allowed_origins = vec!["https://www.example.com".to_string()];

    let state = AppState {
        allowed_origins,
    };

    // CORS Layer for HTTP requests (GET/POST/etc)
    // This does NOT affect WebSocket handshakes automatically, as per your observation.
    let cors = CorsLayer::new()
        .allow_origin("https://www.example.com".parse::<HeaderValue>().unwrap())
        .allow_methods([axum::http::Method::GET, axum::http::Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    // Build the router
    let app = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .layer(ServiceBuilder::new().layer(cors).into_inner())
        .with_state(Arc::new(state));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    tracing::info!("Listening on {}", addr);

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
    headers: HeaderMap,
    State(state): State<Arc<AppState>>,
) -> Result<Response, StatusCode> {
    // Extract Origin header manually or via TypedHeader logic
    // We use HeaderMap directly here to handle the case where Origin might be missing gracefully
    // if you strictly require it, you can return 400 if missing.

    let origin_header = headers
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok())
        .map(|s| s.to_string());

    match origin_header {
        Some(origin) => {
            // Check if the origin is in the allowed list
            // You might want to parse the URL to check just the hostname if ports vary,
            // but strict string matching is safer for specific allowed sites.
            if state.allowed_origins.contains(&origin) {
                tracing::info!("WebSocket connection allowed from: {}", origin);

                // Upgrade to WebSocket
                Ok(ws.on_upgrade(|socket| async move {
                    handle_socket(socket, session_id).await;
                }))
            } else {
                tracing::warn!("WebSocket connection rejected from unauthorized origin: {}", origin);
                Err(StatusCode::FORBIDDEN)
            }
        }
        None => {
            // Decide policy for missing Origin header
            // Usually, browsers send Origin. If missing, it might be a non-browser client.
            // For strict security, reject it.
            tracing::warn!("WebSocket connection rejected: Missing Origin header");
            Err(StatusCode::BAD_REQUEST)
        }
    }
}

async fn handle_socket(mut socket: axum::extract::ws::WebSocket, session_id: String) {
    tracing::info!("New WebSocket connection established for session: {}", session_id);

    while let Some(msg) = socket.recv().await {
        match msg {
            Ok(msg) => {
                if let axum::extract::ws::Message::Text(text) = msg {
                    tracing::info!("Received text: {}", text);
                    // Echo back or process
                    if socket.send(axum::extract::ws::Message::Text(format!("Echo: {}", text))).await.is_err() {
                        break;
                    }
                }
            }
            Err(e) => {
                tracing::error!("WebSocket error: {}", e);
                break;
            }
        }
    }

    tracing::info!("WebSocket connection closed for session: {}", session_id);
}
"
}

