{
  "Cargo.toml": "[package]
name = "tokio-broadcast-shutdown"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["full", "sync", "macros", "rt-multi-thread"] }
tokio-stream = { version = "0.1", features = ["sync"] }
futures-util = "0.3"
",
  "main.rs": "use futures_util::stream::{Stream, StreamExt};
use std::sync::Arc;
use tokio::sync::{broadcast, RwLock};
use tokio_stream::wrappers::BroadcastStream;

#[derive(Debug, Clone)]
pub struct Event {
    pub message: String,
}

#[derive(Debug)]
pub struct RecvError;

// We wrap the Sender in an Arc<RwLock<Option<...>>> so we can explicitly set it to None.
// Dropping the last strong reference to the Sender inside the Option is what signals
// the BroadcastStream to stop.
#[derive(Debug, Clone)]
pub struct EventSender {
    tx: Arc<RwLock<Option<broadcast::Sender<Event>>>>,
}

impl EventSender {
    pub fn send(&self, event: Event) -> Result<(), broadcast::error::SendError<Event>> {
        if let Some(tx) = self.tx.blocking_read().as_ref() {
            tx.send(event)
        } else {
            // Channel is closed, return an error or ignore
            Err(broadcast::error::SendError(event))
        }
    }

    // Explicit shutdown method: takes the sender out of the Option and drops it.
    pub async fn shutdown(&self) {
        let mut tx_guard = self.tx.write().await;
        *tx_guard = None; 
        // When this scope ends, the old Sender is dropped.
        // If no other clones exist outside this wrapper, receivers will see Closed.
    }
}

pub struct EventStreamFactory {
    tx: Arc<RwLock<Option<broadcast::Sender<Event>>>>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> impl Stream<Item = Result<Event, RecvError>> + Send + 'static {
        // We must clone the Option content to subscribe. 
        // If it's None, we can't subscribe, so we return an empty stream or handle error.
        // However, typically subscribers are created before shutdown.

        // We need to capture a clone of the sender if it exists at the moment of subscription.
        // Once subscribed, the BroadcastStream holds its own receiver.
        // The stream will end when ALL Senders (including the one held by the factory and any others) are dropped.

        // To make this robust, we assume the sender exists when creating the stream.
        let maybe_tx = self.tx.blocking_read().clone();

        if let Some(tx) = maybe_tx {
            let rx = tx.subscribe();
            BroadcastStream::new(rx).filter_map(|res| async move {
                match res {
                    Ok(event) => Some(Ok(event)),
                    Err(broadcast::error::RecvError::Closed) => None, // Stream ends
                    Err(broadcast::error::RecvError::Lagged(_)) => Some(Err(RecvError)),
                }
            })
        } else {
            // Return an empty stream immediately if already shut down
            futures_util::stream::empty().boxed()
        }
    }
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, _) = broadcast::channel::<Event>(20);
    let shared_tx = Arc::new(RwLock::new(Some(tx)));

    (
        EventSender { tx: shared_tx.clone() },
        EventStreamFactory { tx: shared_tx },
    )
}

#[tokio::main]
async fn main() {
    let (sender, factory) = events_channel();
    let sender_clone_for_task = sender.clone();

    // Spawn a task that simulates a client listening to SSE
    let consumer_handle = tokio::spawn(async move {
        let mut stream = factory.all_events();
        println!("Consumer: Started listening...");

        while let Some(result) = stream.next().await {
            match result {
                Ok(event) => println!("Consumer: Received event: {}", event.message),
                Err(_) => println!("Consumer: Received lag error"),
            }
        }

        println!("Consumer: Stream closed (Sender dropped). Exiting.");
    });

    // Simulate work
    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
    sender_clone_for_task.send(Event { message: "Hello World".to_string() }).unwrap();

    tokio::time::sleep(tokio::time::Duration::from_millis(500)).await;
    sender_clone_for_task.send(Event { message: "Second Event".to_string() }).unwrap();

    println!("Main: Triggering shutdown...");

    // This explicitly drops the internal Sender, signaling the stream to close
    sender.shutdown().await;

    // Wait for the consumer to finish processing the closure
    let _ = consumer_handle.await;

    println!("Main: Application shutting down cleanly.");
}
"
}

