        MeshMaterial3d(cube_material),
        Transform::default(),
        RotatingCube,
    ));

    // We don't actually spawn a mesh for the gizmo in this demo because we use bevy_gizmos.
    // We just spawn a marker to ensure logic runs if needed, though the system runs based on cube existence.
    commands.spawn(GizmoTarget);
}

fn rotate_cube(time: Res<Time>, mut query: Query<&mut Transform, With<RotatingCube>>) {
    for mut transform in query.iter_mut() {
        // Rotate around Y and X simultaneously to demonstrate the problem clearly
        transform.rotation = Quat::from_rotation_y(time.elapsed_seconds() * 0.5)
            * Quat::from_rotation_x(time.elapsed_seconds() * 0.3);
    }
}

fn update_gizmo(
    query: Query<&Transform, With<RotatingCube>>,
    gizmos: Gizmos,
) {
    for cube_transform in query.iter() {
        // SIMULATING A RAYCAST HIT
        // In a real app, you get this from a raycast. 
        // Here we assume we hit the "Front" face (+Z) of the cube locally.
        // The normal in LOCAL space is +Z.
        let local_normal = Vec3::Z;

        // Calculate the Normal in WORLD space by rotating the local normal by the cube's rotation.
        // This is equivalent to what a physics engine returns in world coordinates.
        let world_normal = cube_transform.rotation * local_normal;

        // Calculate the center of the face in World Space
        // Face center = Cube Position + (World Normal * 0.5) (since cube is 1x1x1)
        let face_center = cube_transform.translation + (world_normal * 0.5);

        // ---------------------------------------------------------
        // THE MATH SOLUTION
        // ---------------------------------------------------------
        // We need a rotation that:
        // 1. Aligns the gizmo's forward axis (let's say +Z) with the `world_normal`.
        // 2. Preserves the rotational orientation (roll/twist) of the cube so the square edges match.
        //
        // Approach:
        // 1. Start with the Cube's Rotation. This gives us the correct "twist" relative to the world.
        // 2. However, the Cube's Rotation points its own +Z in `world_normal` ONLY if we hit the +Z face.
        //    If we hit the +Y face, the Cube's +Z is pointing somewhere else, but we want the Gizmo's +Z to point up (+Y).
        //
        // Robust Approach using Basis Vectors:
        // We construct a new basis (coordinate system) for the gizmo.
        // Forward (Z): The Hit Normal.
        // Up (Y): Ideally the Cube's Up vector, projected to be perpendicular to the Normal.
        // Right (X): Cross product of Up and Forward.

        let forward = world_normal.normalize();

        // Get the cube's current UP vector in world space
        let cube_up = cube_transform.rotation * Vec3::Y;

        // Calculate the "Right" vector first to ensure orthogonality
        // Right = CubeUp x Forward (Note: order matters for handedness, Bevy is Right Handed)
        // If Forward and CubeUp are parallel (hitting top/bottom exactly), this cross product becomes 0.
        // We need a fallback in that case.
        let mut right = cube_up.cross(forward);

        if right.length_squared() < 1e-6 {
            // Fallback: If normal is parallel to cube's up (hitting top or bottom face),
            // use the cube's Right vector to derive the new Up/Right.
            let cube_right = cube_transform.rotation * Vec3::X;
            right = cube_right.cross(forward).normalize();
        } else {
            right = right.normalize();
        }

        // Now calculate the true "Up" vector for the gizmo
        // Up = Forward x Right
        let up = forward.cross(right).normalize();

        // Construct the Rotation Matrix / Quaternion from these basis vectors
        // Bevy's Mat3::from_cols takes (Right, Up, Forward) for a rotation matrix
        let rot_matrix = Mat3::from_cols(right, up, forward);
        let gizmo_rotation = Quat::from_mat3(&rot_matrix);

        // Draw the Gizmo
        // We offset slightly so it doesn't z-fight with the cube surface
        let offset_pos = face_center + (forward * 0.01);

        gizmos.rect(
            Transform::from_translation(offset_pos).with_rotation(gizmo_rotation).to_isometry(),
            Vec2::new(0.95, 0.95), // Slightly smaller than 1.0 to see the cube edge
            Color::srgb(0.0, 1.0, 0.0), // Green indicator
        );

        // Optional: Draw the normal to verify direction
        gizmos.arrow(face_center, face_center + (forward * 1.5), Color::srgb(1.0, 1.0, 0.0));
    }
}
