    while let Some((indices, val)) = imm_iter.next() {
        println!("Indices: {:?}, Value: {}", indices, val);
    }

    // --- Test Mutable Iterator ---
    println!("\n--- Mutable Iteration ---");

    // Re-clone iterators because they were consumed/moved
    let iter_0_mut: Box<dyn ArrayViewIterator> = Box::new(0..dims[0]);
    let iter_1_mut: Box<dyn ArrayViewIterator> = Box::new(0..dims[1]);

    let mut mut_iter = ArrayIteratorFromDynMut {
        array: &mut array,
