            // Real WAD3: 4 bytes ID, 4 bytes num_entries, 4 bytes dir_offset
            if bytes.len() < 12 {
                return Err(WadLoaderError::InvalidHeader);
            }

            let num_entries = u32::from_le_bytes([bytes[4], bytes[5], bytes[6], bytes[7]]) as usize;
            let dir_offset = u32::from_le_bytes([bytes[8], bytes[9], bytes[10], bytes[11]]) as usize;

            if dir_offset + (num_entries * 16) > bytes.len() {
                return Err(WadLoaderError::InvalidHeader);
            }

            let mut entries = Vec::with_capacity(num_entries);

            // Parse Directory
            for i in 0..num_entries {
                let entry_start = dir_offset + (i * 16);
                let offset = u32::from_le_bytes([
                    bytes[entry_start],
                    bytes[entry_start + 1],
                    bytes[entry_start + 2],
                    bytes[entry_start + 3],
                ]);
                let size = u32::from_le_bytes([
                    bytes[entry_start + 4],
                    bytes[entry_start + 5],
                    bytes[entry_start + 6],
                    bytes[entry_start + 7],
                ]);
                // Name is 8 bytes, null terminated
                let name_bytes = &bytes[entry_start + 8..entry_start + 16];
                let name_end = name_bytes.iter().position(|&b| b == 0).unwrap_or(8);
                let name = String::from_utf8_lossy(&name_bytes[..name_end]).to_string();

                entries.push(WadEntry { name, offset, size });
            }

            Ok(WadArchive { entries })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["wad"]
    }
}

