            if parts.len() != 2 {
                return Err(WadLoaderError::EntryNotFound("Invalid format. Use: archive.wad:name.wtex".into()));
            }

            let entry_with_ext = parts[0]; // "texture_name.wtex"
            let archive_path_str = parts[1]; // "path/to/archive.wad"

            let entry_name = entry_with_ext.trim_end_matches(".wtex").to_string();
            let archive_path = std::path::PathBuf::from(archive_path_str);

            // Load Archive Dependency
            let archive_handle: Handle<WadArchive> = load_context.load(&archive_path);
            let archive = load_context.wait_for(&archive_handle).await;

            let entry = archive
                .entries
                .iter()
                .find(|e| e.name == entry_name)
                .ok_or_else(|| WadLoaderError::EntryNotFound(entry_name.clone()))?;

            // Read specific chunk from disk (Simulated lazy load)
