            let disk_path = Path::new("assets").join(&archive_path);

            let mut file = File::open(&disk_path).await.map_err(|e| WadLoaderError::Io(e))?;
            file.seek(std::io::SeekFrom::Start(entry.offset as u64)).await?;

            let mut buffer = vec![0u8; entry.size as usize];
            file.read_exact(&mut buffer).await?;

            Ok(WadTexture {
                name: entry_name,
