        while data.len() < 200 { data.push(0); }

        // Data 1
        data.extend_from_slice(b"0123456789");
        // Data 2
        data.extend_from_slice(b"ABCDEFGHIJ");

        std::fs::write(wad_path, data).expect("Failed to write test wad");
