    // Load the Archive (Only loads the TOC, very fast)
    let _archive_handle: Handle<WadArchive> = asset_server.load("test.wad");

    // Load specific textures LAZILY using the custom syntax "archive:entry.ext"
    // These triggers the WadTextureLoader which depends on WadArchive
    let tex1: Handle<WadTexture> = asset_server.load("test.wad:tex1.wtex");
    let tex2: Handle<WadTexture> = asset_server.load("test.wad:tex2.wtex");

    info!("Requested lazy loads for tex1 and tex2. They will load only when needed/accessed.");

    // Store handles in a resource to prevent them from being unloaded immediately
    // and to check status later
    // For simplicity, we just log in the update loop
}

fn print_loaded_assets(
    asset_server: Res<AssetServer>,
    archives: Res<Assets<WadArchive>>,
    textures: Res<Assets<WadTexture>>,
) {
    // Check archive status
    let archive_path = "test.wad";
    if let Some(handle) = asset_server.get_handle(archive_path) {
        match asset_server.get_load_state(handle) {
            Some(state) => {
                if state.is_loaded() {
                    if let Some(archive) = archives.get(handle) {
                        println!("Archive Loaded: Found {} entries (TOC only, no image data loaded yet)", archive.entries.len());
                    }
                }
            }
            None => {}
        }
    }

    // Check texture status
    let tex1_path = "test.wad:tex1.wtex";
    if let Some(handle) = asset_server.get_handle(tex1_path) {
        match asset_server.get_load_state(handle) {
            Some(state) => {
                if state.is_loaded() {
                    if let Some(tex) = textures.get(handle) {
                        println!("Lazy Texture Loaded: {} (Size: {} bytes)", tex.name, tex.data.len());
                    }
                } else if state.is_failed() {
                    println!("Texture load failed!");
                } else {
                    println!("Texture loading...");
                }
            }
            None => {}
        }
    }

    // Stop after a few seconds to avoid spam
    // In a real app, you wouldn't do this
}"
